const questions = [
    { id: "fill-1", category: "填空题", question: "政治权力特征：___、___、___", answer: "强制性、专业性、自主性", explanation: "强制性：警察执法、法院判决具有强制力；专业性：只有国家机关才能行使；自主性：不受其他社会力量支配", memorization: "口诀：强专自" },
    { id: "fill-2", category: "填空题", question: "政治权力五种方式：___、___、___、___、___", answer: "强制性权力、功利性权力、操纵性权力、合法性权力、人格型权力", explanation: "强制性=直接暴力（逮捕）；功利性=利益交换（政策补贴）；操纵性=暗中控制（舆论引导）；合法性=法律授权（征税）；人格型=个人魅力（领袖号召）", memorization: "口诀：强功操合人" },
    { id: "fill-3", category: "填空题", question: "政治权力基础：___、___、___、___", answer: "物质基础、知识基础、动机、制度", explanation: "物质=军队、监狱等硬件；知识=治国理政的信息技术；动机=统治意愿；制度=宪法法律框架", memorization: "口诀：物知动制" },
    { id: "fill-4", category: "填空题", question: "政治文化三成分：___、___、___", answer: "政治认知取向、政治情感取向、政治评价取向", explanation: "认知=知道什么（了解选举制度）；情感=感觉如何（对政府信任或不信任）；评价=判断好坏（认为某政策好或坏）", memorization: "口诀：知情评" },
    { id: "fill-5", category: "填空题", question: "意识形态特征（5项）：___、___、___、___、___", answer: "阶级性、现实性、相对独立性、依赖性、总体性", explanation: "阶级性=为特定阶级服务；现实性=反映现实社会（资本主义意识形态反映资本主义）；相对独立性=不完全随经济基础变化；依赖性=最终仍取决于经济基础；总体性=涵盖政治经济文化全方位", memorization: "口诀：阶现独依总" },
    { id: "fill-6", category: "填空题", question: "政治社会化特征：___、___、___", answer: "互动性、创新性、持续性", explanation: "互动性=家庭、学校、媒体等多方互动塑造政治观；创新性=每代人都有新的政治认知；持续性=从童年到终生不断进行", memorization: "口诀：持续、创新、互动" },
    { id: "fill-7", category: "填空题", question: "议会三大职能：___、___、___", answer: "立法权、财政权、监督权", explanation: "⚠️ 易错！不是行政权和司法权。立法=制定法律；财政=审批政府预算（美国国会批准联邦预算）；监督=质询政府官员、弹劾", memorization: "口诀：立财监（⚠️不是行政和司法）" },
    { id: "fill-8", category: "填空题", question: "政党作用：___、___、___、___", answer: "目标制定、利益表达、动员和社会化、精英形成与遴选", explanation: "目标制定=提出竞选纲领；利益表达=代表特定群体发声（工党代表工人）；动员=组织选民投票；精英遴选=培养和选拔政治人才", memorization: "口诀：目表动精" },
    { id: "fill-9", category: "填空题", question: "政党制度：___、___、___", answer: "一党制、两党制、多党制", explanation: "一党制=苏联共产党；两党制=美国民主党vs共和党、英国保守党vs工党；多党制=法国、意大利", memorization: "口诀：一两多" },
    { id: "fill-10", category: "填空题", question: "韦伯统治类型：___、___、___", answer: "卡里斯马型（魅力型）、传统型、法理型", explanation: "魅力型=凭个人魅力统治（拿破仑）；传统型=凭世袭传统统治（封建王朝皇帝）；法理型=凭法律规则统治（现代民选总统）", memorization: "口诀：魅传法" },
    { id: "fill-11", category: "填空题", question: "国家能力（5项）：___、___、___、___、___", answer: "资源提取能力、经济调控能力、合法化能力、社会管理和一体化能力、服务能力", explanation: "资源提取=征税、征兵；经济调控=宏观调控货币政策；合法化=让民众认同统治；社会管理=维持社会秩序；服务=提供公共产品（教育医疗）", memorization: "口诀：提调合一服" },
    { id: "fill-12", category: "填空题", question: "政治参与方式：___、___、___、___", answer: "投票、选举、主动接触、结社活动", explanation: "投票=公民投票公决；选举=竞选人大代表；主动接触=给市长写信、上访；结社=加入政党、工会、环保组织", memorization: "口诀：投选接结" },
    { id: "fill-13", category: "填空题", question: "社会契约说代表：___、___、___", answer: "霍布斯、洛克、卢梭", explanation: "霍布斯《利维坦》主张强大专制；洛克主张有限政府、分权；卢梭《社会契约论》主张人民主权", memorization: "口诀：霍洛卢" },
    { id: "fill-14", category: "填空题", question: "马克思主义国家分类（4类）：___、___、___、___", answer: "奴隶制国家、封建制国家、资产阶级国家、社会主义国家", explanation: "按历史发展阶段划分，对应奴隶社会→封建社会→资本主义社会→社会主义社会", memorization: "口诀：奴封资社" },
    { id: "fill-15", category: "填空题", question: "政治发展两种形式：___、___", answer: "政治革命、政治改革", explanation: "革命=暴力推翻旧制度（法国大革命）；改革=渐进改良（清末新政、改革开放）", memorization: "口诀：革命vs改革（暴力vs渐进）" },
    { id: "fill-16", category: "填空题", question: "政治性社团即：___、___、___", answer: "利益集团、压力集团、院外活动集团", explanation: "三个名称指同一类组织，如全国总工会、工商联、美国全国步枪协会(NRA)", memorization: "口诀：利益=压力=院外（同一事物三名称）" },
    { id: "fill-17", category: "填空题", question: "西方统治理论三大流派：___、___、___", answer: "精英统治论、多元统治论、新马克思主义的统治论", explanation: "精英论=少数精英统治（莫斯卡）；多元论=多个利益集团竞争制衡（达尔）；新马克思主义=资产阶级统治披上民主外衣（米尔斯）", memorization: "口诀：精多新马" },
    { id: "fill-18", category: "填空题", question: "空想社会主义标志：1516年莫尔___", answer: "《乌托邦》", explanation: "\"乌托邦\"=Utopia，意为\"不存在的好地方\"。托马斯·莫尔描绘了一个没有私有制的理想社会", memorization: "记忆点：1516年+莫尔+乌托邦" },
    { id: "fill-19", category: "填空题", question: "空想社会主义代表人物：___、___、___", answer: "圣西门、傅立叶、欧文", explanation: "圣西门（法）→实业制度；傅立叶（法）→法郎吉公社；欧文（英）→\"新和谐村\"实验。口诀：圣傅欧 = \"剩下偶\"", memorization: "口诀：圣傅欧（剩下偶）" },
    { id: "fill-20", category: "填空题", question: "空想社会主义局限性（5点）：否认历史必然性 / 看不到人民群众 / 离开阶级斗争 / 理性原则基础 / 不成熟理论对应不成熟生产", answer: "空想社会主义局限性（5点）：否认历史必然性 / 看不到人民群众 / 离开阶级斗争 / 理性原则基础 / 不成熟理论对应不成熟生产", explanation: "核心问题：只想靠道德呼吁和理性设计改造社会，没有找到变革社会的真正力量（无产阶级）和正确道路（阶级斗争）", memorization: "记忆：五错=方向错+人错+方法错+基础错+时机不成熟" },
    { id: "fill-21", category: "填空题", question: "三大工人运动：___、___、___", answer: "法国里昂丝织工人起义、英国宪章运动、德国西里西亚纺织工人起义", explanation: "口诀：法里昂·英宪章·德西里。标志着无产阶级作为独立政治力量登上历史舞台", memorization: "口诀：法里昂·英宪章·德西里" },
    { id: "fill-22", category: "填空题", question: "科学社会主义诞生标志：___", answer: "1848年2月《共产党宣言》", explanation: "马克思恩格斯为共产主义者同盟起草的纲领，第一次系统阐述科学社会主义理论", memorization: "记忆点：1848年2月+共产党宣言" },
    { id: "fill-23", category: "填空题", question: "科学社会主义创始人：___、___", answer: "马克思、恩格斯", explanation: "", memorization: "记忆点：马克思+恩格斯" },
    { id: "fill-24", category: "填空题", question: "正义者同盟1847年更名为___，口号：___", answer: "共产主义者同盟、\"全世界无产者，联合起来！\"", explanation: "前身是德国流亡者的秘密组织，改组后成为第一个国际性的无产阶级政党", memorization: "记忆点：正义者同盟→共产主义者同盟" },
    { id: "fill-25", category: "填空题", question: "苏联模式基本特征：___（斯大林体制）", answer: "过度集权", explanation: "所有权力集中于中央和斯大林个人，涵盖政治经济思想对外四个维度", memorization: "记忆点：四个字=过度集权" },
    { id: "fill-26", category: "填空题", question: "斯大林三大运动：___、___、___", answer: "高速工业化、农业全盘集体化、大清洗", explanation: "工业化=五年计划优先发展重工业；集体化=强迫农民加入集体农庄；大清洗=1930年代肃反运动处决大量党政军干部", memorization: "口诀：高工·农集·大清" },
    { id: "fill-27", category: "填空题", question: "社会主义国家最多：___", answer: "16个", explanation: "冷战时期，除苏联外还有15个社会主义国家（中国、越南、古巴等）", memorization: "记忆点：冷战时期共16个社会主义国家" },
    { id: "fill-28", category: "填空题", question: "60年代___走社会主义道路，70年代___、___、___走社会主义道路", answer: "古巴、越南、老挝、柬埔寨", explanation: "⚠️ 易错点：古巴在拉美（西半球唯一社会主义国家），越老柬在亚洲", memorization: "记忆点：60s古巴+70s越老柬" },
    { id: "fill-29", category: "填空题", question: "南斯拉夫自治社会主义三阶段：___、___、___", answer: "工人自治、社会自治、联合劳动", explanation: "铁托探索的\"第三条道路\"，区别于苏联模式。工人自治(1950s)→扩大到社会各领域→1974年联合劳动体制", memorization: "口诀：工人→社会→联合" },
    { id: "fill-30", category: "填空题", question: "斯大林后历任领导人：___", answer: "赫鲁晓夫→勃列日涅夫→安德罗波夫→契尔年科→戈尔巴乔夫", explanation: "赫鲁晓夫=批判斯大林、玉米运动；勃列日涅夫=停滞时代最长(18年)；戈尔巴乔夫=改革导致苏联解体。口诀：赫勃安契戈", memorization: "口诀：赫勃安契戈" },
    { id: "fill-31", category: "填空题", question: "东欧剧变三波： - 第一波：___、___（1989年最先）", answer: "波兰、匈牙利", explanation: "", memorization: "记忆：三波=波匈→德保捷罗→阿南（由北到南）" },
    { id: "fill-32", category: "填空题", question: "冷战后社会主义流派：___、___、___", answer: "民主社会主义、民族社会主义、生态社会主义", explanation: "民主社会主义=西欧社会党（瑞典社民党）；民族社会主义=拉美左翼（委内瑞拉查韦斯）；生态社会主义=绿色和平运动", memorization: "口诀：民主·民族·生态" },
    { id: "fill-33", category: "填空题", question: "半殖民地半封建三阶段：___→___→___", answer: "鸦片战争、中日甲午战争、八国联军侵华", explanation: "1840开始沦为 → 1895大大加深 → 1900完全形成。口诀：鸦甲八", memorization: "口诀：鸦甲八（1840→1895→1900）" },
    { id: "fill-34", category: "填空题", question: "三个不平等条约：___(1842) / ___(1895) / ___(1901)", answer: "《南京条约》、《马关条约》、《辛丑条约》", explanation: "南京=割香港岛、五口通商；马关=割台湾、赔白银二亿两；辛丑=赔银4.5亿两(本息9.8亿)，中国完全沦为半殖民地", memorization: "口诀：南京·马关·辛丑（1842·1895·1901）" },
    { id: "fill-35", category: "填空题", question: "旧民主主义革命三大运动：___、___、___", answer: "太平天国运动、义和团运动、辛亥革命", explanation: "都是农民或资产阶级领导的，没有无产阶级领导，所以是\"旧\"民主主义", memorization: "口诀：太平·义和·辛亥" },
    { id: "fill-36", category: "填空题", question: "五四运动：1919年5月4日，___", answer: "新民主主义革命开端", explanation: "标志着无产阶级登上历史舞台。导火索：巴黎和会上中国外交失败（山东权益转让日本）", memorization: "记忆点：1919.5.4+新民主主义革命开端" },
    { id: "fill-37", category: "填空题", question: "八七会议后三大起义：___、___、___", answer: "南昌起义、秋收起义、广州起义", explanation: "1927年八七会议确定武装斗争方针。南昌=1927.8.1建军节；秋收=毛泽东领导；广州=1927.12张太雷", memorization: "口诀：南秋广（南昌·秋收·广州）" },
    { id: "fill-38", category: "填空题", question: "毛泽东三篇文章：___、___、___（注意：前两篇是文章标题，第三篇是通信）", answer: "《中国的红色政权为什么能够存在》、《井冈山的斗争》、《星星之火，可以燎原》", explanation: "⚠️ 考试陷阱：第三篇不是\"文章\"而是\"通信\"，理论名称是\"工农武装割据和农村包围城市\"，不是文章标题", memorization: "记忆：前两篇是文章，第三篇是通信（⚠️陷阱）" },
    { id: "fill-39", category: "填空题", question: "土地法：___→___", answer: "《井冈山土地法》、《兴国土地法》", explanation: "井冈山(1928)=没收一切土地；兴国(1929)=修改为没收地主阶级土地，保护中农。从\"左\"倾到正确", memorization: "记忆：井冈山→兴国（没收一切→没收地主）" },
    { id: "fill-40", category: "填空题", question: "1956年毛泽东___，为___作准备", answer: "《论十大关系》、中共八大", explanation: "十大关系涵盖重轻农、沿海内地、国家集体个人等，核心是探索中国自己的社会主义建设道路", memorization: "记忆点：1956+论十大关系+为八大准备" },
    { id: "fill-41", category: "填空题", question: "文革序幕：对___和___的批判（1965-1966）", answer: "《海瑞罢官》、《二月提纲》", explanation: "姚文元发表《评新编历史剧〈海瑞罢官〉》拉开文革序幕", memorization: "记忆：海瑞罢官+二月提纲=文革序幕" },
    { id: "fill-42", category: "填空题", question: "文革中期事件：___(1971)", answer: "林彪集团武装政变", explanation: "\"九一三事件\"：林彪乘飞机外逃，在蒙古温都尔汗坠机身亡", memorization: "记忆点：1971九一三事件+林彪外逃" },
    { id: "fill-43", category: "填空题", question: "十二大提出___：工业、农业、___和___", answer: "四个现代化、国防、科学技术", explanation: "1954年周恩来首次提出，1964年再次强调，十二大进一步推进。注意顺序不固定，但四个内容要记全", memorization: "记忆：工业·农业·国防·科技" },
    { id: "fill-44", category: "填空题", question: "经济体制改革特点：重点由___；城市由___", answer: "农村→城市、试点→全面铺开", explanation: "农村=家庭联产承包责任制(1978小岗村)先行；城市=扩大企业自主权、国企改革", memorization: "记忆：农村→城市，试点→全面" },
    { id: "fill-45", category: "填空题", question: "邓小平理论主题：___；精髓：___", answer: "什么是社会主义，怎样建设社会主义、解放思想、实事求是", explanation: "主题回答了根本问题，精髓是思想路线。本质论=解放发展生产力+消灭剥削共同富裕", memorization: "记忆：主题=什么是+怎样建；精髓=解放思想+实事求是" },
    { id: "fill-46", category: "填空题", question: "社会主义初级阶段：___提出", answer: "十三大", explanation: "1987年十三大系统论述，含义：已经进入社会主义但还处于初级阶段，生产力落后", memorization: "记忆点：十三大（1987）提出" },
    { id: "fill-47", category: "填空题", question: "社会主义本质：___ + ___", answer: "解放发展生产力、消灭剥削，共同富裕", explanation: "邓小平1992年南方谈话提出。破除了\"社会主义=计划经济+平均主义\"的旧观念", memorization: "记忆：解放发展生产力+消灭剥削共同富裕" },
    { id: "fill-48", category: "填空题", question: "一国两制：台港澳保持___", answer: "资本主义制度长期不变", explanation: "最初为解决台湾问题提出，先在香港(1997)、澳门(1999)实施", memorization: "记忆：台港澳保持资本主义制度长期不变" },
    { id: "fill-49", category: "填空题", question: "十五大：确立___", answer: "邓小平理论", explanation: "1997年十五大，邓小平理论写入党章，成为党的指导思想", memorization: "记忆点：十五大（1997）确立邓小平理论" },
    { id: "fill-50", category: "填空题", question: "十八大（2012年）：___写入党章", answer: "科学发展观", explanation: "2012年十八大，胡锦涛提出科学发展观，核心是\"以人为本，全面协调可持续\"", memorization: "记忆点：十八大（2012）科学发展观写入党章" },
    { id: "fill-51", category: "填空题", question: "十九大（2017年）（4点）：___ / ___ / ___ / 确立___", answer: "新时代、主要矛盾变化、两步走战略、习近平思想", explanation: "2017年十九大，习近平新时代思想写入党章", memorization: "口诀：新时代·新矛盾·两步走·新思想" },
    { id: "fill-52", category: "填空题", question: "两步走：___；___", answer: "2020-2035基本实现现代化、2035-本世纪中叶现代化强国", explanation: "替代了原来的\"三步走\"。第一步15年基本现代化，第二步15年建成强国", memorization: "记忆：2020-2035基本现代化；2035-本世纪中叶强国" },
    { id: "fill-53", category: "填空题", question: "新时代主要矛盾：___和___", answer: "人民日益增长的美好生活需要、不平衡不充分的发展", explanation: "从\"物质文化需要vs落后生产\"升级而来。美好生活=不只是吃饱穿暖，还有民主法治公平正义安全环境", memorization: "记忆：美好生活需要vs不平衡不充分发展" },
    { id: "fill-54", category: "填空题", question: "八个明确vs十四个坚持：明确=___(怎么看)；坚持=___(怎么办)", answer: "指导思想、行动纲领", explanation: "类比：明确=世界观（认识论）；坚持=方法论（实践论）", memorization: "记忆：明确=指导思想（怎么看）坚持=行动纲领（怎么办）" },
    { id: "fill-55", category: "填空题", question: "行为主义学派代表：___、___、___", answer: "卡尔·多伊奇、莫顿·卡普兰、戴维·辛格", explanation: "行为主义=用自然科学方法（数据统计、模型）研究政治。多伊奇=一体化理论；卡普兰=国际系统模型；辛格=层次分析法", memorization: "口诀：行为多卡辛" },
    { id: "fill-56", category: "填空题", question: "新自由制度主义代表：___、___、___", answer: "罗伯特·基欧汉、约瑟夫·奈、理查德·罗斯克兰斯", explanation: "基欧汉=《霸权之后》论国际合作；奈=\"软实力\"概念提出者", memorization: "口诀：新自由基奈罗" },
    { id: "fill-57", category: "填空题", question: "国际体系特征：___、___、___", answer: "不平等性、联系性、整体性", explanation: "不平等性=南北差距、大国小国不平等；联系性=各国经济贸易紧密联系；整体性=牵一发而动全身（金融危机全球蔓延）", memorization: "口诀：整体联系不平等" },
    { id: "fill-58", category: "填空题", question: "国际格局四种类型：___、___、___、___", answer: "一元格局、两极格局、多极格局、两极多元格局", explanation: "一元=美国独霸（冷战后初期）；两极=美苏对抗（1947-1991冷战）；多极=多强并存（当前趋势）；两极多元=两个超级大国+多个力量中心", memorization: "口诀：一两多两多" },
    { id: "fill-59", category: "填空题", question: "国家四要素：___、___、___、___", answer: "三要素：人民、领土、主权；四要素加：政府", explanation: "三要素说（人民、领土、主权）和四要素说（加政府）。类比公司：人民=员工，领土=办公场所，政府=管理层，主权=独立法人资格", memorization: "口诀：领土主权人民政府" },
    { id: "fill-60", category: "填空题", question: "国家根本利益要素：___、___、___、___", answer: "国家安全、领土完整、社会制度、经济利益", explanation: "这四项是底线，任何国家都不可妥协。如9·11后美国把国家安全提升到最高优先级", memorization: "口诀：安领土·社经济" },
    { id: "fill-61", category: "填空题", question: "国家安全：以人民安全为___、政治安全为___、经济安全为___、军事科技文化社会安全为___、促进国际安全为___", answer: "宗旨、根本、基础、保障、依托", explanation: "总体国家安全观的五大要素，考试常考排序！口诀：人宗·政根·经基·军保·际依", memorization: "口诀：人宗·政根·经基·军保·际依" },
    { id: "fill-62", category: "填空题", question: "国际冲突分类（5种）：语言象征性冲突、一般性冲突、对抗性冲突、___、___", answer: "国际危机、国际战争", explanation: "从轻到重：口舌之争→一般摩擦→正面对抗→古巴导弹危机级别→全面战争", memorization: "记忆：从轻到重=语言→一般→对抗→危机→战争" },
    { id: "fill-63", category: "填空题", question: "广义国际组织：___、___", answer: "政府间国际组织(IGO)、国际非政府组织(INGO)", explanation: "IGO=联合国、世贸组织、北约（政府参与）；INGO=国际红十字会、绿色和平、国际奥委会（民间组织）", memorization: "口诀：IGO+INGO" },
    { id: "fill-64", category: "填空题", question: "跨国公司：___", answer: "垄断资本主义高度发展的产物", explanation: "如苹果、丰田、三星——在全球范围内配置资源、生产和销售，对母国和东道国都有巨大影响", memorization: "记忆点：垄断资本主义高度发展的产物" },
    { id: "fill-65", category: "填空题", question: "相互依存：___阐述，分___和___两维度", answer: "基欧汉和奈、敏感性、脆弱性", explanation: "敏感性=一方变化传导到另一方的速度（油价上涨→全球通胀）；脆弱性=承受变化冲击后恢复的能力（产油国vs消费国恢复能力不同）", memorization: "记忆：基欧汉和奈+敏感性+脆弱性" },
    { id: "fill-66", category: "填空题", question: "外交关系四种：___、___、___、___", answer: "正式外交关系、半外交关系、非正式外交关系、民间外交", explanation: "正式=互派大使；半外交=互派代办（低于大使）；非正式=利益代表处（如美国在台协会）；民间=乒乓外交、企业交流", memorization: "记忆：正式→半正式→非正式→民间" },
    { id: "fill-67", category: "填空题", question: "外交决策特点：政治性、法制性、权威性、___、___", answer: "组织性（有序性）、广泛性", explanation: "组织性=按程序有步骤地决策（外交部→国务会议→最高领导审批）；广泛性=涉及经济军事文化等方方面面", memorization: "口诀：政法权组广" },
    { id: "fill-68", category: "填空题", question: "国际政治自然环境：___、___、___", answer: "地理因素、人口状况、自然资源", explanation: "地理=岛国vs大陆国（英国vs俄罗斯，影响战略选择）；人口=人口红利vs老龄化；资源=石油出口国vs资源匮乏国", memorization: "口诀：地人资" },
    { id: "fill-69", category: "填空题", question: "人类命运共同体四大内涵：①___ ②___ ③___ ④___", answer: "①相互尊重平等 ②文明交流互鉴 ③合作共赢 ④可持续安全", explanation: "对比西方\"文明冲突论\"（亨廷顿），中国主张文明对话而非对抗", memorization: "口诀：平等·互鉴·共赢·安全" },
    { id: "fill-70", category: "填空题", question: "综合国力克莱因公式：___（物质要素×精神要素）", answer: "PP=(C+E+M)×(S+W)", explanation: "C=基本实体(人口领土) E=经济能力 M=军事能力；S=战略意图 W=贯彻国家意志。精神要素是乘数因子，说明\"人心\"的重要性", memorization: "记忆：PP=(C+E+M)×(S+W) 物质×精神" },
    { id: "fill-71", category: "填空题", question: "联合国：___成立", answer: "1945年", explanation: "二战后成立，创始会员国51个，总部纽约。安全理事会五大常任理事国：中美俄英法（一票否决权）", memorization: "记忆点：1945年+中美俄英法一票否决" },
    { id: "fill-72", category: "填空题", question: "补充说明新增 — 老挝：2016年十大首次明确___为党的指导思想", answer: "凯山·丰威汉思想", explanation: "类比：凯山·丰威汉之于老挝，如同胡志明之于越南、金日成之于朝鲜", memorization: "记忆点：2016+凯山·丰威汉思想" },
    { id: "fill-73", category: "填空题", question: "补充说明新增 — 朝鲜：2012年指导思想修改为___", answer: "金日成-金正日主义", explanation: "从\"主体思想\"升级为包含两代领导人的思想体系，体现权力传承的意识形态化", memorization: "记忆点：2012+金日成-金正日主义" },
    { id: "fill-74", category: "填空题", question: "补充说明新增 — 古巴：古共六大通过___；古共七大首次提出___", answer: "《党和革命的经济与社会政策纲要》、古巴社会主义经济社会模式理念", explanation: "古巴版的\"改革开放\"：在保持社会主义制度前提下有限度地引入市场机制", memorization: "记忆点：六大=政策纲要+七大=模式理念" },
    { id: "fill-75", category: "填空题", question: "补充说明新增 — 尼泊尔两大共产党合并为___(2018)", answer: "尼泊尔共产党", explanation: "2018年尼共（联合马列）和尼共（毛主义中心）合并，一度成为执政党", memorization: "记忆点：2018+两大共产党合并" },
    { id: "term-1", category: "名词解释", question: "政治", answer: "围绕公共权力展开的活动及资源的权威性分配的系统化过程。", explanation: "例：政府制定税收政策（公共权力），决定教育和国防经费比例（资源分配），按法定程序执行（系统化过程）", memorization: "公共权力 / 权威性分配 / 系统化过程" },
    { id: "term-2", category: "名词解释", question: "政治权力", answer: "政治关系中权力主体依靠政治强制力，为实现利益而作用于权力客体的政治力量。", explanation: "例：中央政府（主体）通过法律手段要求地方政府（客体）执行环保政策", memorization: "政治强制力 / 政治力量 / 权力主体→客体" },
    { id: "term-3", category: "名词解释", question: "政治文化", answer: "社会成员在长期政治社会化中形成的、直接影响政治行为的相对稳定的心理过程和心理特征。", explanation: "例：中国人普遍认同\"大一统\"就是中国政治文化的一种体现", memorization: "政治社会化，政治行为心理过程心理特征" },
    { id: "term-4", category: "名词解释", question: "意识形态", answer: "社会的思想上层建筑，是阶级/集团基于根本利益自觉反应形成的理论体系。", explanation: "例：自由主义是西方资产阶级的意识形态，马克思主义是无产阶级的意识形态", memorization: "思想上层建筑 / 阶级利益 / 理论体系" },
    { id: "term-5", category: "名词解释", question: "政治社会化", answer: "社会成员在实践中获取政治知识和能力，形成政治意识和立场的过程。", explanation: "例：一个年轻人从学校教育、新闻报道、家庭讨论中逐渐形成自己的政治观点，这就是政治社会化", memorization: "政治知识和能力，政治意识和立场" },
    { id: "term-6", category: "名词解释", question: "国家能力", answer: "政府制定并实施政策和干净透明执法的能力。", explanation: "例：疫情防控就是国家能力的综合体现——资源提取（调配物资）、社会管理（封控措施）、服务能力（疫苗研发）", memorization: "制定实施政策 / 干净透明执法 / 五项具体能力" },
    { id: "term-7", category: "名词解释", question: "政党", answer: "一定阶级/阶层活跃分子为某种目标有计划地组织的政治组织。", explanation: "例：中共代表工人阶级和广大人民，有党章党纲，目标是实现共产主义", memorization: "有计划组织 / 阶级阶层 / 政治目标" },
    { id: "term-8", category: "名词解释", question: "政党制度", answer: "通过政党进行政治活动的方式或状态。", explanation: "例：中国=中国共产党领导的多党合作制度；美国=两党制（民主党vs共和党轮替执政）", memorization: "政治活动方式 / 一党制两党制多党制" },
    { id: "term-9", category: "名词解释", question: "政治参与", answer: "公民直接或间接影响政府决定的政治行为。形式：投票、选举、主动接触、政治结社。", explanation: "例：参加人大代表投票、给政府提意见、加入环保NGC、网上参与政策讨论", memorization: "影响政府 / 政治行为 / 四种形式" },
    { id: "term-10", category: "名词解释", question: "政治发展", answer: "政治权力/权利关系的变化发展。", explanation: "例：从封建专制到君主立宪（革命性发展），从威权体制到民主化（渐进性发展）", memorization: "权力权利变化 / 革命与改革" },
    { id: "term-11", category: "名词解释", question: "民主（马克思主义）", answer: "①阶级统治形式 ②国家形式（政体） ③公民的平等和参政权。", explanation: "马克思主义认为民主不是抽象的\"全民民主\"，而是有阶级性的——社会主义民主是最广大人民的民主，区别于资产阶级民主（本质是少数资本家的民主）", memorization: "阶级统治 / 政体 / 平等参政" },
    { id: "term-12", category: "名词解释", question: "科学社会主义", answer: "关于无产阶级解放斗争发展规律的科学。", explanation: "\"科学\"二字是关键——区别于空想社会主义，科学社会主义建立在唯物史观和剩余价值学说两大发现基础上", memorization: "无产阶级解放斗争发展规律" },
    { id: "term-13", category: "名词解释", question: "苏联模式", answer: "以过度集权为特征的斯大林体制。", explanation: "四个维度：政治上党政不分、干部委任；经济上指令性计划、优先重工业；思想上舆论一律；对外封闭、大国沙文主义", memorization: "过度集权 / 斯大林体制 / 政治+经济+思想+对外" },
    { id: "term-14", category: "名词解释", question: "毛泽东思想", answer: "马列主义与中国实际结合，集体智慧的结晶。", explanation: "\"集体智慧\"说明不只是毛泽东个人的功劳，还有周恩来、刘少奇、朱德等人的贡献。活的灵魂：实事求是、群众路线、独立自主", memorization: "马列主义中国化 / 集体智慧结晶 / 实事求是" },
    { id: "term-15", category: "名词解释", question: "邓小平理论", answer: "主题：什么是社会主义，怎样建设社会主义。精髓：解放思想、实事求是。", explanation: "核心突破：贫穷不是社会主义，社会主义也可以搞市场经济", memorization: "社会主义本质 / 改革开放 / 解放思想实事求是" },
    { id: "term-16", category: "名词解释", question: "习近平新时代中国特色社会主义思想", answer: "马克思主义中国化最新成果。八个明确(怎么看) + 十四个坚持(怎么办)。", explanation: "回答了\"新时代坚持和发展什么样的中国特色社会主义、怎样坚持和发展\"这个重大时代课题", memorization: "最新成果 / 八个明确十四个坚持 / 新时代" },
    { id: "term-17", category: "名词解释", question: "社会主义初级阶段", answer: "生产力落后条件下建设社会主义的特定阶段。", explanation: "两个含义：①已经进入社会主义（不是过渡时期）②还处于初级阶段（生产力不发达）。决定了不能超越阶段", memorization: "生产力落后 / 特定阶段 / 十三大提出" },
    { id: "term-18", category: "名词解释", question: "社会主义本质", answer: "①解放发展生产力 ②消灭剥削，共同富裕。", explanation: "1992年南方谈话提出。从\"以阶级斗争为纲\"转向\"以经济建设为中心\"的理论基础", memorization: "发展生产力 / 消灭剥削 / 共同富裕" },
    { id: "term-19", category: "名词解释", question: "一国两制", answer: "台港澳保持资本主义制度长期不变。", explanation: "前提是\"一个中国\"，核心是\"社会主义制度为主体+资本主义制度为补充\"", memorization: "一个中国 / 资本主义制度 / 长期不变" },
    { id: "term-20", category: "名词解释", question: "中国特色社会主义新时代", answer: "中华民族从站起来、富起来到强起来的伟大飞跃。", explanation: "三个阶段：站起来（毛泽东时代）→富起来（邓小平时代）→强起来（习近平时代）", memorization: "站富强新矛盾两步走" },
    { id: "term-21", category: "名词解释", question: "人类命运共同体", answer: "四大内涵：①相互尊重平等 ②合作共赢 ③可持续安全 ④文明交流互鉴。", explanation: "对比西方\"零和博弈\"思维：你赢我输 vs 共赢。中国方案：一带一路、亚投行等都是具体实践", memorization: "相互尊重 / 合作共赢 / 四大内涵" },
    { id: "term-22", category: "名词解释", question: "国际体系", answer: "主权国家、国际组织、跨国公司等多种行为体之间形成的有机整体。", explanation: "例：当前国际体系包含主权国家、国际组织、跨国公司等多种行为体，牵一发而动全身", memorization: "有机整体 / 整体性+联系性+不平等性" },
    { id: "term-23", category: "名词解释", question: "国际政治格局", answer: "主要政治力量的对比状态。", explanation: "\"格局\"像棋局——谁是棋手（大国）、谁在什么位置（力量对比）、规则是什么（国际秩序）", memorization: "力量对比 / 四种类型 / 与时代经济秩序联系" },
    { id: "term-24", category: "名词解释", question: "国家主权", answer: "处理对内对外事务的最高权力。", explanation: "对内=政府在其领土内的最高管辖权；对外=独立自主不受他国干涉。1648年《威斯特伐利亚和约》确立", memorization: "最高权力 / 对内对外 / 不可干涉" },
    { id: "term-25", category: "名词解释", question: "国家利益", answer: "满足国家生存发展的必要条件。两重性：阶级性与民族性 / 特殊性与普遍性。", explanation: "两重性举例——阶级性：维护工人阶级和广大人民的根本利益；民族性：维护国家主权和领土完整（全民族共同利益）；特殊性：台湾问题是中国核心利益（特定国家的特定关切）；普遍性：应对气候变化、维护世界和平（各国共同利益）", memorization: "生存发展 / 两重性 / 外交基本依据" },
    { id: "term-26", category: "名词解释", question: "综合国力", answer: "克莱因公式 PP=(C+E+M)×(S+W)。物质要素×精神要素。", explanation: "C+E+M是硬件（可量化），S+W是软件（难量化但决定性的乘数）。解释了为什么物质不占优的国家有时也能取得政治胜利", memorization: "克莱因公式 / 物质+精神 / 决定格局" },
    { id: "term-27", category: "名词解释", question: "联合国", answer: "1945年成立。宗旨(4)：和平安全 / 友好关系 / 国际合作 / 保障人权。", explanation: "六大主要机构：大会、安理会、经社理事会、托管理事会、国际法院、秘书处", memorization: "1945年 / 四大宗旨 / 七大原则" },
    { id: "term-28", category: "名词解释", question: "跨国公司", answer: "通过对外直接投资从事跨国生产经营，垄断资本主义高度发展的产物。", explanation: "例：苹果公司在中国生产iPhone（利用廉价劳动力），在美国设计芯片（利用技术优势），全球销售——这就是跨国公司的典型运作", memorization: "对外直接投资 / 垄断资本主义产物" },
    { id: "term-29", category: "名词解释", question: "相互依存", answer: "行为体间相互依赖、相互制约的关系。基欧汉和奈阐述，分敏感性和脆弱性两维度。", explanation: "敏感性例：国际油价上涨，中国油价马上跟着涨（传导快）。脆弱性例：日本高度依赖石油进口，断油后承受力远低于有战略储备的国家（恢复力不同）", memorization: "基欧汉和奈 / 敏感性+脆弱性 / 依赖制约" },
    { id: "term-30", category: "名词解释", question: "外交政策", answer: "指导外交活动的目标、原则和行动方针。", explanation: "例：中国外交政策目标=维护国家主权安全发展利益；原则=独立自主和平外交；方针=和平发展合作共赢", memorization: "外交活动目标、原则、行动方针" },
    { id: "short-1", category: "简答题", question: "政治文化功能（4点）", answer: "①指导政治行为：政治文化作为一种无形的力量，直接影响社会成员的政治行为方式，规定人们政治行为的取向、模式与规范。\n②决定政治制度和结构模式：政治文化为政治制度的建立提供合法性依据，影响制度选择和结构设计，不同政治文化背景下会形成不同的制度模式。\n③决定政治实际运作状况：政治文化影响政治过程的实际运行，包括政策制定、执行和反馈的方式与效果。\n④影响政治体系稳定与变革：与政治体系相适应的政治文化有助于维护政治稳定；反之，当政治文化发生根本性变化而政治体系未能相应调整时，便会推动政治变革。", explanation: "例：民主观念深入人心→指导公民投票行为(①)→推动建立民主制度(②)→影响政府决策方式(③)→促进政治改革(④)", memorization: "口诀：定向·定制度·定运作·定稳革" },
    { id: "short-2", category: "简答题", question: "政党作用（4点）", answer: "①目标制定：政党通过制定纲领和政策目标，为国家发展指明方向，把社会各阶层的利益诉求转化为明确的政治目标。\n②利益表达：政党作为社会与公共权力之间的桥梁，汇集和表达特定阶级、阶层或群体的利益要求，使之进入政治过程。\n③动员和社会化：政党通过宣传、教育和组织活动，动员民众参与政治生活，同时传播政治文化，实现政治社会化功能。\n④精英形成与遴选：政党是政治精英的培训基地和选拔渠道，通过内部培养和选举机制，为政权机关输送合格的政治人才。", explanation: "想象政党是\"桥梁\"：一端连着社会（收集利益诉求②、动员群众③），另一端连着政府（提出政策目标①、输送人才④）", memorization: "口诀：定目标·表利益·动员化·选精英" },
    { id: "short-3", category: "简答题", question: "议会三大职能", answer: "①立法权：即制定、修改和废止法律的权力，是议会最基本的职能。议会通过立法程序将统治阶级的意志上升为国家意志，为社会各项活动提供法律规范和依据。\n②财政权：即审议和批准国家预算、决算和赋税的权力，被称为\"钱袋权\"。政府的一切财政收支必须经过议会同意，这是议会制约政府的重要手段。\n③监督权：即对政府行政活动进行监督的权力，包括质询政府工作、调查重大问题、弹劾违法官员等。议会通过监督权确保政府依法行政，防止权力滥用。", explanation: "类比公司：立法=制定公司章程；财政=审批预算；监督=审计和问责", memorization: "口诀：立法·财政·监督" },
    { id: "short-4", category: "简答题", question: "政治参与方式（4种）", answer: "①投票：公民通过投票方式参与政治决策，如全民公决、公民投票等，是最基本、最低限度的政治参与形式。\n②选举：公民通过选举活动选出代表自己利益的人进入政权机关，包括直接或间接选举，是代议民主的基础。\n③主动接触：公民主动与政府官员或议员接触，表达个人或群体的利益诉求，如信访、游说、请愿等。\n④结社活动：公民通过组织或加入政党、工会、利益集团等社会组织，以集体方式参与政治，是程度较高的政治参与形式。", explanation: "从低到高排列：投票是最基本最低限度的参与；结社活动是较高程度的参与", memorization: "口诀：投·选·接·结" },
    { id: "short-5", category: "简答题", question: "政治参与发展方向（3点）", answer: "①从资本主义社会到社会主义社会再到全社会参与的演进：在资本主义社会政治参与具有阶级局限性，社会主义社会使广大劳动人民获得广泛参与权，最终向全体社会成员参与发展。\n②从少数人的参与到多数人的参与再到全体人民的参与：随着政治民主化的发展，参与主体不断扩大，逐步排除财产、性别、种族等限制，实现普遍参与。\n③从单一化到多样化再到多层化的发展：政治参与的形式和渠道日益丰富，从传统的投票选举扩展到网络问政、基层协商、社会监督等多种途径，形成多层次参与体系。", explanation: "总趋势：参与主体越来越多（量变），参与方式越来越丰富（质变）", memorization: "口诀：全社会·全人员·多层化（三全趋势）" },
    { id: "short-6", category: "简答题", question: "政治管理作用（3点）", answer: "①维护现存政治秩序和政治规范：政治管理通过制度化的方式，确保社会成员遵守既定的政治规则和法律规范，维护政治生活的有序性和稳定性。\n②维护政治发展和政治稳定：政治管理在保持社会稳定的前提下，通过渐进调整适应社会变化，为政治发展创造条件，实现改革、发展与稳定的统一。\n③促进民主政治生活：政治管理通过完善公民参与渠道、保障公民权利、提高政府透明度等方式，推动政治生活的民主化，使民主制度落到实处。", explanation: "管理≠统治：统治是阶级压迫，管理是服务全社会。政治管理保证社会有序运行", memorization: "口诀：维规范维秩序·保稳定保发展·促民主促政生" },
    { id: "short-7", category: "简答题", question: "政治统治合法化途径（2点）", answer: "①法律基础：统治阶级通过制定宪法和法律，以国家根本大法和法律体系的形式确认自己的统治地位，使政治统治获得法定形式和程序上的合法性，这是政治统治合法化的硬性途径。\n②意识形态教化：统治阶级通过学校、媒体、宗教等渠道传播主流意识形态，使被统治阶级从内心认同现存政治秩序，将统治阶级的利益表述为社会公共利益，这是政治统治合法化的软性途径。", explanation: "法律=硬合法化（宪法规定执政地位）；意识形态=软合法化（让民众真心认同）", memorization: "口诀：法律基础+意识形态教化" },
    { id: "short-8", category: "简答题", question: "空想社会主义局限性（5点）", answer: "①否认历史发展的必然性：空想社会主义者不了解资本主义必然灭亡、社会主义必然胜利的历史规律，而是从抽象的\"理性\"出发设计未来社会。\n②看不到人民群众特别是无产阶级的历史作用：他们寄希望于统治阶级或有产者的善心和理性，而不是依靠广大人民群众的革命斗争。\n③离开阶级斗争去设计和谐社会：空想社会主义者反对阶级斗争，幻想通过和平宣传和小型实验来实现社会改造。\n④以唯心主义的理性原则为理论基础：他们把社会主义看作是\"永恒真理\"\"永恒正义\"的表现，而不是社会经济发展到一定阶段的必然产物。\n⑤不成熟的理论是同不成熟的资本主义生产状况和不成熟的阶级状况相适应的：在资本主义生产方式还不发达、无产阶级尚未作为独立政治力量登上历史舞台的历史条件下，空想社会主义不可避免地具有局限性。", explanation: "五句话概括：方向错了（否认必然性）→找错人了（看不到群众）→方法错了（离开阶级斗争）→基础错了（唯心主义理性）→时机不成熟（生产力未达到）", memorization: "口诀：无根·无人·无斗争·无基础·不成熟" },
    { id: "short-9", category: "简答题", question: "科学社会主义诞生意义（3点）", answer: "①社会主义从空想变为科学：马克思恩格斯创立的唯物史观和剩余价值学说，揭示了资本主义剥削的秘密和社会发展的客观规律，使社会主义建立在科学理论基础之上。\n②社会主义从少数人的思想变为群众性社会运动：科学社会主义与工人运动相结合，使无产阶级从\"自在的阶级\"变为\"自为的阶级\"，推动了国际共产主义运动的兴起。\n③从理论走向实践：科学社会主义为无产阶级革命提供了理论武器和行动指南，指导工人阶级通过革命斗争推翻资本主义制度，建立无产阶级专政，最终实现共产主义。", explanation: "从\"空想\"到\"科学\"，从\"书斋理论\"到\"实践运动\"——标志着社会主义从幻想变为现实道路", memorization: "口诀：飞跃·运动·合流" },
    { id: "short-10", category: "简答题", question: "苏联模式特征", answer: "苏联模式即斯大林模式，基本特征是过度集权，具体表现在四个维度：\n①政治维度：实行过度集权的党和国家领导体制，权力高度集中于党中央和个人，干部实行自上而下的委任制，缺乏有效的民主监督机制，法制建设薄弱。\n②经济维度：生产资料以国家所有制占绝对优势，经济运行依靠自上而下的指令性计划，排斥市场调节作用；优先发展重工业和军事工业，忽视轻工业和农业，国民经济比例严重失调。\n③思想文化维度：思想文化管理高度集中，以领袖言论为唯一真理标准，学术自由受到限制，教条主义和个人崇拜盛行，思想僵化、文化单一。\n④对外关系维度：对外实行封闭政策，强调两大阵营对立；在国际共产主义运动中推行大国大党主义，干涉他国内政，强行输出自己的模式。", explanation: "四个维度记忆法：政治（权太集中）→经济（计划指令）→思想（一个声音）→对外（老大哥主义）", memorization: "口诀：政治集权·经济计划·思想一律·对外封闭" },
    { id: "short-11", category: "简答题", question: "苏联模式失败", answer: "苏联模式失败的原因：\n①体制积弊太深：高度集中的政治经济体制长期得不到根本改革，阻碍了生产力发展和民主政治建设，积累了大量社会矛盾。\n②戈尔巴乔夫改革路线错误：推行\"人道的民主的社会主义\"，背离了科学社会主义原则，实行\"多元化\"\"公开性\"，从根本上动摇了党的领导和社会主义制度。\n③西方和平演变：西方国家长期对苏联实施\"和平演变\"战略，通过意识形态渗透、经济制裁等手段，加剧了苏联国内的政治危机。\n\n教训：\n①必须坚决反对\"左\"的和右的错误倾向，始终坚持科学社会主义基本原则。\n②必须坚持党的领导，任何削弱党的领导的改革都会动摇社会主义制度的根基。\n③必须高度警惕西方敌对势力的\"和平演变\"图谋，维护国家意识形态安全。", explanation: "三重原因：内因（体制弊端）+ 导火索（戈尔巴乔夫改革方向错误）+ 外因（西方渗透）", memorization: "口诀：积弊+路线错误+和平演变" },
    { id: "short-12", category: "简答题", question: "冷战后共产党探索（4点）", answer: "①承认苏联模式已经过时和破产：冷战结束后，共产党组织普遍认识到苏联模式的弊端和失败，摒弃了高度集权和封闭僵化的做法。\n②深入研究资本主义的新变化：面对当代资本主义在政治、经济、科技等方面的新发展，各国共产党加强了对资本主义现状和矛盾的研究。\n③探索走本国特色社会主义道路：不同国家根据自身国情探索各具特色的社会主义发展道路，如中国特色社会主义、越南革新开放、古巴经济模式更新等。\n④探索社会主义的重大理论问题：围绕社会主义本质、发展阶段、市场经济与社会主义关系等重大问题进行理论创新，丰富和发展科学社会主义。", explanation: "核心逻辑：旧路走不通(①②) → 必须走新路(③④)。中共=中国特色社会主义、越南=革新开放、古巴=经济模式更新", memorization: "口诀：旧路不通→研究新变→本国特色→理论探索" },
    { id: "short-13", category: "简答题", question: "新时代意义（5个\"是\"）", answer: "①承前启后、继往开来、在新的历史条件下继续夺取中国特色社会主义伟大胜利的时代：强调新时代是在已有成就基础上继续前进的历史方位。\n②决胜全面建成小康社会、进而全面建设社会主义现代化强国的时代：明确了新时代的阶段性目标，从全面建成小康社会迈向建设现代化强国。\n③全国各族人民团结奋斗、不断创造美好生活、逐步实现全体人民共同富裕的时代：体现了以人民为中心的发展思想，把共同富裕作为社会主义本质要求。\n④全体中华儿女勠力同心、奋力实现中华民族伟大复兴中国梦的时代：确立了新时代的历史使命，凝聚海内外中华儿女的力量实现民族复兴。\n⑤我国日益走近世界舞台中央、不断为人类作出更大贡献的时代：展现了中国在国际格局中地位的历史性变化，承担大国责任。", explanation: "记忆逻辑：对内建设(①②③) → 民族复兴(④) → 对外影响(⑤)，由内到外递进", memorization: "口诀：建设·强国·共富·复兴·舞台（由内到外）" },
    { id: "short-14", category: "简答题", question: "十八大历史贡献（2012年，4点）", answer: "①把科学发展观同马克思列宁主义、毛泽东思想、邓小平理论、\"三个代表\"重要思想一道确立为党的指导思想并写入党章，实现了党的指导思想的又一次与时俱进，为党和国家事业发展提供了重要理论遵循。\n②强调坚持中国特色社会主义政治发展道路，积极稳妥推进政治体制改革，发展更加广泛、更加充分、更加健全的人民民主，保证人民依法实行民主选举、民主决策、民主管理、民主监督。\n③确立了全面建成小康社会的战略目标，提出到2020年实现国内生产总值和城乡居民人均收入比2010年翻一番，开启了实现第一个百年奋斗目标的新征程。\n④坚定不移沿着中国特色社会主义道路前进，既不走封闭僵化的老路，也不走改旗易帜的邪路，丰富和发展了中国特色社会主义理论体系。", explanation: "一理论(①) + 两部署(②③) + 一道路(④)。十八大=承上启下（胡锦涛→习近平过渡）", memorization: "口诀：科发入章·政改·小康·中特路" },
    { id: "short-15", category: "简答题", question: "十九大历史贡献（2017年，4点）", answer: "①作出中国特色社会主义进入新时代的重大政治判断，这是我国发展新的历史方位，在中华人民共和国发展史、中华民族发展史、世界社会主义发展史和人类社会发展史上都具有重大意义。\n②提出我国社会主要矛盾已经转化为人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾，这一重大政治论断反映了我国社会发展的客观实际，是制定党和国家大政方针、长远战略的重要依据。\n③对决胜全面建成小康社会、开启全面建设社会主义现代化国家新征程作出战略部署，提出分两步走在本世纪中叶建成富强民主文明和谐美丽的社会主义现代化强国的战略安排。\n④把习近平新时代中国特色社会主义思想确立为党的指导思想并写入党章，实现了党的指导思想的又一次与时俱进，为新时代坚持和发展中国特色社会主义提供了根本遵循和行动指南。", explanation: "十九大=划时代。新判断(新时代+新矛盾) + 新部署(两步走) + 新思想", memorization: "口诀：新时代·新矛盾·两步走·新思想" },
    { id: "short-16", category: "简答题", question: "八个明确vs十四个坚持", answer: "①八个明确（指导思想层面）：回答「怎么看」的问题，即新时代坚持和发展什么样的中国特色社会主义。系统阐述了新时代中国特色社会主义的总目标、总任务、总体布局、战略布局等基本问题，构成习近平新时代中国特色社会主义思想的理论内核。\n②十四个坚持（行动纲领层面）：回答「怎么办」的问题，即新时代怎样坚持和发展中国特色社会主义。涵盖坚持党对一切工作的领导、坚持以人民为中心、坚持全面深化改革等基本方略，是落实习近平新时代中国特色社会主义思想的实践要求。\n③二者关系：前者是后者的理论基础和认识前提，后者是前者的具体展开和实践路径，体现了理论与实践、认识论与方法论的统一。", explanation: "类比驾照考试：明确=交通规则手册（理论上应该怎么做）；坚持=上路实操练习（实际中具体怎么做）", memorization: "口诀：明确=世界观·坚持=方法论" },
    { id: "short-17", category: "简答题", question: "中国共产党国际政治思想（6点）", answer: "①和平共处五项原则：1950年代提出，即互相尊重主权和领土完整、互不侵犯、互不干涉内政、平等互利、和平共处，成为中国处理国际关系的基本准则。\n②'三个世界'理论：1970年代提出，第一世界指美苏两个超级大国，第二世界指其他发达国家，第三世界指广大发展中国家，为国际统一战线提供了理论框架。\n③和平与发展是时代主题：1980年代提出，科学判断时代特征，认为世界大战可以避免，发展问题是核心问题，为中国外交战略调整提供了依据。\n④建立国际新秩序：1990年代提出，主张建立和平、稳定、公正、合理的国际政治经济新秩序，反对霸权主义和强权政治。\n⑤和谐世界理念：2000年代提出，主张各国人民携手努力，推动建设持久和平、共同繁荣的和谐世界，丰富了国际关系理论。\n⑥人类命运共同体：2010年代提出，主张构建相互尊重、公平正义、合作共赢的新型国际关系，是中国特色大国外交的总目标。", explanation: "按时间线记忆：1950s(①)→1970s(②)→1980s(③)→1990s(④)→2000s(⑤)→2010s(⑥)，每个时代一个关键词", memorization: "口诀：和平共处→三世界→和平发展→新秩序→和谐→命运共同体" },
    { id: "short-18", category: "简答题", question: "国际政治格局一般特征（4点）", answer: "①与一定的历史阶段相联系：国际政治格局是特定历史条件下的产物，反映一定时期主要政治力量对比关系，随着历史条件变化而演变。\n②与世界经济格局相互作用：经济基础决定上层建筑，世界经济格局是国际政治格局的物质基础，国际政治格局对经济格局具有反作用。\n③与国际秩序相互作用：国际秩序是国际政治格局的规则体现，格局决定秩序，秩序维护格局，二者相互影响。\n④新旧格局交替具有过渡性：国际政治格局的演变是一个渐进过程，新旧格局并存、交织、替代，往往经历较长时间的过渡。", explanation: "格局不是孤立的——它由经济基础决定(②)，受国际规则约束(③)，随时代变迁(①④)", memorization: "口诀：历史阶段·经济格局·国际秩序·新旧过渡" },
    { id: "short-19", category: "简答题", question: "冷战后格局", answer: "冷战后国际政治格局的特征：\n①国际力量重新组合：两极格局瓦解后，各种力量分化重组，大国关系深刻调整，新兴经济体和发展中国家群体性崛起，国际力量对比更趋均衡。\n②国家间相互依存日益加深且复杂多样：经济全球化深入发展，各国在政治、经济、安全、文化等领域的联系日益紧密，利益交融、休戚与共。\n③社会制度之间的矛盾依旧存在：冷战虽然结束，但不同社会制度、意识形态之间的较量并未消失，霸权主义和强权政治依然存在。\n\n趋势：\n①世界格局多极化深入发展：美国霸权地位相对衰落，欧盟、俄罗斯、中国、日本、新兴国家等多极力量不断发展壮大。\n②大国间竞争更趋激烈：围绕国际秩序、地缘政治、科技产业、规则标准等领域的竞争日益加剧，但合作与竞争并存。\n③区域一体化和区域合作不断加强：欧盟、东盟、非盟等区域组织作用上升，区域全面经济伙伴关系协定等安排深化了区域合作。", explanation: "冷战后的世界：不是一家独大(多元化)，但也不太平(竞争激烈)，各区域抱团(区域化)", memorization: "口诀：重组·依存·制度矛盾 / 多元·竞争·区域化" },
    { id: "short-20", category: "简答题", question: "联合国宗旨（4点）", answer: "①维护国际和平与安全：联合国首要宗旨是采取有效集体办法，防止和消除对和平的威胁，制止侵略行为或其他破坏和平的行为，通过和平方式解决国际争端。\n②发展各国之间的友好关系：联合国基于尊重人民平等权利和自决原则，发展各国之间以尊重主权平等、互不侵犯、互不干涉内政为基础的良好邻里关系。\n③促进国际合作：联合国促进各国在经济、社会、文化等方面的国际合作，以解决国际间经济、社会、文化和人道主义性质的问题，促进和鼓励尊重人权与基本自由。\n④协调各国行动：联合国作为各国协调行动的中心，通过大会、安理会等机构，协调各国政策，达成共同目标，使各国能够协同应对全球性挑战。", explanation: "从最重要到最日常：和平(①)→友好(②)→合作(③)→协调(④)", memorization: "口诀：护和平，展关系，促合作，协行动" },
    { id: "essay-tips", category: "论述题", question: "⚠️ 论述题答题模板（考场急救）", answer: "【模板1：原因/条件类】适用于'为什么……''试述……的原因/条件'\n总起：×××是多种因素共同作用的结果。\n分点：①经济基础……②阶级力量……③时代背景……④主观条件……⑤外部环境……\n总结：因此，×××具有历史必然性。\n\n【模板2：意义/作用类】适用于'试述×××的意义''×××的作用'\n总起：×××具有重大而深远的意义。\n分点：①政治上……②经济上……③思想上……④国际上……⑤对未来的启示……\n总结：综上所述，×××是……的重要里程碑。\n\n【模板3：特征/表现类】适用于'试述×××的基本特征''×××的主要表现'\n总起：×××主要表现为以下几个方面。\n分点：①……性/化 ②……性/化 ③……性/化 ④……性/化（一般写4-5点）\n总结：这些特征相互联系，共同构成了×××的总体面貌。\n\n【模板4：经验/教训类】适用于'试述×××的历史教训''总结×××的经验'\n总起：×××给我们提供了深刻的经验/教训。\n分点：①必须坚持……②必须防止……③必须处理好……与……的关系 ④必须与时俱进……\n总结：只有……才能……\n\n【模板5：关系/联系类】适用于'试述A与B的关系''×××与×××的联系'\n总起：A与B是辩证统一、相互影响的关系。\n分点：①A决定B……②B反作用于A……③在……条件下，两者相互转化……\n总结：正确认识和处理A与B的关系，对于……具有重要意义。\n\n【急救技巧】实在不会写，就抄材料中的相关句子，加上'首先、其次、再次、最后'凑够三段，每段写3-4行，至少得一半分。", explanation: "考场万能模板：原因/条件→意义/作用→特征/表现→经验/教训→关系/联系。按题型套用，保底拿分。", memorization: "五模板+急救技巧=保底一半分" },
    { id: "essay-1", category: "论述题", question: "苏联模式基本特征和弊病", answer: "【推荐模板：模板3（特征/表现类）+ 模板4（经验/教训类）】\n\n一、苏联模式的形成与定义\n苏联模式是20世纪30年代在苏联形成的一种社会主义建设模式，以过度集权为基本特征，又称斯大林体制。它通过高速工业化、农业全盘集体化和大清洗三大运动最终确立，是苏联在特定历史条件下探索社会主义道路的结果。\n\n二、基本特征——过度集权的四个维度\n①政治维度：实行过度集权的党和国家领导体制，权力高度集中于党中央和个人，干部实行自上而下的委任制，缺乏有效的民主监督机制，法制建设薄弱。\n②经济维度：生产资料以国家所有制占绝对优势，经济运行依靠自上而下的指令性计划，排斥市场调节作用；产业发展优先发展重工业和军事工业，忽视轻工业和农业，国民经济比例严重失调。\n③思想文化维度：思想文化管理高度集中，以领袖言论为唯一真理标准，学术自由受到限制，教条主义和个人崇拜盛行，思想僵化、文化单一。\n④对外关系维度：对外实行封闭政策，强调两大阵营对立；在国际共产主义运动中推行大国大党主义，干涉他国内政，强行输出自己的模式。\n\n三、主要弊病\n①政治上缺乏民主与监督，个人专断导致重大决策失误，如大清洗造成大量冤案，严重破坏了社会主义民主与法制。\n②经济上效率低下、结构失衡，指令性计划压抑了企业和劳动者的积极性，资源配置效率低，人民生活水平长期得不到提高。\n③思想文化上僵化保守，教条主义阻碍了理论创新和学术繁荣，助长了个人崇拜，为后来的改革埋下了隐患。\n④对外关系上封闭和霸权主义损害了社会主义的国际形象，大国主义引起了社会主义国家之间的矛盾和分裂。\n\n四、历史教训\n苏联模式的失败告诉我们：社会主义建设必须坚持民主与法制，不能搞个人专断；必须重视经济发展质量，改善人民生活；必须解放思想、与时俱进，不能思想僵化；必须尊重各国主权，平等相待。中国改革开放正是吸取了这些教训，\"不走封闭僵化的老路\"，探索出了中国特色社会主义道路。", explanation: "答题框架：先定义苏联模式→分四个维度展开特征→分析弊病→总结教训。联系中国\"不走封闭僵化的老路\"", memorization: "结构：定义→政治维度→经济维度→思想维度→对外维度→教训" },
    { id: "essay-2", category: "论述题", question: "科学社会主义基本经验和教训", answer: "【推荐模板：模板4（经验/教训类）】\n\n一、基本经验（正面总结：应该坚持什么）\n①必须坚持共产党的领导。共产党是社会主义事业的领导核心，只有坚持党的领导，才能保证社会主义建设的正确方向，凝聚全国各族人民的力量，克服各种困难和风险。\n②必须坚定社会主义信念。社会主义是历史发展的必然趋势，虽然在发展过程中会遇到挫折和困难，但必须坚信社会主义制度的优越性和历史必然性，不能因暂时的困难而动摇。\n③必须坚持并丰富发展马克思主义。马克思主义是科学的世界观和方法论，但必须与本国实际和时代特征相结合，在实践中不断推进马克思主义中国化、时代化，用发展着的马克思主义指导新的实践。\n④必须探索适合本国国情的社会主义发展道路。各国国情不同，社会主义没有固定模式，必须从本国实际出发，走自己的路，不能照搬外国模式。中国特色社会主义的成功就是探索本国道路的典范。\n⑤必须善于把握历史转折的机遇。在历史发展的关键时刻，要敏锐把握机遇，果断作出正确决策，推动社会主义事业不断向前发展。\n\n二、主要教训（反面警示：应该避免什么）\n①要防止\"左\"的和右的错误倾向。\"左\"的错误表现为超越历史阶段的急躁冒进，右的错误表现为背离社会主义方向的改旗易帜。苏联解体的重要教训之一就是戈尔巴乔夫的\"人道的民主的社会主义\"从根本上背离了科学社会主义。\n②必须把远大理想与现实目标结合起来。既要坚持共产主义的远大理想，又要脚踏实地地从社会主义初级阶段的实际出发，制定切实可行的路线方针政策，不能脱离实际空喊口号。\n③必须高度重视生产力发展和科学技术进步。社会主义的根本任务是解放和发展生产力，必须坚持以经济建设为中心，把发展作为第一要务，用科学技术推动经济社会发展。\n④必须积极稳妥地推进社会主义改革。改革是社会主义发展的动力，但必须坚持正确的改革方向，在党的领导下有计划、有步骤地推进，不能搞\"休克疗法\"式的激进改革。\n⑤必须坚持独立自主与对外开放的统一。既要学习借鉴国外有益经验，又要维护国家主权和独立，警惕西方敌对势力的\"和平演变\"战略，防止外部势力干涉内政。", explanation: "经验=正面（该做的），教训=反面（不该做的）。可列表对比作答", memorization: "结构：经验5点（正面）+教训5点（反面），列表对比" },
    { id: "essay-3", category: "论述题", question: "习近平新时代中国特色社会主义思想", answer: "【推荐模板：模板2（意义/作用类）+ 模板3（特征/表现类）】\n\n一、时代背景\n中国特色社会主义进入新时代，这是我国发展新的历史方位。新时代的标志是：我国社会主要矛盾已经转化为人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾。在这样的历史条件下，以习近平同志为核心的党中央围绕新时代坚持和发展什么样的中国特色社会主义、怎样坚持和发展中国特色社会主义这一重大时代课题，进行了艰辛理论探索，创立了习近平新时代中国特色社会主义思想。\n\n二、\"八个明确\"——指导思想层面的理论内核\n\"八个明确\"系统回答了新时代坚持和发展什么样的中国特色社会主义，是理论层面的核心内容：\n①明确坚持和发展中国特色社会主义的总任务是实现社会主义现代化和中华民族伟大复兴，在全面建成小康社会的基础上，分两步走在本世纪中叶建成富强民主文明和谐美丽的社会主义现代化强国。\n②明确新时代我国社会主要矛盾是人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾，必须坚持以人民为中心的发展思想。\n③明确中国特色社会主义事业总体布局是\"五位一体\"、战略布局是\"四个全面\"，强调坚定道路自信、理论自信、制度自信、文化自信。\n④明确全面深化改革总目标是完善和发展中国特色社会主义制度、推进国家治理体系和治理能力现代化。\n⑤明确全面推进依法治国总目标是建设中国特色社会主义法治体系、建设社会主义法治国家。\n⑥明确党在新时代的强军目标是建设一支听党指挥、能打胜仗、作风优良的人民军队，把人民军队建设成为世界一流军队。\n⑦明确中国特色大国外交要推动构建新型国际关系，推动构建人类命运共同体。\n⑧明确中国特色社会主义最本质的特征是中国共产党领导，中国特色社会主义制度的最大优势是中国共产党领导。\n\n三、\"十四个坚持\"——行动纲领层面的实践方略\n\"十四个坚持\"系统回答了新时代怎样坚持和发展中国特色社会主义，是实践层面的基本方略：坚持党对一切工作的领导；坚持以人民为中心；坚持全面深化改革；坚持新发展理念；坚持人民当家作主；坚持全面依法治国；坚持社会主义核心价值体系；坚持在发展中保障和改善民生；坚持人与自然和谐共生；坚持总体国家安全观；坚持党对人民军队的绝对领导；坚持\"一国两制\"和推进祖国统一；坚持推动构建人类命运共同体；坚持全面从严治党。\n\n四、历史地位与重大意义\n习近平新时代中国特色社会主义思想是马克思主义中国化最新成果，是党和人民实践经验和集体智慧的结晶，是中国特色社会主义理论体系的重要组成部分，是全党全国人民为实现中华民族伟大复兴而奋斗的行动指南。这一思想开辟了马克思主义新境界、中国特色社会主义新境界、治国理政新境界、管党治党新境界，必将指引中国人民在新时代不断夺取中国特色社会主义新胜利。", explanation: "答题技巧：先说明背景（新时代新矛盾），再展开八个明确和十四个坚持，最后总结其历史地位", memorization: "结构：背景+八个明确（理论）+十四个坚持（实践）+历史地位" },
    { id: "essay-4", category: "论述题", question: "农村包围城市理论", answer: "【推荐模板：模板1（原因/条件类：为什么中国必须走这条路）+ 模板2（意义/作用类）】\n\n一、红色政权存在的原因和条件\n毛泽东在《中国的红色政权为什么能够存在？》《井冈山的斗争》《星星之火，可以燎原》等著作中，系统分析了中国红色政权能够存在和发展的原因和条件：\n①中国是一个政治经济发展极不平衡的半殖民地半封建大国。地方性的农业经济和帝国主义划分势力范围的分裂剥削政策，造成白色政权间的长期分裂和战争，使一小块或若干小块的共产党领导的红色区域能够在四围白色政权包围的中间发生和坚持下来。\n②国民革命的影响和良好的群众基础。中国红色政权首先发生和能够长期存在的地方，是在1926年和1927年两年国民革命过程中工农兵士群众曾经大大地起来过的地方，如湖南、广东、湖北、江西等省。\n③全国革命形势是继续向前发展的。引起革命的矛盾一个也没有解决，白色政权的分裂和战争是持续不断的，这就为红色政权的存在和发展提供了客观条件。\n④有相当力量的正式红军的存在。正式红军的存在是红色政权存在的必要条件，如果没有相当力量的正式武装，便决然不能造成割据局面。\n⑤共产党组织的有力量和它的政策的正确。共产党组织的有力量和各项政策的正确执行，是红色政权长期存在和发展的最关键的主观条件。\n\n二、工农武装割据思想\n工农武装割据是农村包围城市、武装夺取政权道路的核心内容，三者密切结合、缺一不可：\n①土地革命是基本内容。实行\"打土豪、分田地\"，满足农民的土地要求，调动广大农民参军参战的积极性，为革命战争提供人力物力支持。\n②武装斗争是主要形式。中国革命的特点和优点之一是武装的革命反对武装的反革命，必须以革命的武装消灭反革命的武装。\n③农村革命根据地是战略基地。根据地是红军生存和发展的依托，是开展土地革命和武装斗争的战略阵地，没有巩固的根据地，武装斗争就会失去后方支持。\n\n三、农村根据地的地位和前景\n毛泽东指出，红军、游击队和红色区域的建立和发展，是半殖民地中国在无产阶级领导之下的农民斗争的最高形式。农村包围城市、武装夺取政权的道路，突破了俄国十月革命\"城市中心论\"的模式，是马克思主义中国化的伟大创举，为中国革命指明了正确方向。\n\n四、历史意义\n农村包围城市道路理论是毛泽东思想形成的重要标志，它表明中国共产党人已经能够把马克思列宁主义基本原理与中国革命具体实际相结合，独立自主地解决中国革命的道路问题，为夺取新民主主义革命胜利奠定了理论基础。", explanation: "核心创新：突破了\"城市中心论\"（苏联模式），找到中国独特的革命道路", memorization: "结构：红色政权条件+工农武装割据+根据地建设" },
    { id: "essay-5", category: "论述题", question: "中国特色社会主义民主制度", answer: "【推荐模板：模板3（特征/表现类）】\n\n一、人民代表大会制度——根本政治制度\n人民代表大会制度是我国的根本政治制度，是中国特色社会主义民主政治的核心体现。它体现了国家一切权力属于人民的宪法原则，人民通过民主选举产生人大代表，组成国家权力机关，行使国家权力。人民代表大会制度实行民主集中制原则，既能充分发扬民主，又能保证国家统一和高效运转，是中国共产党把马克思主义基本原理同中国具体实际相结合的伟大创造。\n\n二、中国共产党领导的多党合作和政治协商制度\n这一制度是我国的一项基本政治制度。其显著特征是：共产党领导、多党派合作，共产党执政、多党派参政。各民主党派是接受共产党领导、同共产党通力合作的亲密友党，是参政党而非反对党。中国人民政治协商会议是这一制度的重要机构，是各党派、各团体、各民族、各阶层大团结大联合的组织，履行政治协商、民主监督、参政议政职能。\n\n三、民族区域自治制度\n民族区域自治制度是在国家统一领导下，各少数民族聚居的地方实行区域自治，设立自治机关，行使自治权。这一制度把民族因素与区域因素相结合、政治因素与经济因素相结合、历史因素与现实因素相结合，既保障了少数民族管理本民族内部事务的权利，又维护了国家统一和民族团结。\n\n四、基层群众自治制度\n基层群众自治制度是指城乡基层群众在党的领导下，依法直接行使民主权利，实行自我管理、自我服务、自我教育、自我监督。包括农村村民委员会、城市居民委员会和职工代表大会等形式。基层民主是人民当家作主最直接、最广泛的实践，是社会主义民主政治的基础性工程。\n\n五、中国特色社会主义民主制度的作用\n①符合中国最广大人民的根本利益，体现了人民当家作主的社会主义民主本质。②促进了社会生产力发展，为社会主义现代化建设提供了坚实的政治保障。③有效整合社会各阶层利益，协调不同群体关系，凝聚社会共识。④维护社会公平正义和长治久安，为中华民族伟大复兴创造了稳定的政治环境。", explanation: "四项：人民代表大会制度（根本）、多党合作政治协商、民族区域自治、基层群众自治", memorization: "结构：人大制度（根本）+多党合作+民族区域自治+基层自治" },
    { id: "essay-6", category: "论述题", question: "国际体系变化及原因", answer: "【推荐模板：模板3（特征/表现类：变化的表现）+ 模板1（原因/条件类：变化的原因）】\n\n一、国际体系的形成\n国际体系是19世纪末20世纪初资本主义发展到帝国主义阶段后逐步形成的。其形成原因有三：\n①科技革命的推动。工业革命特别是第二次科技革命极大地提高了生产力，促进了交通运输和通讯技术的发展，为世界范围内各行为主体之间的联系提供了物质技术条件。\n②垄断资本的产生和发展。垄断组织形成后，资本输出成为主要特征，各国经济的相互依存日益加深，客观上要求建立跨越国界的经济联系和规则体系。\n③殖民政策的出现。帝国主义列强瓜分世界、掠夺殖民地的政策，使世界被划分为压迫民族和被压迫民族，形成了宗主国与殖民地之间的依附关系，推动了国际政治经济体系的建立。\n\n形成的标志主要包括：国际分工的完成、世界货币体系和世界市场的出现、殖民体系的建立。\n\n二、国际体系的当代变革\n进入21世纪以来，尤其是2008年国际金融危机后，国际体系加速深刻变革，主要表现为：\n①国际力量结构发生深刻变化。美国霸权地位相对衰落，中国、印度、巴西等新兴经济体快速崛起，国际力量对比朝着更加均衡的方向发展，多极化趋势深入发展。\n②国际制度面临调整与改革。现有的国际政治经济制度（如联合国、世界银行、IMF等）是在二战后形成的，已不能充分反映当今国际力量对比的变化，新兴国家要求增加话语权和代表性的呼声日益高涨。\n③国际秩序面临新要求。旧的国际秩序以西方为中心，存在明显的不公正不合理之处；建立更加公正合理的国际新秩序成为广大发展中国家的共同诉求。\n④逆全球化趋势和单边主义抬头。部分发达国家内部出现民粹主义、贸易保护主义倾向，单边主义行为增多，多边主义和国际合作面临挑战。\n\n三、变化的原因分析\n①经济全球化深入发展的结果。全球化使各国经济相互依存加深，新兴经济体在全球经济中的比重上升，推动了国际权力结构的转移。\n②科技革命和产业变革的推动。信息技术革命、人工智能等新技术的发展，改变了国家竞争力的来源，为后发国家提供了赶超机遇。\n③国际金融危机的催化作用。2008年金融危机暴露了西方金融体系的深层弊端，削弱了发达国家主导的国际经济治理体系的合法性。\n④广大发展中国家联合自强。发展中国家群体性崛起，通过金砖国家合作、二十国集团等平台协调立场，共同推动国际体系向更加公正合理的方向变革。", explanation: "答题时强调2008年金融危机后的新变化：新兴大国崛起、国际制度调整、旧秩序改革", memorization: "结构：变化三方面+原因三点（2008金融危机后新变化）" },
    { id: "essay-7", category: "论述题", question: "中共国际政治思想演变", answer: "【推荐模板：模板3（特征/表现类：不同阶段的思想特征）】\n\n一、和平共处五项原则（1950年代）\n时代背景：新中国成立初期，面临西方封锁遏制，需要打破外交孤立。核心主张：互相尊重主权和领土完整、互不侵犯、互不干涉内政、平等互利、和平共处。这是中国处理国际关系的基本准则，标志着中国外交政策的成熟，超越了意识形态差异，具有普遍的适用性。\n\n二、\"三个世界\"理论（1970年代）\n时代背景：美苏争霸，世界多极化趋势初现，第三世界国家崛起。核心主张：第一世界指美苏两个超级大国，第二世界指其他发达国家，第三世界指广大发展中国家。中国属于第三世界，要加强同第三世界国家的团结，争取第二世界，反对超级大国的霸权主义。这一理论为国际统一战线提供了分析框架。\n\n三、和平与发展是时代主题（1980年代）\n时代背景：冷战后期，世界大战危险降低，经济全球化加速。核心主张：邓小平科学判断时代特征，认为和平与发展是当代世界两大主题，世界大战可以避免，发展问题是核心问题。这一判断为中国实行改革开放、以经济建设为中心的外交战略调整提供了理论依据。\n\n四、建立国际新秩序（1990年代）\n时代背景：冷战结束，两极格局瓦解，世界进入新旧格局转换期。核心主张：主张建立和平、稳定、公正、合理的国际政治经济新秩序，核心是反对霸权主义和强权政治，尊重各国人民自主选择社会制度和发展道路的权利。\n\n五、和谐世界理念（2000年代）\n时代背景：中国综合国力大幅提升，国际社会对中国发展存在疑虑，\"中国威胁论\"甚嚣尘上。核心主张：胡锦涛提出推动建设持久和平、共同繁荣的和谐世界，强调国与国之间要和平共处、互利共赢，不同文明要交流互鉴，各国发展要相互促进。这一理念丰富了中国特色国际关系理论。\n\n六、人类命运共同体（2010年代至今）\n时代背景：世界面临百年未有之大变局，全球性挑战日益增多，逆全球化、保护主义抬头。核心主张：习近平提出构建人类命运共同体，主张建设相互尊重、公平正义、合作共赢的新型国际关系，推动全球治理体系变革，倡导共建\"一带一路\"，为解决全球性问题贡献中国智慧和中国方案。\n\n总结：中国共产党国际政治思想的演变，体现了与时俱进的理论品格，始终坚持独立自主的和平外交政策，从维护国家利益出发，逐步从地区性大国走向负责任的世界大国，为国际政治理论发展作出了重要贡献。", explanation: "答题线索：每个阶段的时代背景+核心主张+代表人物，体现中国外交思想的与时俱进", memorization: "结构：六阶段按时间线=和共→三世界→和发展→新秩序→和谐→命运共同体" },
    { id: "essay-8", category: "论述题", question: "意识形态功能", answer: "【推荐模板：模板2（意义/作用类：功能=作用）】\n\n意识形态是系统地、自觉地反映社会经济形态和政治制度的思想体系，是一定阶级或社会集团的根本利益在政治上的集中表现。意识形态在社会政治生活中发挥着重要作用。\n\n一、政治功能\n①维护政权合法化。意识形态通过论证现存政治秩序的合理性，使被统治阶级从内心认同统治阶级的统治，将统治阶级的特殊利益表述为社会公共利益，从而为政治统治提供合法性依据。例如，资产阶级通过\"天赋人权\"\"社会契约\"等观念论证资本主义制度的合理性。\n②推动社会政治动员。意识形态能够激发社会成员的政治热情，动员他们参与政治活动，为实现特定政治目标而行动。革命时期，先进的意识形态能够动员广大人民群众投身革命；建设时期，主流意识形态能够动员人民投身社会主义现代化建设。\n③实现政权转移。当社会发生根本性变革时，新的意识形态为新的政治统治提供合法性论证，推动政权从旧阶级向新阶级转移。例如，马克思主义意识形态为无产阶级推翻资产阶级统治、建立无产阶级专政提供了理论武器。\n\n二、经济功能\n①保护团体内部团结。意识形态通过共同的价值观和信仰，增强团体成员的认同感、归属感和凝聚力，减少内部矛盾和冲突，维护组织团结。\n②论证集体行动合理性。意识形态为集体行动提供理论依据，使成员相信集体行动是正当的、必要的，从而提高集体行动的效能。\n③动员成员实现规模效益。意识形态激励成员为集体利益贡献力量，降低组织动员成本，实现\"1+1>2\"的规模效益。\n④约束成员行为，减少\"搭便车\"。意识形态通过价值规范和道德约束，使成员自觉遵守集体规则，减少机会主义行为和\"搭便车\"现象，降低组织监督成本。\n\n总之，意识形态是维护政治统治、推动社会发展的重要精神力量，正确认识意识形态的功能，对于加强意识形态建设、维护国家政治安全具有重要意义。", explanation: "政治三功能：合法化（让统治有理）+动员（让民众行动）+政权转移（让权力交接平稳）", memorization: "结构：政治功能3（合法化+动员+政权转移）+经济功能4" },
    { id: "essay-9", category: "论述题", question: "政治参与制约因素", answer: "【推荐模板：模板1（原因/条件类：制约因素=限制原因）】\n\n政治参与是普通公民通过各种方式影响政府决策或与政府活动相关的公共政治生活的政治行为。政治参与的程度和方式受到多种因素的制约。\n\n一、社会经济发展水平\n社会经济发展水平是决定政治参与的根本性因素。一般来说，经济发展水平越高，政治参与程度也越高。原因在于：经济发展提高了公民的教育程度，增强了公民的权利意识和民主意识；经济发展改善了通讯和交通条件，为政治参与提供了物质基础；经济发展催生了新的社会阶层和利益集团，它们有强烈的政治参与需求。反之，在经济落后、民众温饱问题尚未解决的情况下，民众更关心经济生活而非政治参与。例如，发展中国家在现代化进程中，往往出现政治参与急剧扩大而政治制度吸纳能力不足的张力，导致政治不稳定。\n\n二、社会环境与社会地位\n社会环境和社会地位对政治参与有直接影响。城市化程度、教育水平、职业类型、收入状况等都会影响公民的政治参与意愿和能力。一般来说，城市居民比农村居民参与程度高，受教育程度高的人比受教育程度低的人参与程度高，中产阶级和知识分子群体参与意识更强。社会地位较高的群体通常拥有更多的政治资源和信息渠道，能够更有效地参与政治。\n\n三、政治制度与运行机制\n政治制度是制约政治参与的关键性因素。在民主制度下，选举、听证、信访、舆论监督等参与渠道较为畅通，公民政治参与有制度保障；在专制制度下，参与渠道被压制，政治参与受到严格限制。此外，政党制度、选举制度、立法制度等具体制度设计也会影响政治参与的广度和深度。例如，多党制比一党制提供更多元的参与渠道，直接民主比间接民主提供更高的参与程度。\n\n四、政治心理与文化传统\n政治心理和文化传统对政治参与具有深层影响。政治文化中的参与型取向鼓励公民积极介入政治，而服从型取向则使公民倾向于被动接受政府决策。不同国家和民族的历史文化传统也会塑造不同的政治参与模式。例如，东方文化传统强调集体主义和权威服从，公民政治参与相对内敛；西方文化传统强调个人主义和权利意识，公民政治参与相对活跃。\n\n综上所述，政治参与是一个复杂的社会政治现象，受到经济、社会、制度、文化等多重因素的综合制约。要扩大公民有序政治参与，必须从发展经济、完善制度、培育文化等多方面入手。", explanation: "例：经济落后→民众更关心温饱而非政治参与；专制制度→参与渠道被压制", memorization: "结构：经济发展+社会环境+政治制度+政治心理" },
    { id: "essay-10", category: "论述题", question: "多党合作制特点及中国选择原因", answer: "【推荐模板：模板3（特征/表现类：制度特点）+ 模板1（原因/条件类：为什么选择这个制度）】\n\n一、中国共产党领导的多党合作制的特点\n①中国共产党处于领导地位，各民主党派接受共产党的领导。中国共产党是中国特色社会主义事业的领导核心，这一领导地位是在长期革命斗争中形成并由宪法确立的。各民主党派不是在野党或反对党，而是参政党，自觉接受共产党的领导。\n②允许各民主党派合法存在并参政议政。在中国，除共产党外，还有八个民主党派（民革、民盟、民建、民进、农工党、致公党、九三学社、台盟），它们均有合法地位，通过各级人民代表大会、中国人民政治协商会议等渠道参与国家政治生活。\n③以政治协商制度替代政党竞争制度。中国共产党与各民主党派之间是\"长期共存、互相监督、肝胆相照、荣辱与共\"的关系，通过政治协商而非政党竞争来处理政党关系，避免了西方多党制中政党恶斗、政策摇摆的弊端。\n\n二、中国选择多党合作制度的原因\n①中国复杂的社会阶级结构决定了不能实行一党制或两党制。近代中国阶级关系复杂，既有工人阶级、农民阶级，又有民族资产阶级、小资产阶级等，需要一种能够团结各阶级阶层的政党制度。多党合作制既能保证工人阶级领导，又能团结各民主党派所联系的社会阶层。\n②反动统治的专制化和革命任务的艰巨性决定了必须建立广泛的统一战线。在半殖民地半封建的旧中国，帝国主义、封建主义、官僚资本主义势力强大，任何单一阶级或政党都无法独立完成革命任务，必须联合一切可以联合的力量。\n③中国共产党在革命和建设中的主导作用是多党合作制度形成的决定性因素。中国共产党在长期的革命斗争中展现了卓越的领导能力和先进性，赢得了各民主党派的信任和拥护，形成了共产党领导、多党派合作的政治格局。\n\n三、与西方多党制的本质区别\n西方多党制建立在多党竞争、轮流执政的基础上，各政党之间是竞争对手关系；中国多党合作制建立在共产党领导、多党派合作的基础上，各政党之间是团结合作关系。中国的政党制度既避免了苏联一党制的僵化，又避免了西方多党制的混乱，是中国特色社会主义政治发展道路的重要制度创造。", explanation: "中国特色：共产党领导+多党合作+政治协商，区别于西方多党竞争制度", memorization: "结构：特点（领导+合作+协商）+原因（历史+国情+实践）" },
    {"id": "ipe-term-05-0", "category": "名词解释", "question": "最优货币区（Optimal Currency Area, OCA）", "answer": "指在某一地理区域内，采用单一货币或固定汇率比各自浮动汇率更有效率的经济区域。为什么要素自由流动、经济结构相近、财政统一是它的前提条件？因为加入货币区意味着放弃独立的货币政策和汇率工具，一旦区内某国遭遇只冲击它、不冲击别国的非对称冲击，就不能再靠降息或本币贬值自救，只能依靠劳动力和资本自由流动转移到别处、或者靠统一财政的转移支付来吸收冲击；这些条件不满足，单一货币就弊大于利。 最优货币区理论本质上揭示了**货币主权让渡的条件**——欧元区是最典型的实践案例，但其内部各国经济结构差异大、财政不统一，说明\"最优\"条件在现实中难以完全满足。货币区的形成不仅是经济问题，更是**政治权力博弈**的结果。", "explanation": "最优货币区理论本质上揭示了**货币主权让渡的条件**——欧元区是最典型的实践案例，但其内部各国经济结构差异大、财政不统一，说明\"最优\"条件在现实中难以完全满足。货币区的形成不仅是经济问题，更是**政治权力博弈**的结果。", "memorization": "OCA=单一货币/固定汇率更有效率的区域。条件：要素流动+财政统一。欧元区=政治意志强推、最优条件未满足的典型。翟东升：货币区是政治权力博弈的结果。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-term-05-1", "category": "名词解释", "question": "经常项目与资本项目", "answer": "中国长期\"双顺差\"格局（经常+资本项目同时顺差），本质上是**将实际资源换成外币资产**，承担了他国量化宽松的代价，体现了国际货币体系不对称的结构性剥削。", "explanation": "中国长期\"双顺差\"格局（经常+资本项目同时顺差），本质上是**将实际资源换成外币资产**，承担了他国量化宽松的代价，体现了国际货币体系不对称的结构性剥削。", "memorization": "经常管\"货物+服务+收入\"，资本管\"投资+资产\"，二者互为镜像。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-term-05-2", "category": "名词解释", "question": "国际收支（Balance of Payments, BOP）", "answer": "国际收支不仅是经济账本，更是**国际政治权力关系的映射**。美国长期经常项目逆差却安然无恙，正因为美元霸权使其可以用\"印钞\"来平衡，而发展中国家的逆差则往往引发货币危机，这体现了国际货币体系中的**结构性不平等**。", "explanation": "国际收支不仅是经济账本，更是**国际政治权力关系的映射**。美国长期经常项目逆差却安然无恙，正因为美元霸权使其可以用\"印钞\"来平衡，而发展中国家的逆差则往往引发货币危机，这体现了国际货币体系中的**结构性不平等**。", "memorization": "BOP = 经常 + 资本 + 误差遗漏 = 0（会计平衡），核心看经常项目差额。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-term-05-3", "category": "名词解释", "question": "一价定律（Law of One Price）", "answer": "一价定律指在自由贸易、没有运输成本和贸易壁垒的理想条件下，同一种商品在不同市场用同一货币计价的价格应当相等。背后是套利机制：只要同一商品在两地的价差超过运输成本，套利者就会在低价地买进、到高价地卖出，买盘抬高低价、卖盘压低高价，最终把价差抹平。它是购买力平价理论的微观基石。一价定律在**可贸易品**领域大致成立，但在服务业等非贸易品领域经常失效。这正是发展中国家货币往往被PPP低估的原因——\"巴拉萨-萨缪尔森效应\"揭示了生产率差异导致的系统性价格偏差。", "explanation": "一价定律在**可贸易品**领域大致成立，但在服务业等非贸易品领域经常失效。这正是发展中国家货币往往被PPP低估的原因——\"巴拉萨-萨缪尔森效应\"揭示了生产率差异导致的系统性价格偏差。", "memorization": "同物同价靠套利，现实因成本和壁垒而偏离，是PPP理论的基石。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-term-05-4", "category": "名词解释", "question": "可贸易品（Tradable Goods）", "answer": "中国崛起在全球范围内引发了一场**\"价格革命\"**——工业制成品、运力、电力、算力和火力五个领域的可贸易品价格大幅下降，这重塑了全球贸易格局和各国比较优势结构。可贸易品部门的强大是一国货币国际化的产业基础。", "explanation": "中国崛起在全球范围内引发了一场**\"价格革命\"**——工业制成品、运力、电力、算力和火力五个领域的可贸易品价格大幅下降，这重塑了全球贸易格局和各国比较优势结构。可贸易品部门的强大是一国货币国际化的产业基础。", "memorization": "能出口就是可贸易品，价格由国际市场定；不能出口的叫不可贸易品，价格由本地定。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-short-05-1", "category": "简答题", "question": "简述公开市场操作成为发达市场经济国家最主要政策工具的原因是什么？", "answer": "公开市场操作（央行在公开市场上买卖国债等证券以调节流动性）成为最主要工具的原因有三大优势：1. **主动性强**：央行可根据需要主动操作，灵活调整规模和方向；2. **信号清晰**：市场能直接读取政策意图，预期管理效果好；3. **对市场冲击小**：相比直接调整存准率或利率，对银行体系和实体经济的扰动更温和。背景是发达国家国债市场深度足够，央行有充足\"弹药\"进行操作。", "explanation": "", "memorization": "三大优势：主动灵活 + 信号清晰 + 冲击小。翟东升：国债市场深度是前提。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-short-05-2", "category": "简答题", "question": "全球货币市场份额的分布体现了何种结构性规律？", "answer": "全球货币市场份额呈现**极度不均衡的幂律分布（Power Law）**：美元50%+、欧元20-25%、英镑日元各5%、人民币~3%，其余200种货币共享极小份额。核心规律是**赢者通吃+路径依赖**：货币国际化具有极强网络外部性和规模报酬递增，使用者越多越倾向使用，导致领先货币优势自我强化，落后货币被锁定边缘。翟东升称之为\"货币份额幂律\"。", "explanation": "", "memorization": "货币份额 = 幂律分布 → 赢者通吃 + 路径锁定，翟东升称之为\"货币份额幂律\"。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-short-05-3", "category": "简答题", "question": "为什么印度参与了RCEP的长期谈判但最后选择了退出？", "answer": "\"三怕 + 两个深层逻辑\"：一怕中国商品凭借产业链优势大规模进入，冲击印度本土制造业；二怕贸易逆差进一步扩大（印度对中国已有巨额逆差）；三怕国内政治压力（农民、纺织等利益集团反对）。深层逻辑：印度战略上想\"平衡中国\"，经济上又不愿承担开放成本，最终选择退出以保政治安全。", "explanation": "", "memorization": "三怕：中国货+逆差+国内政治。印度想平衡中国却不愿付开放代价。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-short-05-4", "category": "简答题", "question": "美国对华经贸政策为何由最初的脱钩断链（de-coupling）改为去风险化（de-risking）？", "answer": "\"一个本质 + 三个原因\"：本质是美国战略从\"全面对抗\"转向\"精准遏制\"。原因：1. 完全脱钩成本太高（美国企业和盟友利益受损）；2. 技术上难以彻底切割（中国在供应链中深度嵌入）；3. 需要拉拢盟友共同行动（\"去风险\"更易达成共识）。翟东升：从\"小院高墙\"到\"精准卡位\"，但可能搬起石头砸自己的脚。", "explanation": "", "memorization": "脱钩→去风险 = 从\"全面断\"到\"精准卡\"。原因：不可行 + 代价大 + 拉盟友。翟东升：小院高墙，但可能反噬。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-short-05-5", "category": "简答题", "question": "简述国际货币的含义的几个层次", "answer": "国际货币的含义分为**私人使用**和**官方使用**两大维度，各有三个功能层次：价值尺度（计价货币/锚货币）、交换媒介（结算货币/干预货币）、价值储藏（投资货币/储备货币）。国际货币的最高层次是成为全球\"锚货币\"和储备货币，掌握货币权力的金字塔顶端。美元在所有六个维度占据主导。人民币国际化应从贸易计价结算起步，逐步向投资和储备拓展。\"债务定价币种\"是翟东升特别强调的概念——谁能用本币为债务定价，谁就掌握金融体系核心权力。", "explanation": "- 国际货币的最高层次是成为**全球\"锚货币\"和储备货币**——这意味着掌握了**货币权力的金字塔顶端** - 美元之所以强势，是因为它在所有六个维度上都占据主导地位 - 人民币国际化应从贸易计价结算起步，逐步向投资和储备功能拓展，但不必照搬美元模式 - \"债务定价币种\"是翟东升特别强调的概念——谁能用本币为债务定价，谁就掌握了金融体系的核心权力", "memorization": "国际货币 = 2维度（私人/官方）× 3功能（价值尺度/交换媒介/价值储藏） = 6格。最高层次：锚货币+储备货币（美元六格全占）。翟东升：\"债务定价币种\" = 金融体系核心权力。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-essay-05-1", "category": "论述题", "question": "论述布雷顿森林体系确立的目标、出现的问题与崩溃原因", "answer": "【一个背景 → 三个目标 → 两大支柱 → 四个问题 → 崩溃过程】1944年布雷顿森林会议，美国凭借实力推行怀特方案。三大目标：汇率稳定、贸易自由、国际协调。两大支柱：双挂钩（美元-黄金，其他货币-美元）和两大机构（IMF+世界银行）。四个问题：1. 特里芬困境（美元供给 vs 信心）；2. 美国逆差导致美元过剩；3. 各国汇率调整权不平等；4. 黄金-美元脱钩风险。崩溃：1971年尼克松关闭黄金窗口，1973年固定汇率崩溃，体系瓦解。翟东升：布雷顿森林是美国霸权的制度化安排，其崩溃标志着美国从\"黄金美元\"转向\"石油美元+金融霸权\"新阶段。", "explanation": "", "memorization": "背景+目标+支柱+特里芬+尼克松冲击。翟东升：美国霸权制度化→新阶段转型。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-essay-05-2", "category": "论述题", "question": "能否用一揽子大宗商品而不是一种贵金属作为锚来锁住货币，请论述原因及对人民币国际化的策略参考", "answer": "理论上可行但实际困难重重。优势：克服单一商品局限、与实体经济挂钩、抑制通胀、减少特里芬困境。困难：仓储验证成本极高、价格波动剧烈、权重设定难共识、无法解决\"谁来发行\"的权力问题。翟东升替代方案：**以中国工业产能作为人民币的\"实物锚\"**——人民币的信用基础是世界工厂的供给能力，而非黄金或大宗商品。这对人民币国际化启示：不必追求\"商品锚\"，而应**以实体产业和贸易网络为根基**，逐步扩大人民币在国际贸易和投资中的使用。", "explanation": "", "memorization": "商品篮子锚理论美但不实。翟东升：中国用\"工业产能+世界工厂\"作人民币锚。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-essay-05-3", "category": "论述题", "question": "2012年之前和之后的人民币汇率水平存在何种差异，背后体现出新时代治国理念出现了何种变迁？", "answer": "2012年前：持续单边升值（8.28→6.3），窄幅波动，\"爬行升值\"，外汇储备快速积累。2012年后：双向波动为主（6.3-7.3宽幅震荡），弹性增强，\"811\"汇改后市场化程度提高，储备趋稳。政策逻辑从\"出口导向型增长\"（保出口、保就业）转向\"高质量发展+风险防范\"（不再刻意追求升值，强调汇率稳定服务于国内经济平衡）。治国理念变迁：从\"发展是硬道理\"的规模扩张转向\"以人民为中心\"的高质量发展+总体国家安全观。翟东升：汇率政策从\"为增长服务\"转向\"为安全与平衡服务\"。", "explanation": "", "memorization": "升值→双向波动 = 增长优先 → 安全+高质量。翟东升：汇率从\"增长工具\"到\"安全阀\"。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-term-08-13", "category": "名词解释", "question": "SWIFT系统", "answer": "环球银行金融电信协会（Society for Worldwide Interbank Financial Telecommunication），是全球最主要的跨境金融报文传送系统，为200多个国家和地区的金融机构提供标准化的支付结算信息传输服务。 翟东升：SWIFT已被美国\"武器化\"，成为金融制裁的核心工具（如2022年将部分俄罗斯银行踢出SWIFT）。它不是中性的技术平台，而是**美元霸权的\"神经系统\"**——谁被断开SWIFT连接，就等于被切断全球金融血脉。中国建设CIPS（人民币跨境支付系统）和推动数字人民币跨境应用，正是为了**构建不依赖SWIFT的替代性结算通道**。", "explanation": "SWIFT已被美国\"武器化\"，成为金融制裁的核心工具（如2022年将部分俄罗斯银行踢出SWIFT）。它不是中性的技术平台，而是**美元霸权的\"神经系统\"**——谁被断开SWIFT连接，就等于被切断全球金融血脉。中国建设CIPS（人民币跨境支付系统）和推动数字人民币跨境应用，正是为了**构建不依赖SWIFT的替代性结算通道**。", "memorization": "SWIFT = 全球金融\"邮局\"，传报文不转钱；美国武器化 → 中国建CIPS绕开。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-term-08-14", "category": "名词解释", "question": "拉美债务危机", "answer": "20世纪80年代初，以1982年墨西哥宣布无力偿还外债为标志，席卷拉美主要国家的大规模主权债务违约事件，导致拉美陷入\"失去的十年\"。 翟东升：拉美债务危机是**美元潮汐收割的经典案例**——美国先降息放水培育泡沫，再加息收水引爆危机。IMF的\"救助\"方案（紧缩+私有化+开放）实为**华盛顿共识的强制推行**，本质是**为下一轮收割拆除防火墙**，使外围国家更深地嵌入美元体系。", "explanation": "拉美债务危机是**美元潮汐收割的经典案例**——美国先降息放水培育泡沫，再加息收水引爆危机。IMF的\"救助\"方案（紧缩+私有化+开放）实为**华盛顿共识的强制推行**，本质是**为下一轮收割拆除防火墙**，使外围国家更深地嵌入美元体系。<br>📺 <a href='https://www.bilibili.com/video/BV15b4y1Q7Ez' target='_blank' style='color:#6a8899;text-decoration:underline'>B站·陈平眉山论剑《拉美借债史》（18.8万播放）</a>", "memorization": "借美元债 → 美国加息 → 还不起 → \"失去的十年\"。翟东升：美元潮汐收割的教科书案例。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-term-08-15", "category": "名词解释", "question": "去工业化", "answer": "指一国制造业在国民经济中的比重（产值占GDP比重和就业占比）持续下降的过程和趋势。 翟东升：去工业化是**中央-外围体系运转的副产品**。对中央国家而言，货币霸权导致本币高估，制造业被迫外移（\"荷兰病\"）；对外围国家而言，过度开放资本账户和遵从华盛顿共识，导致本土工业被跨国资本掏空。**守住制造业基本盘**是翟东升反复强调的核心命题——人民币的真正\"锚\"不是黄金，而是中国的工业产能。", "explanation": "去工业化是**中央-外围体系运转的副产品**。对中央国家而言，货币霸权导致本币高估，制造业被迫外移（\"荷兰病\"）；对外围国家而言，过度开放资本账户和遵从华盛顿共识，导致本土工业被跨国资本掏空。**守住制造业基本盘**是翟东升反复强调的核心命题——人民币的真正\"锚\"不是黄金，而是中国的工业产能。", "memorization": "制造业占比持续下降 = 去工业化。分成熟型（正常）和病理型（危险）。翟东升：守住制造业 = 守住货币之锚。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-term-08-16", "category": "名词解释", "question": "预算软约束", "answer": "匈牙利经济学家科尔奈（Kornai）提出的概念，指企业（尤其是国有企业）即使经营亏损，也能通过政府补贴、贷款减免、税收优惠等方式继续存活，不受\"硬预算约束\"的市场纪律制约。之所以叫软，是因为企业预期亏损总会被政府兜底，于是失去了降本增效的压力，敢于过度投资、过度负债，效率长期低下却倒不掉。 翟东升：预算软约束不仅存在于转型经济体，在国际层面同样适用——**美国凭借美元霸权享有全球最大的\"预算软约束\"**，可以长期维持财政赤字和贸易逆差而不受严厉的市场惩罚，因为全球各国不得不持有美元资产为其融资。", "explanation": "预算软约束不仅存在于转型经济体，在国际层面同样适用——**美国凭借美元霸权享有全球最大的\"预算软约束\"**，可以长期维持财政赤字和贸易逆差而不受严厉的市场惩罚，因为全球各国不得不持有美元资产为其融资。", "memorization": "亏了不死 = 预算软约束。科尔奈提出，原指国企；翟东升延伸：美国靠美元霸权享受全球最大\"软约束\"。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-term-08-17", "category": "名词解释", "question": "依附理论", "answer": "20世纪50-60年代兴起的国际政治经济理论，认为发展中国家（外围）的不发达不是内部原因造成，而是被资本主义世界体系（中心）**结构性剥削和控制**的结果。其核心机制是不平等交换：外围国被锁定在出口初级产品、进口工业制成品的分工里，初级产品贸易条件长期恶化，价值通过价格剪刀差源源不断地流向中心国，于是越融入这套体系、越被抽血，发展差距不是缩小而是扩大。 翟东升：依附理论为理解当代国际货币体系提供了**结构主义分析工具**。外围国家积累美元储备 = 向中心国缴纳\"货币地租\"；贸易条件不断恶化 = 可贸易品定价权被中心国把持。中国的发展经验既证实了依附理论的部分判断（嵌入全球体系确实受制于人），也超越了它（中国通过国家能力实现了从外围向准中心的跃升）。", "explanation": "依附理论为理解当代国际货币体系提供了**结构主义分析工具**。外围国家积累美元储备 = 向中心国缴纳\"货币地租\"；贸易条件不断恶化 = 可贸易品定价权被中心国把持。中国的发展经验既证实了依附理论的部分判断（嵌入全球体系确实受制于人），也超越了它（中国通过国家能力实现了从外围向准中心的跃升）。", "memorization": "穷国穷是因为被富国剥削（结构性），不是自己不努力。弗兰克：越融入越穷；卡多佐：可以有限发展。翟东升：用它解释美元霸权下的货币地租。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-term-08-18", "category": "名词解释", "question": "经济安全", "answer": "指一国在经济领域抵御内外部威胁和冲击、维持经济体系稳定运行和可持续发展的能力与状态。 翟东升：经济安全的核心不是封闭自保，而是**在开放中掌握主动权**。当前最大的经济安全威胁来自美元体系的\"武器化\"——SWIFT制裁、冻结外汇储备、技术脱钩等手段表明，**过度依赖单一货币体系本身就是最大的不安全**。中国推进人民币国际化、建设CIPS、减持美债、增持黄金，本质都是**经济安全的战略布局**。", "explanation": "经济安全的核心不是封闭自保，而是**在开放中掌握主动权**。当前最大的经济安全威胁来自美元体系的\"武器化\"——SWIFT制裁、冻结外汇储备、技术脱钩等手段表明，**过度依赖单一货币体系本身就是最大的不安全**。中国推进人民币国际化、建设CIPS、减持美债、增持黄金，本质都是**经济安全的战略布局**。", "memorization": "经济安全 = 不被卡脖子 + 不被收割。翟东升：最大不安全 = 过度依赖美元体系。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-short-08-1", "category": "简答题", "question": "老龄化如何影响一国货币的汇率？", "answer": "老龄化长期看推动本币**升值**（与直觉相反）。四步传导：老龄化→劳动力供给减少→工资上涨→可贸易品生产成本上升→消费结构变化→可贸易品需求相对萎缩→价格面临通缩压力；同时储蓄率下降→国内投资减少→资本项目顺差缩小→整体购买力平价效应→本币实际购买力上升→名义汇率承受升值压力。翟东升\"人口春秋比\"理论：年轻劳动力与老年人口比值决定利率和汇率走势，老龄化国家（如日德）常呈现低利率+强势货币特征。中国劳动年龄人口2012年峰值后老龄化加速，人民币长期有升值基础。", "explanation": "", "memorization": "老龄化 → 需求缩（可贸易品）→ 价格降 → 购买力升 → 汇率升。翟东升：\"人口春秋比\"决定汇率长期走势，老龄化 = 强货币。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-short-08-2", "category": "简答题", "question": "财政存款压以低利率对冲外汇占款产生的利息节省由谁买单，为什么？", "answer": "机制：双顺差下央行被迫大量购汇→外汇占款膨胀→基础货币被动投放过多。为对冲，央行将财政存款沉淀在央行账户（接近活期低利率），相当于用无息/廉价资金帮助央行对冲，节省了本应通过发行高利率央票来冲销流动性的成本。三类买单者：1. **纳税人**：税收被用来补贴央行货币政策操作（税收\"第二次使用\"）；2. **储蓄者**：财政存款压低整体资金利率，造成负实际利率，储蓄购买力被隐性侵蚀；3. **全体国民**：财政资金滞存导致公共产品和福利供给减少。翟东升：这是出口导向型增长模式内嵌的财富转移链条——沉默的大多数承担代价，出口企业集团和美元体系享受收益。", "explanation": "", "memorization": "财政存款以低利率存央行 = 纳税人的钱被用来帮央行对冲 → 纳税人、储蓄者、全体国民三部分人买单。翟东升：出口导向模式下隐性财富转移的一环。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-short-08-3", "category": "简答题", "question": "简述我国外汇储备形成的微观制度基础", "answer": "三大来源 + 一制度 + 一机制。三大来源：经常项目顺差（世界工厂货物贸易）、资本项目顺差（FDI+热钱）、外汇占款（央行购汇）。核心制度：**结售汇制度**（企业必须将外汇收入卖给银行，银行再卖给央行），形成外汇储备的微观强制机制。机制：出口导向+ FDI优惠+ 汇率稳定目标 + 资本管制下的单向流动偏好，共同驱动外汇持续流入央行资产负债表。翟东升：外汇储备的本质是\"世界工厂\"模式下，**中国用实际资源换取美元纸币资产**，为美元霸权提供融资。", "explanation": "", "memorization": "三大来源+结售汇强制+出口导向制度。翟东升：用真金白银换美钞纸，补贴美元霸权。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-short-08-4", "category": "简答题", "question": "中国持有巨额美债的收益、风险与战略选择", "answer": "收益：1. 外汇储备保值增值（美债仍是全球最安全流动性资产）；2. 维持中美战略互信（金融相互依赖）；3. 支持出口导向模式（美元资产回流美国→美国进口中国商品）。风险：1. **美元信用风险**（美债上限、量化宽松、通胀侵蚀）；2. **政治武器化风险**（美国可冻结/制裁）；3. **机会成本**（不能用于国内投资或进口关键技术）。战略选择：**渐进减持+多元化**（增持黄金、石油、战略资源、股权投资、一带一路投融资）；**推动人民币国际化**减少对美元资产依赖；**构建CIPS+数字人民币**绕开SWIFT。翟东升：持有美债是\"阶段性宿命\"，但必须有退出战略，不能永远当\"冤大头\"。", "explanation": "", "memorization": "收益：安全+互信+模式支撑。风险：信用+政治+机会成本。出路：减持+多元+人民币国际化。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-short-08-5", "category": "简答题", "question": "翟东升如何看待\"美元潮汐\"及其对发展中国家的影响？", "answer": "美元潮汐 = 美国通过货币政策周期（降息放水→加息收水）对全球美元流动性进行收割的结构性现象。传导链条：美联储降息→全球美元泛滥→外围国（尤其是拉美、东南亚）大量举债+资产泡沫→美联储加息→美元回流+利率飙升+资本外逃→外围国债务危机/货币危机/资产崩盘→美国资本低价收购优质资产。经典案例：1980s拉美债务危机、1997亚洲金融危机。影响：发展中国家承担调整成本，美国享受\"收割红利\"。翟东升核心观点：**美元霸权不是中性国际公共产品，而是中心国剥削外围国的制度工具**。中国要防范美元潮汐，必须控制资本账户开放节奏、保持汇率弹性、减持美债、推动人民币国际化。", "explanation": "", "memorization": "降息放水→外围举债泡沫→加息收水→危机→低价收割。翟东升：美元潮汐是中心收割外围的结构性武器。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-essay-08-1", "category": "论述题", "question": "试论述欧债危机的成因、演进与教训", "answer": "【背景+制度缺陷+传导+翟东升解读】背景：2009年希腊主权债务危机爆发，迅速蔓延至爱尔兰、葡萄牙、西班牙、意大利。成因：1. **制度先天缺陷**：欧元区\"统一货币+分散财政\"，无财政转移支付、无共同债务工具；2. **外围国竞争力差距**：德国等核心国生产率高，希腊等外围国靠低利率+举债维持，积累巨额债务；3. **银行-主权恶性循环**：银行持大量本国国债，国债违约风险→银行危机→政府救助→主权债务恶化。演进：2010-2012年多次\"拖延+小修\"，欧洲央行OMT计划+ESM救助基金+紧缩+结构性改革才逐步稳定。教训：1. 最优货币区条件（要素流动、财政一体化、经济结构趋同）缺失时，统一货币成本高于收益；2. 政治意志强推货币统一，经济现实会反噬；3. 外围国在货币联盟中丧失货币主权，危机时只能\"内部贬值\"（降工资、降福利），社会代价巨大。翟东升：欧债危机是**\"最优货币区理论的活教材\"**，证明没有财政联盟的货币联盟是不稳定的。中国人民币国际化切忌重蹈欧元区覆辙，必须**先实现经济趋同和制度建设，再谈货币一体化**。", "explanation": "", "memorization": "制度缺陷（货币统一财政分散）+竞争力差距+银行主权循环。翟东升：最优货币区活教材，政治强推货币统一必反噬。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-essay-08-2", "category": "论述题", "question": "试论述美元霸权如何通过金融市场实现全球收割", "answer": "【机制+渠道+案例+中国启示】机制：美元作为全球储备/结算/投资货币，美国可通过金融市场（而非贸易）实现全球资源转移。核心渠道：1. **美债市场**：全球央行/机构必须持有美债，美国以低成本（甚至负利率）融资，相当于全球向美国缴纳\"铸币税\"；2. **美元潮汐收割**：降息→外围举债泡沫→加息→危机→美国资本低价收购；3. **金融衍生品与评级**：华尔街设计复杂产品向全球销售风险，危机后美联储QE又用全球储蓄为美国纾困；4. **SWIFT武器化**：切断支付通道即切断一国经济血脉。案例：1980s拉美、1997亚洲、2008次贷后全球QE、2022俄乌制裁。翟东升总判断：**美元霸权不是\"特里芬困境\"的被动产物，而是美国主动设计的全球剥削体系**。中国对策：控制美债持有规模、推动CIPS和数字人民币、减少对SWIFT依赖、以工业产能和贸易网络构建人民币信用锚。", "explanation": "", "memorization": "美债+潮汐+衍生品+SWIFT四大渠道。翟东升：美元霸权是主动设计的全球剥削体系。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-essay-08-3", "category": "论述题", "question": "中国应如何应对美元霸权下的金融安全挑战？", "answer": "【四位一体战略】1. **储备资产多元化**：逐步减持美债，增持黄金、战略资源、优质股权、一带一路投融资，降低美元资产集中度。2. **支付结算去美元化**：大力建设CIPS（人民币跨境支付系统），推动数字人民币跨境应用，构建不依赖SWIFT的替代通道。3. **贸易投资本币化**：扩大人民币在货物贸易、服务贸易、对外投资中的计价结算份额，减少\"原罪\"（以美元借债）。4. **制度能力建设**：保持资本账户审慎开放，维护汇率弹性，守住制造业基本盘（翟东升：人民币的真正\"锚\"是工业产能），防范系统性金融风险。翟东升核心命题：**金融安全不是封闭，而是掌握开放中的主动权**。中国不能永远做美元体系的\"优质客户\"，必须从\"乘客\"逐步成为\"造车人\"。", "explanation": "", "memorization": "四位一体：储备多元+支付去美元+贸易本币化+制度能力。翟东升：从乘客变造车人，掌握开放主动权。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-term-09-19", "category": "名词解释", "question": "特里芬困境", "answer": "1960年罗伯特·特里芬提出的命题：作为全球储备货币的发行国（美元），既要通过持续贸易逆差向世界提供足够流动性，又要维持美元对黄金的可兑换性（信心），两者存在根本矛盾。矛盾的机制在于：要给世界提供美元流动性，美国必须长期逆差、把美元输出到海外；可逆差越大、海外美元越多，相对有限且固定的黄金储备就越兑不起，美元信心越受损。提供流动性与维持信心方向正好相反，所以注定二选一。 翟东升：特里芬困境是美元霸权的\"先天宿命\"，但美国通过1971年关闭黄金窗口、转向石油美元+金融霸权，实际上\"摆脱\"了这一困境——世界不得不持有美元，即使美国持续逆差。", "explanation": "特里芬困境是美元霸权的\"先天宿命\"，但美国通过1971年关闭黄金窗口、转向石油美元+金融霸权，实际上\"摆脱\"了这一困境——世界不得不持有美元，即使美国持续逆差。", "memorization": "美元要提供流动性（逆差）就要牺牲信心（不可兑换）。翟东升：美国用石油+金融霸权\"摆脱\"了它。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-term-09-20", "category": "名词解释", "question": "铸币税", "answer": "货币发行者通过发行货币所获得的收益，等于货币面值减去发行成本。对于国际储备货币发行国，铸币税表现为：世界各国用真实资源换取该国纸币或以该币计价的资产，美国得以用\"印钞\"换取全球商品和服务。 翟东升：铸币税是美元霸权最直接的利益体现——美国印绿纸，世界给真货。中国持有巨额美债，实质是向美国缴纳巨额铸币税。", "explanation": "铸币税是美元霸权最直接的利益体现——美国印绿纸，世界给真货。中国持有巨额美债，实质是向美国缴纳巨额铸币税。", "memorization": "印纸换真货 = 铸币税。翟东升：中国持美债 = 向美国缴铸币税。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-term-09-21", "category": "名词解释", "question": "原罪（Original Sin）", "answer": "发展中国家在国际金融市场上只能以强势货币（主要是美元）而非本币发行债务的现象。为什么会有原罪？因为这些国家的货币不被国际市场信任、本币债券市场又浅又窄，外国投资者不愿持有其本币资产，于是只能借美元。 翟东升：\"原罪\"是外围国家在美元霸权体系下的结构性弱点——收入是本币，债务是美元，汇率波动即直接转化为债务负担。中国过去也面临\"原罪\"，通过资本管制+出口创汇+逐步人民币国际化，正在逐步摆脱。", "explanation": "发展中国家在国际金融市场上只能以强势货币（主要是美元）而非本币发行债务的现象。 翟东升：\"原罪\"是外围国家在美元霸权体系下的结构性弱点——收入是本币，债务是美元，汇率波动即直接转化为债务负担。中国过去也面临\"原罪\"，通过资本管制+出口创汇+逐步人民币国际化，正在逐步摆脱。", "memorization": "只能用美元借债 = 原罪。翟东升：本币收入+美元债务=汇率一波动就死。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-term-09-22", "category": "名词解释", "question": "巴拉萨-萨缪尔森效应", "answer": "巴拉萨-萨缪尔森效应：一国生产率增速快的部门（通常是可贸易品部门）工资上涨会带动非贸易品部门工资上涨，导致整体价格水平上升、本币实际汇率升值。 翟东升：该效应解释了为什么发展中国家货币按购买力平价（PPP）衡量往往被低估——非贸易品价格低（理发、餐饮等）。中国制造业生产率快速提升，长期面临本币升值压力，但政策上可通过资本管制、汇率管理延缓名义汇率调整。", "explanation": "一国生产率增速快的部门（通常是可贸易品部门）工资上涨会带动非贸易品部门工资上涨，导致整体价格水平上升、本币实际汇率升值。 翟东升：该效应解释了为什么发展中国家货币按购买力平价（PPP）衡量往往被低估——非贸易品价格低（理发、餐饮等）。中国制造业生产率快速提升，长期面临本币升值压力，但政策上可通过资本管制、汇率管理延缓名义汇率调整。", "memorization": "可贸易品生产率快→工资涨→非贸易品价格涨→实际汇率升值。翟东升：发展中国家货币PPP低估的根源。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-term-09-23", "category": "名词解释", "question": "荷兰病（Dutch Disease）", "answer": "指一国因自然资源出口（或本币高估）导致制造业竞争力下降、产业空心化的现象。最初因荷兰发现天然气后制造业衰落而得名。传导机制是：资源大量出口带来外汇涌入，推动本币升值；本币升值一方面让制造业出口变贵、竞争力下降，另一方面资源部门用高工资把劳动力和资本从制造业吸走，两头夹击之下制造业萎缩、产业空心化。 翟东升：货币霸权国家（美国）因本币高估，制造业被迫外移，出现\"成熟型去工业化\"；而外围国若过早开放资本账户、本币升值，也会得\"荷兰病\"，本土产业被掏空。", "explanation": "指一国因自然资源出口（或本币高估）导致制造业竞争力下降、产业空心化的现象。最初因荷兰发现天然气后制造业衰落而得名。 翟东升：货币霸权国家（美国）因本币高估，制造业被迫外移，出现\"成熟型去工业化\"；而外围国若过早开放资本账户、本币升值，也会得\"荷兰病\"，本土产业被掏空。", "memorization": "资源/本币高估→制造业衰落 = 荷兰病。翟东升：美元霸权+资本开放=外围国得荷兰病。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-term-09-24", "category": "名词解释", "question": "金融自由化", "answer": "指一国放松对金融市场的管制，包括利率市场化、资本账户开放、金融业务混业、国有银行私有化等。其内在风险的逻辑是：资本账户一旦开放，短期国际资本（热钱）可以自由进出，繁荣期大量涌入、吹大资产泡沫并推高本币，一旦美元加息或风吹草动又集体抽逃，本币贬值与资产价格崩盘相互踩踏；缺乏管制的中小型开放经济体，很难扛住这种顺周期的资本大进大出。 翟东升：金融自由化是华盛顿共识的核心药方，对发展中国家往往是\"饮鸩止渴\"——过早开放资本账户+金融自由化，在美元潮汐面前极易引发危机（拉美、亚洲案例）。中国坚持\"渐进+可控\"的金融开放节奏，是避免金融自由化陷阱的成功实践。", "explanation": "指一国放松对金融市场的管制，包括利率市场化、资本账户开放、金融业务混业、国有银行私有化等。 翟东升：金融自由化是华盛顿共识的核心药方，对发展中国家往往是\"饮鸩止渴\"——过早开放资本账户+金融自由化，在美元潮汐面前极易引发危机（拉美、亚洲案例）。中国坚持\"渐进+可控\"的金融开放节奏，是避免金融自由化陷阱的成功实践。", "memorization": "利率市场化+资本开放+混业=金融自由化。翟东升：对发展中国家是饮鸩止渴，中国渐进可控是正解。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-term-09-25", "category": "名词解释", "question": "华盛顿共识", "answer": "1989年威廉姆森总结的一套以新自由主义为内核的经济政策药方：财政纪律、利率自由化、汇率市场化、贸易自由化、国有企业私有化、放松管制、保护产权等，被IMF/世界银行作为发展中国家\"标准方案\"推广。 翟东升：华盛顿共识**不是中性经济学建议，而是美国推行新自由主义全球化的意识形态工具**。拉美\"失去的十年\"、俄罗斯\"休克疗法\"的灾难都与盲目执行直接相关。中国成功在于**有选择地吸收而非照搬**。", "explanation": "华盛顿共识**不是中性经济学建议，而是美国推行新自由主义全球化的意识形态工具**。拉美\"失去的十年\"、俄罗斯\"休克疗法\"的灾难都与盲目执行直接相关。中国成功在于**有选择地吸收而非照搬**。<br>📺 拉美·<a href='https://www.bilibili.com/video/BV15b4y1Q7Ez' target='_blank' style='color:#6a8899;text-decoration:underline'>陈平眉山论剑《拉美借债史》（18.8万）</a> ｜ 俄罗斯·<a href='https://www.bilibili.com/video/BV1b5411x7Kn' target='_blank' style='color:#6a8899;text-decoration:underline'>有机社会《叶利钦如何打断俄罗斯脊梁骨》（110.3万）</a>", "memorization": "\"四化\"药方。翟东升：不是建议，是美国资本开路先锋。中国成功=有选择吸收。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-short-09-1", "category": "简答题", "question": "为什么说\"原罪\"是发展中国家在国际货币体系中的根本弱点？", "answer": "\"原罪\"指发展中国家只能以美元而非本币发行债务。根本弱点：1. **货币错配**：收入本币、债务美元，汇率贬值即债务负担加重；2. **政策空间受限**：危机时不能通过本币贬值/印钞缓解，必须紧缩或求助IMF；3. **金融主权缺失**：借债定价权在美元，利率、期限、条件由中心国金融机构决定。翟东升：原罪是美元霸权体系下外围国的\"宿命\"，中国通过资本管制+出口创汇+人民币国际化正在逐步摆脱。", "explanation": "", "memorization": "本币收入+美元债务=汇率波动即死刑。翟东升：原罪是外围国宿命，中国正在摆脱。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-short-09-2", "category": "简答题", "question": "中国持有巨额美债的战略困境与出路", "answer": "困境：1. 安全资产稀缺（美债仍是全球最安全流动性资产，不持有即面临贬值/通胀风险）；2. 战略互信需要（金融相互依赖是中美关系稳定器之一）；3. 退出即引发市场恐慌和自身损失。出路：**渐进减持+多元化**（黄金、石油、战略矿产、股权、一带一路）；**本币化**（推动贸易投资用人民币结算，减少美元需求）；**支付系统替代**（CIPS+数字人民币）。翟东升：持有美债是阶段性宿命，但必须有清晰的\"退出时间表\"和替代方案，不能永远当\"冤大头\"。", "explanation": "", "memorization": "安全资产稀缺+战略互信=不得不持。出路：减持+多元+本币化+支付替代。翟东升：要有退出时间表。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-short-09-3", "category": "简答题", "question": "翟东升如何评价\"一带一路\"的货币金融意义？", "answer": "一带一路不是单纯的基础设施投资，而是**中国构建人民币国际化新路径的战略平台**。货币金融意义：1. **贸易本币化**：沿线贸易用人民币计价结算，绕开美元；2. **投资本币化**：亚投行+丝路基金+政策性银行用人民币放贷，创造人民币资产需求；3. **储备多元化**：沿线国家央行增持人民币作为储备资产；4. **制度输出**：以中国标准（而非华盛顿共识）提供发展性公共产品，赢得制度性话语权。翟东升：一带一路是**从\"嵌入美元体系\"到\"构建替代网络\"**的关键一步，人民币国际化的根基不是美债，而是中国与全球南方的实体经济联系。", "explanation": "", "memorization": "一带一路=人民币国际化新路径。贸易本币化+投资本币化+储备多元化+制度输出。翟东升：从嵌入美元到构建替代网络。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-short-09-4", "category": "简答题", "question": "如何理解\"人民币的锚不是黄金，而是中国的工业产能\"？", "answer": "翟东升核心命题：货币的国际信用最终锚定于**真实生产能力**。黄金锚是历史阶段性安排（金本位已终结）；美元锚是\"石油+美债+军事\"的混合信用。中国人民币的真正信用基础是**世界工厂的供给能力**——工业制成品、运力、电力、算力、火力五个领域的全球竞争力。启示：人民币国际化不能靠\"藏汇于民\"或单纯资本项目开放，而应**以实体产业和贸易网络为根基**，让全球需要中国商品和服务的主体自愿持有人民币。守住制造业基本盘 = 守住人民币之锚。", "explanation": "", "memorization": "黄金锚已死，美元锚是混合信用，人民币锚=世界工厂产能。守住制造业=守住货币之锚。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-essay-09-1", "category": "论述题", "question": "试论述欧债危机的成因与欧元区改革的困境", "answer": "欧债危机证明了**最优货币区理论的现实困境**——当区域内各国经济结构差异大、财政不统一、要素流动受限时，统一货币带来的\"便利\"远不足以弥补丧失货币主权的代价。欧元区是**政治意志超越经济条件**的产物。改革之策：1. 深化财政一体化：建立更严格的财政规则和自动纠正机制→长远向\"财政联盟\"迈进→设立欧元区财政部协调税收和支出；2. 完善银行联盟：建立单一监管机制（SSM）和单一处置机制（SRM）→切断银行与主权债务的恶性循环→欧洲层面共同应对银行危机；3. 强化危机救助：永久性设立欧洲稳定机制（ESM）→欧洲央行发挥\"最后贷款人\"作用（OMT计划）；4. 推进结构性改革：外围国家改革劳动力市场、提升生产率；核心国家扩大内需促进区域再平衡。翟东升：欧元区改革步履维艰，说明**货币一体化必须与财政一体化同步推进**，否则危机终将重演。中国人民币国际化切忌重蹈覆辙。", "explanation": "", "memorization": "欧债危机证明了**最优货币区理论的现实困境**——当区域内各国经济结构差异大、财政不统一、要素流动受限时，统一货币带来的\"便利\"远不足以弥补丧失货币主权的代价。欧元区是**政治意志超越经济条件**的产物。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-essay-09-2", "category": "论述题", "question": "试论述80年代拉美债务危机成因及反思", "answer": "【外因三击 + 内因三失 → 四点反思】外部成因：1. 美联储激进加息（沃尔克1979年）：国际利率从低位骤升至两位数，拉美浮动利率美元债务利息成本指数级增长；2. 大宗商品价格暴跌：全球衰退→需求下降→石油、铜、大豆等价格暴跌→拉美出口收入锐减；3. 国际资本流动逆转：美国加息→全球资金回流美国→拉美无法借新还旧→流动性枯竭。翟东升核心判断：这就是**\"美元潮汐收割\"的教科书案例**。内部成因：1. 过度举借外债（石油美元充裕时大量借入，非生产性投资）；2. 发展战略失衡（进口替代效率低下+过激金融自由化）；3. 汇率政策僵化（盯住美元→本币高估→损害出口）。四点深刻反思：1. 资本账户开放必须与汇率弹性、监管能力匹配；2. 外债结构（货币、期限、利率）必须审慎管理；3. 发展模式不能依赖外部融资驱动；4. IMF救助往往是\"为下一轮收割拆防火墙\"。", "explanation": "", "memorization": "外因三击 + 内因三失 → 四点反思。翟东升：美元潮汐收割的教科书案例。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-essay-09-3", "category": "论述题", "question": "请简述亚洲金融危机的成因，及金融危机中韩国、香港、台湾、泰国、印尼的不同对策及后果", "answer": "【四层成因 → 五国对策比较】成因：1. 固定汇率与金融自由化错配（僵化盯住美元+过早开放资本账户→热钱涌入+资产泡沫）；2. 银行体系脆弱与企业过度举债（监管不力+货币错配）；3. 经常账户持续恶化（中国崛起竞争+汇率僵化）；4. 国际投机资本立体式攻击。翟东升：与拉美债务危机根本逻辑一脉相承——\"原罪\"+过早资本开放+美元潮汐。五国/地区对策及后果：泰国（危机起点）：外储耗尽后被迫放弃固定汇率，接受IMF严苛条件（紧缩+关闭机构+高利率）→货币暴跌、经济衰退、社会动荡；印度尼西亚：类似泰国，IMF条件更严+苏哈托政权倒台→最惨；韩国：IMF救助+企业重组+金大中改革→痛定思痛后实现产业升级，V型复苏；香港：联系汇率制+高利率+政府入市干预（1998年索罗斯之战）→守住港币，但经济重创；台湾：资本管制+汇率弹性+产业升级（IT代工）→相对安然度过。启示：资本账户开放节奏+汇率制度+产业竞争力+国家能力，决定危机中命运。", "explanation": "", "memorization": "四层成因 + 五国不同命运。翟东升：原罪+资本开放+美元潮汐=危机宿命，国家能力决定后果。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-term-10-41", "category": "名词解释", "question": "外商直接投资（FDI）", "answer": "一国投资者将资本投入他国并掌握**经营控制权**的长期投资行为，核心特征是\"控制权\"和\"持久利益\"，区别于证券投资等组合投资。 翟东升：FDI对中国是一种**可被驾驭的战略工具**——既是推动力也可能造成依赖。中国应从\"以市场换技术\"升级为\"**以市场换股权**\"，利用市场吸引力参股控股国际一流企业，实现\"外资内资化\"。", "explanation": "FDI对中国是一种**可被驾驭的战略工具**——既是推动力也可能造成依赖。中国应从\"以市场换技术\"升级为\"**以市场换股权**\"，利用市场吸引力参股控股国际一流企业，实现\"外资内资化\"。", "memorization": "长期投资+控制权，区别于炒股票的组合投资。翟东升：从\"市场换技术\"到\"市场换股权\"。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-term-10-42", "category": "名词解释", "question": "利率平价", "answer": "在资本自由流动条件下，两国利率差异应等于远期汇率升贴水率，以消除套利机会。其背后是抛补套利机制：若A国利率高于B国，资金会流入A国赚取利差，推高A国货币的即期汇率；但远期市场上A国货币必须贴水、也就是预期贬值，且贬值幅度恰好抵消利差，否则就存在无风险套利。套利者的行动会把利差与远期升贴水拉回相等，平价由此成立。 翟东升：利率平价在成熟金融市场大致成立，但对发展中国家而言，资本管制和政治风险使之经常失效。**中国正是通过资本账户的审慎管控，保持了货币政策的独立性**，没有被迫跟随美联储的利率周期。", "explanation": "利率平价在成熟金融市场大致成立，但对发展中国家而言，资本管制和政治风险使之经常失效。**中国正是通过资本账户的审慎管控，保持了货币政策的独立性**，没有被迫跟随美联储的利率周期。", "memorization": "高利率国货币远期贴水。利率高→资本流入→即期升值，但远期预期贬值→均衡。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-term-10-43", "category": "名词解释", "question": "国债收益率曲线", "answer": "反映不同期限国债到期收益率关系的曲线，横轴为期限（1月、1年、5年、10年、30年），纵轴为收益率。曲线的斜率藏着市场预期：正常情况下期限越长、收益率越高，曲线向上倾斜，因为锁定资金更久要补偿更多不确定性。而当美联储加息把短端利率推高、长端却因市场预期未来经济衰退、通胀回落而走低时，曲线就会倒挂——这就是为什么收益率曲线倒挂被当作经济衰退的前兆信号。 翟东升：美国国债收益率曲线是全球金融市场的**\"温度计\"**，因为美债是后布雷顿森林体系的\"准锚\"——美联储通过影响收益率曲线，不仅调控国内流动性，更对全球美元流动性和资产定价产生**溢出效应**。外围国家持有美债 = 将自身经济命运绑定于这条曲线。", "explanation": "美国国债收益率曲线是全球金融市场的**\"温度计\"**，因为美债是后布雷顿森林体系的\"准锚\"——美联储通过影响收益率曲线，不仅调控国内流动性，更对全球美元流动性和资产定价产生**溢出效应**。外围国家持有美债 = 将自身经济命运绑定于这条曲线。", "memorization": "正常=经济健康（上升斜坡），倒挂=衰退预警（下降斜坡）。翟东升：美债收益率曲线是全球金融温度计。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-term-10-44", "category": "名词解释", "question": "次贷危机", "answer": "2007-2008年间起源于美国次级住房抵押贷款市场的金融危机，因金融衍生品连锁崩盘引发全球性金融海啸。 翟东升：次贷危机是**美元霸权体系内在矛盾的一次总爆发**——美国通过金融创新将风险打包外售，向全球转嫁信用扩张的后果。危机后美联储的QE反而进一步强化了美元霸权——\"搞出危机的人反成了救世主\"，这正是体系的荒谬之处。", "explanation": "次贷危机是**美元霸权体系内在矛盾的一次总爆发**——美国通过金融创新将风险打包外售，向全球转嫁信用扩张的后果。危机后美联储的QE反而进一步强化了美元霸权——\"搞出危机的人反成了救世主\"，这正是体系的荒谬之处。", "memorization": "次级贷款→证券化扩散→房价跌+利率升→衍生品崩→雷曼倒→全球危机。翟东升：美元体系内在矛盾的总爆发。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-term-10-45", "category": "名词解释", "question": "滞涨", "answer": "经济停滞（高失业率）与高通货膨胀并存的经济现象，即\"停滞性通货膨胀\"（Stagflation）。为什么停滞和通胀会同时出现？按传统菲利普斯曲线，失业与通胀本应此消彼长。但1970年代的石油危机是一次供给侧冲击：油价暴涨同时推高了生产成本、造成通胀，又压低了产出、造成失业；以刺激需求为手段的凯恩斯政策对供给冲击无能为力，反而火上浇油。这正是滞涨击穿菲利普斯曲线、宣告凯恩斯主义失灵的根本逻辑。 翟东升：1970年代的滞涨是凯恩斯主义政策失灵的标志，为新自由主义（里根/撒切尔）的上台提供了政治土壤。沃尔克通过极端加息治通胀，虽成功压制物价，但同时触发了拉美债务危机——**治愈中心国的\"病\"，代价由外围国承担**，体现了体系的不对称性。", "explanation": "1970年代的滞涨是凯恩斯主义政策失灵的标志，为新自由主义（里根/撒切尔）的上台提供了政治土壤。沃尔克通过极端加息治通胀，虽成功压制物价，但同时触发了拉美债务危机——**治愈中心国的\"病\"，代价由外围国承担**，体现了体系的不对称性。", "memorization": "停滞+通胀=滞涨。70年代石油危机经典案例。凯恩斯主义无能为力→新自由主义登场。翟东升：治中心国的病，外围国买单。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-term-10-46", "category": "名词解释", "question": "欧洲债务危机", "answer": "2009年底始于希腊、后蔓延至爱尔兰、葡萄牙、西班牙、意大利等欧元区国家的政府债务危机，暴露了欧元区\"统一货币、分散财政\"的制度性缺陷。 翟东升：欧债危机证明了**最优货币区条件在现实中几乎无法满足**——欧元区成员国经济结构差异大、劳动力流动受限、没有财政转移支付。这是政治意志强推货币统一的代价。", "explanation": "欧债危机证明了**最优货币区条件在现实中几乎无法满足**——欧元区成员国经济结构差异大、劳动力流动受限、没有财政转移支付。这是政治意志强推货币统一的代价。", "memorization": "希腊起火→南欧蔓延；根源=有统一央行没统一财政部。翟东升：最优货币区条件不满足的活教材。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-term-10-47", "category": "名词解释", "question": "华盛顿共识", "answer": "1989年由美国经济学家威廉姆森总结的一套以新自由主义为内核的经济政策药方，被IMF和世界银行推广为发展中国家改革的\"标准方案\"。 翟东升：华盛顿共识**不是中性的经济学建议，而是美国推行新自由主义全球化的意识形态工具**。它要求发展中国家打开市场、放松管制、私有化国有资产，实质是为西方资本进入和收割铺路。拉美\"失去的十年\"、俄罗斯\"休克疗法\"的灾难都与盲目执行华盛顿共识直接相关。中国的发展奇迹恰恰在于**有选择地吸收而非照搬**——开放市场但保留资本管制，引入外资但国家掌握关键产业。", "explanation": "华盛顿共识**不是中性的经济学建议，而是美国推行新自由主义全球化的意识形态工具**。它要求发展中国家打开市场、放松管制、私有化国有资产，实质是为西方资本进入和收割铺路。拉美\"失去的十年\"、俄罗斯\"休克疗法\"的灾难都与盲目执行华盛顿共识直接相关。中国的发展奇迹恰恰在于**有选择地吸收而非照搬**——开放市场但保留资本管制，引入外资但国家掌握关键产业。<br>📺 拉美·<a href='https://www.bilibili.com/video/BV15b4y1Q7Ez' target='_blank' style='color:#6a8899;text-decoration:underline'>陈平眉山论剑《拉美借债史》（18.8万）</a> ｜ 俄罗斯·<a href='https://www.bilibili.com/video/BV1b5411x7Kn' target='_blank' style='color:#6a8899;text-decoration:underline'>有机社会《叶利钦如何打断俄罗斯脊梁骨》（110.3万）</a>", "memorization": "\"四化\"药方（自由化、私有化、市场化、去管制化）。翟东升：不是经济学建议，是美国资本开路先锋。中国成功在于有选择地吸收而非照搬。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-short-10-1", "category": "简答题", "question": "新冠疫情期间美国的量化宽松为什么在此后几年内反而导致美元指数的上涨？", "answer": "反直觉现象：QE印钱但美元指数反升。原因：1. **避险需求**：危机中全球资金涌入美元资产（美债、美元现金），推高美元；2. **美元荒**：全球美元流动性短缺（供应链断裂、贸易融资缺口），美联储QE主要解决美国国内，全球仍缺美元；3. **非美货币更弱**：欧洲、日本、发展中国家经济受冲击更大，货币相对贬值；4. **美国复苏更快**：疫苗+财政刺激+科技股，吸引资金回流。翟东升：美元霸权在危机中反而强化——\"安全资产陷阱\"，危机暴露了外围国的脆弱性，强化了中心国的吸引力。", "explanation": "", "memorization": "QE印钱但美元反升，因为：避险（买安全资产）+ 美元荒 + 非美更弱 + 美国复苏快。翟东升：美元霸权在危机中反而强化——\"安全资产陷阱\"。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-short-10-2", "category": "简答题", "question": "近年来美国对华经济政策造成了东亚生产网络的哪些变化？", "answer": "四大变化：1. **供应链\"近岸化\"与\"友岸化\"**：美国对华加征关税→部分劳动密集型和最终组装环节加速向越南、墨西哥等国转移；2. **东亚区域内部整合反而加深**：美国压力推动区域内贸易额攀升，中国保持对周边国家强大的中间品供应能力，中国作为\"区域终端品集成出口者\"和\"中上游零部件供应中心\"的双重地位更加巩固；3. **中国在产业链中的地位升级**：美国高科技封锁倒逼中国加速自主创新和产业升级；4. **区域多中心化**：越南、印度等成为新节点，但中国仍是核心。翟东升：美国的\"脱钩\"政策**搬起石头砸自己的脚**——不但没有削弱中国在东亚网络中的核心地位，反而加速了中国的产业升级和区域内部整合。美国的关税只是改变了顺差的来源国（从中国变成越南、墨西哥），**整体逆差并未减少**。", "explanation": "美国的\"脱钩\"政策**搬起石头砸自己的脚**——不但没有削弱中国在东亚网络中的核心地位，反而加速了中国的产业升级和区域内部整合。美国的关税只是改变了顺差的来源国（从中国变成越南、墨西哥），**整体逆差并未减少**，证明贸易失衡的根源在美国自身的储蓄-投资结构，而非中国。", "memorization": "四变——近岸转移 · 区域内整合加深 · 中国升级 · 多中心化。翟东升：脱钩搬石砸脚，顺差只是换了来源国。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-short-10-3", "category": "简答题", "question": "拜登经济学与新华盛顿共识，反映了美国民主党政府怎样的贸易和产业思维？", "answer": "拜登经济学与新华盛顿共识的本质是**旧华盛顿共识的\"自我否定\"**——美国对外推了40年的新自由主义药方，现在自己不吃了，反而搞起了产业政策和保护主义。这说明新自由主义全球化已经走到尽头。但新华盛顿共识的核心仍是**遏制中国崛起**——只不过从\"全面脱钩\"变成了\"精准打击\"，从\"让市场干\"变成了\"政府干预+盟友协同\"。四大特征：1. 反思\"涓滴效应\"，转向\"中产外交\"；2. 财政大手笔（IRA、CHIPS Act）搞产业政策；3. \"小院高墙\"+盟友围堵（芯片四方联盟、出口管制）；4. 供应链\"去风险化\"。翟东升：美国40年推的药自己不吃了——新自由主义终结的信号，但遏制中国的战略目标未变。", "explanation": "拜登经济学与新华盛顿共识的本质是**旧华盛顿共识的\"自我否定\"**——美国对外推了40年的新自由主义药方，现在自己不吃了，反而搞起了产业政策和保护主义。这说明新自由主义全球化已经走到尽头。但新华盛顿共识的核心仍是**遏制中国崛起**——只不过从\"全面脱钩\"变成了\"精准打击\"，从\"让市场干\"变成了\"政府干预+盟友协同\"。", "memorization": "新自由主义→产业保护主义的转向。四特征：反思涓滴 · 中产外交 · 财政大手笔 · 盟友围堵。翟东升：美国40年推的药自己不吃了——新自由主义终结的信号。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-essay-10-1", "category": "论述题", "question": "2012年之前的双顺差导致中国外汇储备急剧被动扩张，在此背景下，央行货币政策剥夺了谁？补贴了谁？请论述原因", "answer": "【一个前提 → 两类工具 → 三类受害者 → 四类受益者】前提：双顺差→外汇供给远超需求→央行被迫大量买入外汇→外汇占款膨胀→基础货币被动投放过多→央行必须\"冲销\"过剩流动性。两类工具：冲销工具（提高存准/发行央票）→推高市场利率；金融压制（利率管制）→压低存款利率。三类受害者：1. **纳税人**：财政存款低利率存央行 = 税收被用来补贴央行对冲操作；2. **储蓄者**：负实际利率，购买力被侵蚀；3. **实体企业（尤其是民营）**：贷款利率不低，融资贵+融资难。四类受益者：1. **出口企业**（尤其是大型国企）享受低汇率+低融资成本；2. **美元体系**（中国用真金白银换美钞）；3. **房地产与地方政府**（低利率刺激资产泡沫）；4. **金融中介**（存贷利差扩大）。翟东升：这是出口导向型增长模式内嵌的**财富转移链条**——沉默的大多数（纳税人、储户、实体企业）承担代价，特定利益集团和美元体系享受收益。", "explanation": "", "memorization": "前提：双顺差→外汇占款→冲销。两工具：提存准/央票 + 利率管制。三受害：纳税人·储蓄者·民营。四受益：出口企业·美元体系·地产&地方政府·金融中介。翟东升：出口导向模式内嵌的财富转移链条。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-essay-10-2", "category": "论述题", "question": "中国公开市场操作的困境有哪些？央行可用什么\"池子\"吸纳和对冲流动性", "answer": "四大困境：1. **国债市场深度不足**：可供央行买卖的国债规模有限，操作空间小；2. **工具单一**：主要靠存准率和央票，缺乏欧美式的多元化工具；3. **被动性强**：操作目标是维持汇率稳定，而非主动调节利率或通胀；4. **传导机制不畅**：利率市场化不完全，公开市场操作信号向实体经济传导受阻。五大\"池子\"：1. 央行票据（央票）；2. 存款准备金；3. 公开市场回购（正逆回购）；4. 创新工具（MLF、SLF、TMLF等）；5. 国债买卖（逐步扩大）。翟东升：各种\"池子\"本质上都是**央行为维持汇率稳定而冲销外汇占款的\"补救措施\"**。根本解决之道不是发明更多\"池子\"，而是**让汇率更加市场化**，让央行从被动冲销中\"解放\"出来，回归以利率为核心的间接调控。", "explanation": "", "memorization": "> 四大困境：国债浅 · 工具少 · 被动强 · 传导堵 > 五大池子：央票 · 存准 · 回购 · 创新工具（MLF/SLF等）· 国债买卖 > 翟东升：池子是补救，根本出路是汇率市场化", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-essay-10-3", "category": "论述题", "question": "美国指责中国是搭便车者。请反驳此观点，并探讨中国由于加入美国主导的全球化所获得的收益和支付的代价", "answer": "【四点反驳 → 四大收益 → 四大代价 → 翟东升总评】四点反驳：1. 中国是全球经济增长主引擎（贡献率超30%），是\"稳定器\"和\"动力源\"；2. 中国是现行体系的积极参与者和建设者（联合国第二大会费国+维和摊款国）；3. 中国为美国霸权提供了关键支撑（购买美债+提供廉价商品+压低美国通胀）；4. \"搭便车\"论是霸权护持的话术，当中国从追随者变为竞争者，美国便将合理的发展诉求污名化。四大收益：工业化崛起、技术管理能力提升、融入全球价值链、消除极端贫困。四大代价：环境与劳工权益压力、产业链低端锁定、贫富分化加剧、向美元体系缴纳巨额\"货币地租\"（美债+外汇储备）。翟东升总评：**中国不是搭便车者，而是被收了\"车费\"的乘客**。现在中国要从乘客变成\"造车人\"——通过一带一路、亚投行、人民币国际化、产业升级，逐步构建不完全依赖美元体系的平行网络。", "explanation": "", "memorization": "四反驳：增长引擎+体系建设者+撑美元（美债/廉价品/抑通胀）+话术污名化。四收益：工业化·技术·全球链·脱贫。四代价：环境·低端锁定·贫富分化·货币地租。翟东升：中国不是搭便车，是被收了\"车费\"的乘客→正从乘客变\"造车人\"。", "source": "翟东升-货币金融-模拟10"},

    {"id": "ipe-term-01-48", "category": "名词解释", "question": "2008全球金融危机", "answer": "2007-2008年起源于美国次级房贷市场、通过金融衍生品全球扩散的系统性危机，雷曼兄弟破产（2008.9.15）是标志性事件，引发大萧条以来最严重的全球经济衰退。传导链：低利率+监管松弛→次贷泡沫→MBS/CDO证券化扩散→房价崩溃→衍生品价值归零→全球信用紧缩。翟东升：2008危机是**美元霸权体系内在矛盾的一次总爆发**——美国通过金融创新将风险打包外售，向全球转嫁信用扩张后果；危机后美联储QE反而进一步强化了美元霸权，\"搞出危机的人反成了救世主\"。", "explanation": "传导链：低利率+监管松→次贷泡沫→证券化扩散→房价崩→衍生品归零→全球信用紧缩。翟东升：美元霸权内在矛盾总爆发，危机后QE反强化美元地位。", "memorization": "次贷→MBS→雷曼倒→全球危机。翟东升：搞出危机的人反成救世主。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-term-01-49", "category": "名词解释", "question": "金汇兑本位制", "answer": "一战后黄金储量不足以维持古典金本位，各国转而以英镑或美元等关键货币为储备，再间接与黄金挂钩的货币制度。普通国家不直接持有黄金，而持有可兑换黄金的关键货币（英镑/美元），关键货币国再将其货币与黄金挂钩。布雷顿森林体系实质上是金汇兑本位的最高级形态（美元-黄金双挂钩）。翟东升：金汇兑本位看似是技术性安排，实则是**中心国以规则之名攫取铸币税特权**的制度设计——只有美国才能直接兑换黄金，其他国家只能持有美元，美国享有\"嚣张的特权\"。", "explanation": "普通国家持关键货币（英镑/美元），关键货币国再与黄金挂钩。布雷顿森林体系是其最高级形态。翟东升：中心国以规则之名攫取铸币税的制度设计。", "memorization": "不直接持金→持英镑/美元→间接兑金。翟东升：中心国铸币税特权的制度外衣。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-term-01-50", "category": "名词解释", "question": "中心外围关系", "answer": "普雷维什-辛格命题基础上发展的国际政治经济学理论框架：中心国（发达国家）主导技术、资本、货币定价权，外围国（发展中国家）提供劳动力、原材料和市场，两者之间存在不平等的结构性交换——初级产品贸易条件长期恶化，外围国向中心国持续输送剩余价值。翟东升：中心外围关系不只是经济分工，更是**权力结构的体现**——谁掌握货币定价权、技术标准和金融市场，谁就是中心。中国正从外围向\"半中心\"跃升，关键是守住制造业基本盘和推进人民币国际化。", "explanation": "中心掌握技术资本货币定价权，外围提供劳动原材料市场；初级产品贸易条件长期恶化，外围持续向中心输送剩余价值。", "memorization": "中心=定价权+技术，外围=劳动+原材料；贸易条件恶化是外围宿命。翟东升：守制造业+人民币国际化是跃升之路。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-term-01-51", "category": "名词解释", "question": "贸易溢出效应", "answer": "一国的经济政策（尤其是贸易、汇率、财政政策）对他国经济产生的非预期影响，分为正溢出（如中国经济增长带动大宗商品出口国受益）和负溢出（如美国量化宽松导致热钱冲击新兴市场）。翟东升：最重要的贸易溢出效应是**中国\"五重价格革命\"**——中国制造业崛起使全球工业制成品、运力、电力、算力、火力五大领域价格大幅下降，给全球消费者带来巨大正溢出效应，但也冲击了其他国家的制造业就业（逆全球化的根源之一）。", "explanation": "一国政策对他国经济的非预期影响，有正负之分。翟东升：中国五重价格革命是最重要的正溢出效应，但也是逆全球化情绪的来源。", "memorization": "中国制造→全球价格下降（正溢出）；美国QE→热钱冲击新兴市场（负溢出）。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-term-01-52", "category": "名词解释", "question": "新自由主义", "answer": "20世纪70-80年代兴起、以里根/撒切尔为政治代表的经济思潮，核心主张：自由市场万能论、私有化、去管制化、贸易和资本自由化、削减社会福利。理论来源：哈耶克（自发秩序）、弗里德曼（货币主义）、芝加哥学派。政策实践：里根经济学、撒切尔主义、华盛顿共识。翟东升：新自由主义**不是中性的经济学理论，而是资本阶级的意识形态工具**——它为资本的全球流动移除障碍，以\"效率\"话语掩盖分配不平等；其全球推广（华盛顿共识）本质上是为美国资本开拓市场、为美元体系维持霸权服务。2016年以来的逆全球化浪潮正是新自由主义40年恶果的政治反弹。", "explanation": "核心：自由市场万能+私有化+去管制化+贸易资本自由化。代表：里根/撒切尔，理论：哈耶克+弗里德曼。翟东升：资本阶级意识形态工具，华盛顿共识是其国际推广版。", "memorization": "三化：私有化+自由化+去管制。翟东升：资本阶级工具，正在崩溃（2016年逆全球化）。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-term-01-53", "category": "名词解释", "question": "全球化与逆全球化", "answer": "全球化：商品、服务、资本、劳动力、信息跨国流动的深化趋势，以国际分工和相互依存为特征；二战后有两波高峰：1860-1914（古典金本位+蒸汽化）和1980-2008（新自由主义+互联网）。逆全球化：2008年危机后、2016年特朗普当选为标志，各国转向贸易保护主义、民粹主义、供应链本地化，代表事件：英国脱欧、中美贸易战、疫情期间的供应链重组。翟东升：逆全球化的根源不是\"民粹\"，而是**新自由主义全球化收益分配极度不均**——制造业劳动者受损，资本家和金融精英获益；全球化并不\"死亡\"，而是进入**重组阶段**——从\"美元体系主导的全球化\"转向\"多极竞争的区域化\"。", "explanation": "全球化=跨国流动深化；逆全球化=保护主义+民粹+供应链重组。翟东升：根源是新自由主义收益分配不均，逆全球化不是终结而是重组。", "memorization": "全球化两波：1860-1914+1980-2008。逆全球化：2016年特朗普+英国脱欧。翟东升：分配不均是根源，重组而非终结。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-short-01-1", "category": "简答题", "question": "中央外围体系下，中央国家的代价有哪些？", "answer": "【三大代价】①**去工业化（产业空心化）**：货币霸权导致本币高估，制造业成本相对偏高→制造业外移→中产阶级就业流失→贫富分化→政治极化（特朗普现象的深层根源）。②**\"荷兰病\"困境**：货币持续强势→出口竞争力受损→非资源出口部门萎缩→经济结构失衡。③**金融部门过度膨胀（金融化）**：实体投资回报率低于金融投资→资本流向虚拟经济→资产泡沫频发→经济脆弱性上升。翟东升：美国是中央国家代价最典型的体现——美元霸权带来\"嚣张的特权\"，也带来制造业空心化和社会撕裂，这是**\"帝国税\"**。", "explanation": "去工业化+荷兰病+金融化，是货币霸权的三大副作用。翟东升：美国制造业空心化是美元霸权的代价，称为\"帝国税\"。", "memorization": "三代价：去工业化（就业）+荷兰病（出口）+金融化（泡沫）。翟东升：帝国税。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-short-01-2", "category": "简答题", "question": "简述美元霸权的条件。", "answer": "【五大支柱】①**经济科技优势**：美国GDP全球第一（长期）、科技创新领先、跨国公司主导全球市场；②**地缘政治控制力**：军事存在覆盖关键航运线和石油产区，通过军事同盟体系维护美元结算规则；③**货币锚的演进**：从黄金锚→石油锚（1974年基辛格-沙特协议）→美国国债锚，完成信用换锚而未失去主导；④**全球最深最广的金融市场**：美国国债市场规模最大、流动性最强，全球资本别无选择；⑤**网络效应与路径锁定**：历史惯性+SWIFT系统+大宗商品美元计价，转换成本巨大。翟东升：美元霸权的核心在于**替代品太弱**，而非美元自身多强；遵循货币份额幂律分布，赢者通吃。", "explanation": "五大支柱：经科优势+地政控制+锚的演进+金融市场深度+网络锁定。翟东升：美元强不在自身强，在于替代品弱；幂律分布。", "memorization": "五柱：经科·地政·换锚·金融深·网络锁。翟东升：替代品太弱是关键。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-short-01-3", "category": "简答题", "question": "简述世界市场体系的基本结构性特点。", "answer": "【四大结构性特点】①**等级性（不平等性）**：中心国掌握定价权、技术标准和金融规则，外围国处于从属地位；贸易条件长期不利于外围（普雷维什-辛格命题）。②**不对称性**：中心国政策失误可向外输出代价（QE热钱冲击外围），外围国危机只能自行承担（无全球最后贷款人）。③**锁定性（路径依赖）**：全球分工格局一旦形成，因技术积累、网络效应、制度惯性而难以改变；外围国向中心攀升异常艰难。④**动态演化性**：世界体系格局并非一成不变，历史上中心从英国转移到美国；当前中国的崛起正在推动下一轮权力结构重组。", "explanation": "等级性+不对称性+锁定性+动态演化性。翟东升：体系对外围不公平但并非铁板一块，中国是当前重组的推动力。", "memorization": "四特点：等级·不对称·锁定·动态。翟东升：体系可变，中国是当前重组推动力。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-short-01-4", "category": "简答题", "question": "简述中国对外经济关系的\"三外路线\"。", "answer": "\"三外路线\"：**鼓励外贸、吸引外资、控制外汇**，是改革开放后中国对外经济战略的核心。①鼓励外贸：以出口导向为增长引擎，通过低成本制造嵌入全球价值链，积累外汇和技术溢出；②吸引外资：通过税收优惠、基础设施、市场准入换取FDI流入，补充资本缺口并获取管理和技术知识；③控制外汇：实行强制结售汇制度+资本账户管制，将出口所得外汇集中于央行管理，既维持汇率稳定又防范金融风险。翟东升：三外路线是中国在特定发展阶段**充分利用全球化红利**的精准战略，但双顺差积累的巨额外储也使中国向美元体系缴纳了大量\"货币地租\"，随着经济转型，\"三外路线\"正向\"双循环+人民币国际化\"新模式演进。", "explanation": "外贸（出口引擎）+外资（FDI填补缺口）+外汇（强制结售汇+资本管制）。翟东升：利用全球化红利的精准战略，但代价是货币地租；正向双循环演进。", "memorization": "三外：外贸+外资+外汇。翟东升：聪明但有代价，正在升级为双循环。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-essay-01-1", "category": "论述题", "question": "从20世纪70年代开始，阿根廷、智利、乌拉圭等发展中国家实施了一系列金融自由化改革，从政治经济学角度论述其经验教训和对我国未来金融改革的启示。", "answer": "【改革背景→三大失败模式→四条教训→中国启示】背景：70年代布雷顿森林崩溃后，拉美国家在军政府或技术官僚推动下快速推行金融自由化（放开利率、开放资本账户、银行私有化）。三大失败模式：①智利（1975-1982）：\"芝加哥男孩\"主导急速自由化→高利率+汇率高估→银行危机+债务危机，1982年崩溃，国家接管全部银行；②阿根廷（80-90年代反复）：\"比索-美元等价制\"→货币危机→2001年有史以来最大主权违约；③乌拉圭：受阿根廷传染，2002年银行挤兑危机。四条政治经济学教训：①金融自由化不能脱离实体经济支撑，没有强大制造业的金融开放等于门户洞开；②资本账户开放过急→热钱流入制造泡沫→外部冲击时资本外逃引爆危机；③汇率制度选择至关重要——盯住美元+过度举债+竞争力下降=死亡组合；④IMF的\"条件性贷款\"（紧缩+私有化+进一步开放）不是救助，而是为下一轮收割拆除防火墙。中国启示：中国的成功在于**拒绝照搬华盛顿共识**——资本账户审慎开放、维持强大制造业、国家掌握金融资源配置权；未来金融改革须坚持\"渐进+有管理+守住制造业基本盘\"三原则。翟东升：拉美金融自由化是**\"美元潮汐收割\"的经典实验室**，中国应引以为戒。", "explanation": "", "memorization": "三国失败：智利（芝加哥男孩）·阿根廷（等价制）·乌拉圭（传染）。四教训：实体先行·慎开资本账户·汇率制度·警惕IMF。翟东升：美元潮汐实验室。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-essay-01-2", "category": "论述题", "question": "1980年代之后的美国为什么要搞新自由主义全球化？2016年之后的美国为什么会掀起逆全球化浪潮？", "answer": "【新自由主义全球化三大动因→逆全球化三大根源】一、1980年代搞新自由主义全球化：①**资本积累危机的出路**：70年代滞涨使凯恩斯主义内需调控失灵，资本需要全球开拓新市场和廉价劳动力，放开贸易和资本流动是资本积累的内在需求；②**维护美元霸权的制度需要**：布雷顿森林崩溃后，通过金融自由化全球化扩大美元使用范围（石油美元循环+国债吸纳全球储蓄），以\"制度帝国主义\"替代\"实物帝国主义\"；③**冷战终结的意识形态攻势**：\"历史终结论\"将资本主义全球化包装为人类文明终点，西方有强烈的意识形态扩张动力。二、2016年后逆全球化三大根源：①**国内分配恶化**：40年全球化使美国制造业就业流失约500万，中产阶级萎缩，贫富分化加剧，\"赢家\"是资本和金融精英，\"输家\"是蓝领工人；②**中国崛起打破霸权预期**：\"接触政策\"预期失败——中国以不同模式崛起并挑战美国的技术和产业领导地位；③**民粹主义的政治表达**：全球化失利群体通过选票支持保护主义政客（特朗普），以\"本国优先\"宣泄不满。翟东升：逆全球化不是意外，而是新自由主义内在矛盾的**必然政治爆发**；全球化的形式会改变（从美元单极化向多极区域化重组），但相互依存不会终结。", "explanation": "", "memorization": "新自由主义：资本出路+美元霸权+冷战意识形态。逆全球化：分配恶化+中国崛起+民粹爆发。翟东升：逆全球化是新自由主义内在矛盾的政治爆发。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-essay-01-3", "category": "论述题", "question": "我国外资FDI政策经历了何种演变历程，论述各阶段政策背后的政治经济诉求。", "answer": "【四阶段演变→各阶段政治经济诉求】①试验起步期（1978-1991）：设立深圳等经济特区，以\"特区\"隔离风险；以\"三来一补\"（来料加工、来样加工、来件装配、补偿贸易）为主。诉求：引进外汇和技术，解决资本缺口，实验市场化改革路径而不冒全面转型风险。②规模扩张期（1992-2001）：邓小平南方谈话+市场经济体制确立，外资政策全面放开，进入制造业和出口加工业；\"两免三减半\"税收优惠。诉求：以规模换速度，快速推进工业化，积累出口创汇能力，\"以市场换技术\"。③深化入世期（2001-2012）：加入WTO，外资大规模流入，中国成为\"世界工厂\"；外资政策与WTO规则衔接，国民待遇原则普遍适用。诉求：利用国际规则约束倒逼国内改革，深度嵌入全球价值链，积累出口规模和产业能力。④优化升级期（2012至今）：从\"招商引资\"转向\"选商择资\"，强调\"高质量外资\"；安全审查制度建立（2020年外商投资法），对敏感行业限制加强，支持先进制造和服务业外资。诉求：产业升级需要高端外资（研发+先进技术），同时维护国家经济安全。翟东升总评：外资政策演变体现了**国家能力驾驭外资服务于自身发展目标**的能动性——中国成功在于国家始终把握方向，让外资在国家战略框架内运行；未来应从\"以市场换技术\"升级为\"以市场换股权\"，参与国际产业分工主导权之争。", "explanation": "", "memorization": "四阶段：试验起步（78-91）→规模扩张（92-01）→入世深化（01-12）→优化升级（12至今）。翟东升：国家始终驾驭外资，市场换技术→市场换股权。", "source": "翟东升-货币金融-模拟01"},

    {"id": "ipe-term-02-54", "category": "名词解释", "question": "外汇占款", "answer": "央行在外汇市场购入外汇时，向市场（商业银行）投放的等值人民币，是外汇储备形成过程中被动投放的基础货币。计算：外汇占款增量≈外汇储备增量×汇率。2003-2014年间，外汇占款是中国基础货币投放的最主要渠道，峰值超过27万亿元。翟东升：外汇占款机制是中国\"三外路线\"中\"控制外汇\"的核心制度传导链——企业出口→强制结售汇→央行被迫购汇→外汇占款膨胀→基础货币被动扩张→央行再通过存准/央票冲销→这整个过程是**出口导向型增长模式在货币层面的制度性体现**，其背后是复杂的利益博弈和财富分配。", "explanation": "央行购入外汇时被动投放的人民币，是外汇储备形成时的基础货币来源。2003-2014年是中国基础货币主要来源。", "memorization": "企业出口所得外汇→强制结汇→央行购汇投放人民币=外汇占款。翟东升：出口导向模式在货币层面的制度体现。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-term-02-55", "category": "名词解释", "question": "铸币税", "answer": "货币发行者（央行或主权国家）通过发行货币获得的收益，等于货币面值减去铸造成本之差。在现代信用货币体系下，铸币税主要体现为：①国内铸币税：央行印钞购买政府债券，名义上是\"借款\"，实际政府获得实际资源而支付的成本接近于零；②国际铸币税：储备货币国（主要是美国）可以用本国印制的纸币换取他国的真实商品和服务。翟东升：国际铸币税是美元霸权最核心的收益——**\"印纸换资源\"**。中国持有的3万亿美元外储，大部分是中国以真实劳动和资源向美国缴纳的\"货币地租\"；改革国际货币体系、实现铸币税全球共享是翟东升的核心政策主张。", "explanation": "货币发行者通过发行货币获得的收益（面值-成本）。国际铸币税：储备货币国用纸币换真实资源。翟东升：国际铸币税=印纸换资源，是美元霸权最核心收益。", "memorization": "铸币税=面值-成本。国际铸币税：美国印美元换全球资源。翟东升：中国外储是向美国缴纳的货币地租。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-term-02-56", "category": "名词解释", "question": "加工贸易", "answer": "企业进口原材料、零部件，在国内加工、组装成成品后再出口的贸易方式，核心特征是\"两头在外\"（原料进口、产品出口），主要形式包括来料加工和进料加工。加工贸易是改革开放后中国制造业快速发展的重要路径，鼎盛时期（2000年代）占中国出口的约55%。翟东升：加工贸易将中国嵌入全球价值链的**组装环节**，获得就业和外汇但附加值极低（\"微笑曲线\"底部）；它是\"三外路线\"的具体体现，也是中国低估汇率换取出口规模的制度载体。随着劳动力成本上升和产业升级，加工贸易占比已大幅下降，是产业升级的重要指标。", "explanation": "\"两头在外\"（原料进口+产品出口），是中国制造业嵌入全球价值链的主要方式，附加值低（微笑曲线底部）。", "memorization": "两头在外=来料加工+进料加工。翟东升：低附加值换就业和外汇，是三外路线载体，正在升级中。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-term-02-57", "category": "名词解释", "question": "资源诅咒", "answer": "丰富的自然资源（石油、矿产）反而导致经济发展停滞的现象，又称\"荷兰病\"（Dutch Disease）。机制：资源出口繁荣→本币升值→制造业出口竞争力下降→非资源产业萎缩→经济结构畸形→一旦资源价格下跌即陷入危机。典型案例：中东石油国（高度依赖石油，制造业薄弱）；尼日利亚、委内瑞拉（资源丰富但发展停滞）。翟东升：资源诅咒深刻揭示了**货币汇率与产业结构的互动关系**——资源富集导致汇率高估，等同于向制造业征税；它是中心-外围理论的重要补充，也是翟东升强调\"守住制造业才是真正的国力\"的理论依据之一。", "explanation": "资源丰富→本币升值→制造业萎缩→经济结构畸形。\"荷兰病\"是其另一名称。翟东升：揭示汇率与产业结构互动，守住制造业才是真国力。", "memorization": "资源越丰→制造越弱（荷兰病机制）。翟东升：制造业才是真国力，资源是诅咒而非祝福。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-term-02-58", "category": "名词解释", "question": "强制结售汇制度", "answer": "1994年汇率并轨后中国实行的外汇管理制度：境内企业和居民取得的外汇收入必须在规定期限内卖给指定外汇银行（结汇），所需外汇须向指定银行购买（售汇），央行作为外汇市场的\"最终买家\"。该制度将外汇收支集中于国家管控，是外汇储备快速积累的制度基础，直到2012年后逐步改革（允许企业保留外汇）。翟东升：强制结售汇制度是\"三外路线\"中\"控制外汇\"的核心制度工具——**把全社会的美元集中到国家手里**，既维持了汇率稳定、避免了炒汇，也使外储积累成为一种\"行政命令下的被动行为\"，本质上是**将个人和企业的汇率风险社会化由国家统一承担**。", "explanation": "企业外汇收入须卖给银行，所需外汇须向银行购买，央行为最终买家。是1994年汇改后外储积累的制度基础。翟东升：三外路线中控制外汇的核心工具。", "memorization": "外汇收入必须卖给银行（结汇），央行是最终买家。翟东升：把全社会美元集中到国家手里，汇率风险社会化。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-term-02-59", "category": "名词解释", "question": "黄金输送点", "answer": "古典金本位制度下，当两国之间汇率偏离铸币平价一定幅度（运输+保险成本）时，直接运输黄金比在外汇市场买卖更合算，从而触发黄金流动的临界点。分为黄金输出点（汇率高于上限→从本国运金出口）和黄金输入点（汇率低于下限→从外国运金进口）。黄金输送点机制使金本位下的汇率稳定在铸币平价附近窄幅波动，是金本位\"自动调节\"的关键机制。翟东升：黄金输送点机制看似精妙，实则使外围国家在经常项目逆差时被迫承受黄金外流和通货紧缩——**调节的成本永远由外围国承担**，而不是中心国，这是金本位制度权力不对称的具体表现。", "explanation": "金本位下汇率偏离铸币平价超过运金成本时，黄金自动流动。黄金输出点（本币弱）和黄金输入点（本币强）。翟东升：调节成本由外围承担，是金本位权力不对称的体现。", "memorization": "汇率偏离过大→运金比换汇合算→黄金自动流动→汇率回归。翟东升：外围国在逆差时被迫通缩，调节成本不对称。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-short-02-1", "category": "简答题", "question": "1971年以来的全球货币体系有什么基本特点？", "answer": "【牙买加体系五大特点】①**无锚的信用货币体系**：美元脱离黄金后不与任何实物挂钩，美元信用建立在美国综合国力和政治意志上，本质是\"主权信用锚\"；②**浮动汇率为主**：1976年牙买加协议确立汇率自由浮动原则，各国可自主选择汇率制度，全球汇率不确定性大幅上升；③**美元中心地位延续甚至强化**：布雷顿森林崩溃后美元不仅未衰落，反而通过石油美元循环和国债市场维持主导地位；④**国际流动性高度不稳定**：美联储货币政策的外溢效应主导全球流动性周期（美元潮汐），制造反复的新兴市场金融危机；⑤**缺乏对称调整机制**：逆差国被迫紧缩，顺差国（尤其是美国）无需承担调整义务，体系极度不对称。翟东升：牙买加体系不是\"国际协议\"而是**美国单方面宣布的规则**——美国享有不受约束的铸币权，其余国家在这套规则下各自为战。", "explanation": "五特点：无锚信用货币+浮动汇率+美元主导延续+流动性不稳定+调整不对称。翟东升：牙买加体系是美国单方面宣布的规则。", "memorization": "五特点：无锚·浮动·美元主导·流动性不稳·调整不对称。翟东升：美国单方面宣布的规则，其余国家各自为战。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-short-02-2", "category": "简答题", "question": "金本位制度的崩溃带给国际金融和世界经济的影响是什么？", "answer": "【对世界经济和国际金融的双重影响】对世界经济：①短期：崩溃初期引发全球货币战和贸易战，加剧大萧条（1930年代竞争性贬值）；②长期：摆脱黄金束缚为战后需求管理和经济繁荣提供政策空间，但也为全球性通胀和资产泡沫埋下伏笔。对国际金融：①权力结构根本转变：从\"商品锚\"转为\"主权信用锚\"，美元取代黄金成为体系中心，美国获得向全球征收铸币税的权力；②金融不稳定性加剧：脱离黄金→汇率浮动+资本流动频繁→金融危机频率和传染性大增（1971年后全球金融危机频率显著上升）；③中心-外围关系固化：美国可维持长期逆差（\"过度特权\"），外围国积累的美元储备沦为对美国的无息贷款。翟东升：金本位崩溃不是\"失败\"，而是美国的**\"制度升级\"**——脱离黄金束缚后，美国获得了无限制印钞的权力，美元霸权反而进一步强化。", "explanation": "世界经济：短期货币战+贸易战；长期政策空间扩大但通胀风险上升。国际金融：商品锚→信用锚，美元霸权确立，金融不稳定性加剧。翟东升：崩溃是美国制度升级。", "memorization": "对经济：短期贸易战，长期政策空间+通胀风险。对金融：信用锚确立+不稳定性加剧+美国过度特权。翟东升：崩溃=美国制度升级。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-short-02-3", "category": "简答题", "question": "金本位制度崩溃的根源是什么？", "answer": "【三层深层根源】①**物质基础瓦解**：全球经济呈指数级扩张，黄金产量增长缓慢→实物锚无法为爆炸式增长的贸易和金融提供足够流动性→必然引发通缩和体系紧绷（特里芬困境的根源）。②**权力与利益分配冲突**：体系过度依赖中心国（先英后美）的信用和政策→当中心国自身利益与全球责任冲突时（美国越战财政赤字+大社会计划），体系的信任基础被瓦解。③**民主政治与货币纪律的冲突**（翟东升最强调的维度）：金本位要求国内经济服从国际平衡的纪律（逆差→黄金外流→紧缩），但紧缩意味着失业；普选权扩张后，失业不再只是经济代价，更是选举代价→大萧条中率先放弃金本位的国家经济复苏更快→证明政治选择可以抛弃体系→**核心矛盾：一国愿意为国际货币体系的稳定付出多大的国内政治代价？**", "explanation": "三层根源：物质（黄金不够）+权力（中心国违约）+政治（民主vs货币纪律）。翟东升最强调第三层：民主政治与金本位纪律不可兼容。", "memorization": "三根源：黄金不够·中心国违约·民主vs纪律。翟东升：政治选择可以抛弃货币体系。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-short-02-4", "category": "简答题", "question": "请简述金本位在经常项目下的自动调节过程。", "answer": "【休谟\"价格-铸币流动机制\"（Price-Specie-Flow Mechanism）】假设A国出现经常项目逆差（进口>出口）：①A国用黄金偿付逆差→A国黄金外流→A国货币供给收缩→A国物价下降（通货紧缩）；②B国（顺差国）黄金流入→B国货币供给扩张→B国物价上升（通货膨胀）；③价格调整→A国出口商品变便宜、B国出口商品变贵→A国出口增加、进口减少→逆差自动收窄→体系恢复均衡。翟东升：这个\"自动调节\"机制有三大问题：①**调节不对称**（逆差国被迫通缩，顺差国无压力必须通胀，调整成本主要由逆差国外围国承担）；②**政治不可持续**（通缩意味着失业和经济衰退，民主国家无法长期忍受）；③**中心国特权**（作为关键货币国的英美在逆差时可以不立即失去黄金，机制对外围更严苛）。", "explanation": "休谟机制：逆差→黄金外流→货币收缩→物价下降→出口竞争力恢复→逆差收窄。翟东升：调节不对称（外围承担成本），政治不可持续。", "memorization": "逆差→黄金外流→物价降→出口变便宜→逆差缩小。翟东升：自动调节代价由外围承担，政治上不可持续。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-short-02-5", "category": "简答题", "question": "简述全球通胀率低的三个阶段及成因。", "answer": "【三阶段低通胀成因】①**1980年代初-1990年代**（沃尔克紧缩效应）：美联储主席沃尔克以极高利率（最高达20%）强力压通胀→货币主义政策确立→发达国家通胀预期锚定在低位；②**1990年代-2008年**（全球化红利+中国冲击）：中国（\"世界工厂\"）加入全球分工→全球制造业竞争加剧→工业品价格大幅下降→\"中国输出通缩\"；同时东欧解体+信息技术革命进一步压低成本；③**2008-2020年**（需求不足+量化宽松悖论）：金融危机导致需求长期疲弱→即便大规模QE也难以触发通胀→\"低增长、低通胀、低利率\"三低并存（日本化风险）。2021年后：新冠疫情+供应链断裂+能源危机终结了这一阶段，全球通胀重现。翟东升：中国在第二阶段的\"通缩输出\"是对全球最大的贡献之一，也是\"五重价格革命\"的主要内容，但美国将其解读为\"不公平贸易\"，是逆全球化叙事的重要来源。", "explanation": "三阶段：沃尔克紧缩（80年代）+中国冲击（90-2008）+需求不足（2008-2020）。翟东升：中国通缩输出是全球最大贡献，被美国误读为\"不公平\"。", "memorization": "三低通胀：沃尔克→全球化+中国→量化宽松失效（日本化）。翟东升：中国五重价格革命是最重要成因。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-essay-02-1", "category": "论述题", "question": "随着我国经济的发展，未来国内哪些类型的产业有可能面临对外转移的压力及原因？在这波产业转移浪潮中，中国应如何保持对核心产业链的掌控？", "answer": "【转移压力类型→原因→掌控策略】面临转移压力的三类产业：①**劳动密集型低端制造业**（纺织、服装、鞋类、简单电子组装）：中国劳动力成本持续上升（2000年代月均工资从500元升至现在数千元），越南、孟加拉、印尼等国相对成本优势显现；②**高污染高耗能产业**（化工、钢铁、有色冶炼的部分环节）：中国环保标准趋严，土地成本上升，加上碳中和目标约束，这些环节转移至标准较低的东南亚、非洲国家有成本动机；③**出口导向型组装加工**（受中美关税战影响）：为规避美国对华关税，部分企业将最终组装环节转移至越南、墨西哥（\"近岸化\"），以产地转换规避关税。中国保持核心掌控的四大策略：①**保住价值链的关键节点**：即便组装环节外移，也要把核心零部件（如MLCC、精密模具、特种材料）生产保留在国内，形成\"不可或缺的中间品\"；②**主动输出产业链**（一带一路逻辑）：与其被动承受产业外移，不如主动向东南亚、非洲等地输出产业，以\"产业链编辑能力\"（CICE）掌握海外产业网络的核心；③**加速产业升级**：从低端制造→高端制造+智能制造，占领微笑曲线两端（研发设计+品牌营销），让外移的只是低附加值环节；④**强化技术自主**：在芯片、操作系统、工业软件等关键\"卡脖子\"领域突破，使产业链中的关键技术不依赖外部。翟东升：产业转移是经济发展的自然规律，关键是**让转移的只是低附加值环节，让留下来的是定价权和关键技术**；\"产业链编辑能力\"（CICE）是大国维护产业领导地位的核心工具。", "explanation": "", "memorization": "三类转移：劳动密集型+高污染高耗能+受关税战影响的组装。四策略：守关键节点+主动输出产业链+加速升级+强化技术自主。翟东升：让转移的只是低附加值，CICE是核心工具。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-essay-02-2", "category": "论述题", "question": "从政治经济学角度诠释我国巨量外汇储备的成因及产生过程。", "answer": "【三层分析框架：制度→机制→政治经济学本质】制度基础：①强制结售汇制度（1994年汇改后）：企业出口所得外汇必须卖给银行→银行在外汇市场卖出→央行作为最终买家被动购入→外汇储备自动积累；②汇率管理目标：央行为维持人民币不大幅升值（保护出口竞争力），主动在外汇市场买入美元。外储积累的三大来源：①经常项目顺差（主体，\"世界工厂\"出口创汇）；②资本项目顺差（FDI+热钱流入）；③1994-2005年盯住美元导致的持续人民币低估。政治经济学本质（三层逻辑）：①**国内政治联盟**：出口企业（利润依赖低汇率）+外资企业（人民币低估使其在华成本低）+地方政府（GDP增长靠出口）+国有银行（外汇中介收益）形成强大利益联盟，共同支持维持低汇率=积累外储的政策；②**国际政治博弈**：低汇率换取美国对中国快速工业化的政治容忍，同时用外储（购买美债）为中美贸易关系提供\"债务稳定器\"；③**财富转移的隐秘机制**：外储积累本质上是全体中国人将劳动成果换成了美元纸资产——既然美联储可以随时增发美元稀释购买力，中国的外储实际上是**向美元体系缴纳的\"货币地租\"**（翟东升核心判断）。翟东升总结：外储数字越大，不是越有面子，而是**缴纳的货币地租越多**。应该用外储进行实体资产投资（一带一路）而非继续持有低收益美债。", "explanation": "", "memorization": "三来源：经常顺差+资本顺差+汇率低估。三层政治：国内联盟（出口+FDI+地方+银行）+国际博弈（债务稳定器）+财富转移（货币地租）。翟东升：外储越大，地租越多。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-essay-02-3", "category": "论述题", "question": "中国当今在全球市场体系中处在什么位置，其现阶段特点和判断指标有哪些，并给出下一步发展方向。", "answer": "【位置判断→现阶段特点→判断指标→发展方向】位置判断：中国已从\"外围\"跃升至\"半中心\"，正在向\"核心\"转变，但尚未完全进入中心——这是翟东升对中国当前世界市场体系定位的核心判断。现阶段特点（三个\"同时\"）：①同时具有中心国特征（制造业产值全球第一、货物贸易全球第一、基础设施能力全球领先）和外围国特征（核心技术仍有被\"卡脖子\"风险、人民币尚未完全国际化、资本账户未完全开放）；②同时面临来自两个方向的压力——高端技术被美国封堵、低端制造被越南/印度竞争；③同时推进两条路线——守住制造业基本盘+向高附加值端升级。判断指标：①产业结构指标：制造业增加值占GDP比重（维持在27%以上=健康）；②技术自主指标：在半导体、航空发动机、操作系统等关键领域自主率；③货币指标：人民币在国际结算/储备中的份额（SWIFT、SDR权重）；④价值链位置：出口产品附加值和技术含量（从加工贸易→一般贸易升级比重）。发展方向：①产业：从\"世界工厂\"→\"世界实验室\"，加大研发，向微笑曲线两端延伸；②货币：人民币国际化提速（贸易结算→债券市场→数字人民币）；③对外：以\"产业链编辑能力\"（CICE）主导一带一路产业布局；④制度：在WTO改革和新国际货币体系建设中争取更大话语权。翟东升：中国的目标不是复制美元霸权模式，而是构建一种**以制造业信用而非金融霸权为基础的\"民本主义\"国际经济新秩序**。", "explanation": "", "memorization": "位置：外围→半中心→向核心转变。三个同时：中心+外围特征并存·两头压力并存·两条路线并进。判断指标：制造业比重+技术自主率+人民币份额+附加值。翟东升：制造业信用而非金融霸权，民本主义新秩序。", "source": "翟东升-货币金融-模拟02"},

    {"id": "ipe-term-03-60", "category": "名词解释", "question": "央票（央行票据）", "answer": "中国人民银行以自身为债务人向商业银行等金融机构发行的短期债券，期限通常为3个月至1年，主要用于对冲外汇占款带来的过剩流动性。2003-2013年是央票的鼎盛时期，峰值时未偿余额达4万多亿元。央票相当于央行主动\"借钱\"来锁定银行体系的过剩资金，到期后不得不偿还→再次面临冲销压力→\"滚动对冲\"形成持续成本。翟东升：央票是一种**不得已的政策工具**——它是强制结售汇+汇率干预→外汇占款过多→被迫发行央票对冲的\"补救\"产品；央行为此支付利息，相当于**全体纳税人为\"出口导向型增长模式\"承担对冲成本**，体现了出口政治联盟的代价如何被社会化。", "explanation": "央行发行给商业银行的短期债券，用于对冲外汇占款（2003-2013年的主要冲销工具）。翟东升：补救工具，对冲成本由全体纳税人承担。", "memorization": "央行向商业银行借钱（发债）→锁定过剩流动性→对冲外汇占款。翟东升：补救工具，成本社会化。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-term-03-61", "category": "名词解释", "question": "雁行模式", "answer": "日本经济学家赤松要（1930年代）提出的东亚产业升级模型：先进国家（日本）先发展某产业→随着劳动力成本上升将该产业转移至次发达国家（亚洲四小龙）→再转移至更低成本国家（中国、东盟）——如同大雁飞行队形，头雁带动后雁依次跟进。该模式解释了东亚二战后的经济奇迹和产业梯度转移规律。翟东升：雁行模式在中国崛起后被**根本性颠覆**——中国不再是顺序承接\"头雁（日本）\"甩出的低端产业的\"尾雁\"，而是通过\"产业链编辑能力\"（CICE）跳过雁行队列，在多个产业同时从低端向高端冲击。新格局下中国已成为东亚产业网络的新\"头雁\"，但这并非线性传递，而是网络化、并联式的新型分工。", "explanation": "日本→四小龙→中国/东盟的梯度产业转移模型。翟东升：被中国崛起颠覆——中国跳过队列、成为新头雁，CICE取代雁行。", "memorization": "头雁（日本）带后雁（四小龙→中国→东盟）依次升级。翟东升：中国已颠覆雁行，成为新头雁。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-term-03-62", "category": "名词解释", "question": "\"三外路线\"", "answer": "翟东升对中国改革开放后对外经济战略核心的概括：**鼓励外贸（促进出口）、吸引外资（引进FDI）、控制外汇（强制结售汇+资本管制）**。三者相互配合：鼓励外贸→外汇流入增加；控制外汇（强制结售汇）→外汇流入变成央行外储积累；吸引外资→同时带来外汇和技术。三外路线使中国在短期内完成工业化所需的资本积累，但也制造了外汇储备过度积累、经常项目对出口依赖过深、人民币主权部分让渡等代价。翟东升：三外路线是特定历史阶段的**战略选择而非价值立场**——在资本积累不足、技术落后的初始条件下，这是最优的发展路径；随着中国经济成熟，应逐步向\"双循环\"模式演进。", "explanation": "鼓励外贸+吸引外资+控制外汇，三者相互配合推动中国快速工业化。翟东升：历史阶段最优路径，正向双循环演进。", "memorization": "三外：外贸+外资+外汇（强制结售汇）。翟东升：历史最优路径，现在升级为双循环。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-term-03-63", "category": "名词解释", "question": "量化宽松（QE）", "answer": "央行在政策利率接近零下界（零利率约束）时采用的非常规货币政策，通过在二级市场大规模购买中长期国债（及其他资产），直接向金融体系注入流动性、压低长期利率。2008年危机后美联储（2008-2014年三轮QE）、欧央行（2015年起）、日本央行（2013年起）相继实施。翟东升：QE的本质是**美联储代替财政部印钱购买国债**——既为政府赤字融资，又将超额储备注入银行体系；但大量新增流动性并未主要流向实体经济，而是推高资产价格（股市、债市、房市），加剧贫富分化。更重要的是，美国QE产生的美元流动性溢出全球，**\"制造全球泡沫→加息收水引爆外围危机\"是翟东升\"美元潮汐收割\"机制的第一步**。", "explanation": "零利率约束下央行购买长期资产的非常规货币政策，直接注入流动性。2008年后美欧日相继使用。翟东升：QE制造全球泡沫，美元潮汐收割的第一步。", "memorization": "政策利率→0时，央行直接买长期国债。翟东升：QE→美元溢出全球→泡沫→加息收割外围。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-term-03-64", "category": "名词解释", "question": "货币乘数", "answer": "货币供应量（M2）与基础货币之比，反映银行体系将一单位基础货币扩张为多单位货币供给的能力。公式：货币乘数 = 1 / （法定存款准备金率 + 超额存准率 + 现金漏损率）。若法定存准率为10%，理论货币乘数为10，即央行投放1元基础货币，银行通过存款-贷款-存款的循环最终创造10元货币。翟东升：货币乘数机制揭示了现代货币创造的**\"内生性\"**——货币不只是央行\"印出来\"的，更是银行体系\"贷出来\"的；当经济不景气时，信贷需求不足→货币乘数下降→即便央行大量投放基础货币也难以扩大货币供给（\"推绳子\"困境）。这是QE在实体经济传导效果有限的根本原因。", "explanation": "货币供应量/基础货币，反映银行扩张信用的能力。准备金率越低，乘数越大。翟东升：货币乘数揭示货币的内生性，QE效果受制于信贷需求。", "memorization": "货币乘数=M2/基础货币≈1/准备金率。翟东升：货币靠贷款创造，经济不景气时乘数下降→QE失效（推绳子）。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-term-03-65", "category": "名词解释", "question": "基础货币", "answer": "又称\"高能货币\"（High-Powered Money），是央行直接创造的货币，包括流通中的现金和商业银行在央行的存款准备金（法定+超额）。基础货币是整个货币供给体系的\"源头\"，银行体系通过货币乘数将其放大为更大的货币供应量（M2）。中国基础货币的投放渠道：2003-2013年以外汇占款为主（被动），2014年后外汇占款下降，改以MLF、再贷款等工具主动投放。翟东升：基础货币投放渠道的变化是中国货币政策从**\"被动式\"向\"主动式\"转型**的重要标志——从\"为维持汇率被迫购汇投放\"转向\"以定向工具支持特定实体经济领域\"，体现了货币政策独立性的逐步提升。", "explanation": "央行直接创造的货币=流通现金+银行准备金。是货币供给的源头，通过货币乘数放大为M2。翟东升：投放渠道从被动（外汇占款）→主动（MLF等），体现货币政策独立性提升。", "memorization": "基础货币=现金+准备金，是高能货币。翟东升：从被动购汇投放到主动MLF投放，是政策独立性提升的标志。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-term-03-66", "category": "名词解释", "question": "全球供应链", "answer": "产品从原材料采购、零部件生产、最终组装到销售分布于多个国家的全球化生产网络，以分工细化、比较优势最大化为特征。形成背景：贸易自由化（WTO）+信息技术（互联网+ERP系统）+运输成本下降（集装箱化）。翟东升：全球供应链是新自由主义全球化的核心制度成果，中国通过三外路线深度嵌入其中，成为\"世界工厂\"。但2020年后新冠疫情和中美博弈使全球供应链的**脆弱性暴露无遗**——过度集中在单一国家（中国）导致的供应链中断，引发西方国家的\"供应链安全化\"焦虑，推动供应链重组（近岸化/友岸化）。翟东升认为：即便供应链在形式上重组，中国作为中间品生产者和关键技术节点的地位仍难以在短期内被取代。", "explanation": "跨国分布的生产网络，以分工细化和比较优势为特征。翟东升：中国是全球供应链核心，2020年后供应链安全化推动重组，但中国关键地位难以短期取代。", "memorization": "全球供应链=原料→零件→组装→销售跨多国。翟东升：中国是核心，脆弱性暴露后重组但中国地位难撼动。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-short-03-1", "category": "简答题", "question": "哪些因素可驱动发展中国家主权债务违约？", "answer": "【五大驱动因素】①**外部冲击（美元潮汐）**：美联储加息→资本外流→外汇储备耗尽→无力还债（最常见触发器，如1982年墨西哥、1997年东南亚）；②**债务结构脆弱**：短期外币债务+浮动利率→利率上升+本币贬值双重打击→\"债务雪崩\"；③**经常账户持续逆差**：出口竞争力弱、大宗商品价格下跌→外汇收入减少→偿债能力下降；④**财政纪律崩溃**：政府过度举债（维持政治福利承诺）→债务/GDP比率突破临界点→市场信心崩溃→利率飙升→违约自我实现；⑤**政治动荡**：政权更迭或内战→政策不确定性→资本外逃→外汇耗尽。翟东升：主权债务违约的核心是\"**原罪**\"（无法以本币在国际市场借债）——一旦被迫以美元举债，便将偿债能力完全暴露于美联储的货币政策和汇率风险之下。", "explanation": "五因素：外部冲击（美元潮汐）+债务结构脆弱+经常逆差+财政失控+政治动荡。翟东升：\"原罪\"是根本——以美元举债即丧失主动权。", "memorization": "五驱动：美元潮汐+债务结构+经常逆差+财政失控+政治动荡。翟东升：原罪（只能借外币）是根本原因。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-short-03-2", "category": "简答题", "question": "简述对待债务的经济后果的不同看法。", "answer": "【三大学派对比】①**凯恩斯主义/后凯恩斯主义**：债务有益论——政府借债支出能创造需求、就业和收入，产生乘数效应；在经济衰退期政府举债是必要的稳定器（\"逆周期\"调控）。赤字不危险，重要的是\"谁来还\"和\"用来做什么\"。②**财政保守主义/奥地利学派**：债务有害论——政府债务挤出私人投资、扭曲利率、积累系统性风险；长期高债务必然导致财政危机，今天的赤字是明天的税负（李嘉图等价）。③**现代货币理论（MMT）**：货币主权论——主权货币国（如美国）不受偿债能力约束，可持续印钱偿债；政府支出的唯一约束是通胀，而非\"没有钱\"。翟东升：赤字/债务问题高度**情境依赖**——对拥有货币主权的美国而言，债务是\"另一国的资产\"（翟东升：中国的外储就是美国的负债，美国可以印钞稀释）；对没有货币主权、只能借外币的发展中国家，债务则是\"死亡陷阱\"。", "explanation": "三学派：凯恩斯主义（债务有益）vs财政保守主义（债务有害）vs MMT（货币主权国无约束）。翟东升：高度情境依赖——货币主权国债务vs无主权国外债的本质不同。", "memorization": "三看法：有益（凯恩斯）·有害（保守）·货币主权无约束（MMT）。翟东升：情境依赖，货币主权国和外围国债务性质截然不同。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-short-03-3", "category": "简答题", "question": "简述美国金融危机对欧债危机的传导路径。", "answer": "【五步传导链】①**次贷有毒资产传染**：2007-2008年美国次贷危机爆发→欧洲银行持有大量MBS/CDO等美国\"有毒资产\"→遭受巨额损失→欧洲银行资本充足率下降→信用收缩；②**金融市场恐慌传导**：雷曼破产后全球流动性危机→欧洲金融市场也出现美元荒→欧洲央行需向银行紧急注资；③**经济衰退导致财政恶化**：金融危机引发欧洲经济深度衰退→税收大幅下降→政府为救助银行大规模支出→财政赤字和公共债务急剧攀升；④**银行救助使主权信用受损**：爱尔兰、西班牙将私人银行债务\"国有化\"（担保）→政府资产负债表承压→债券市场开始质疑主权信用；⑤**希腊引爆**：2009年底希腊新政府揭露财政数据造假，赤字实际高达GDP的12.7%→市场恐慌蔓延→国债收益率飙升→南欧多国陷入债务危机。翟东升：欧债危机是**美元霸权危机\"传染\"给欧元区\"先天缺陷\"**的结果——引爆点是美国金融危机，但火药桶是欧元区\"货币统一财政分散\"的制度性缺陷。", "explanation": "五步传导：有毒资产传染→金融恐慌→经济衰退→财政恶化→主权信用受损→希腊引爆。翟东升：美国危机点燃欧元区制度缺陷这个火药桶。", "memorization": "五步：有毒资产→恐慌→衰退→财政恶化→希腊引爆。翟东升：美国点火，欧元区制度缺陷是火药桶。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-short-03-4", "category": "简答题", "question": "简要罗列1970年代以来历次系统性国际金融危机。", "answer": "【主要危机时间轴】①1973-74年：石油危机（OPEC石油禁运→能源价格冲击→西方滞涨）；②1982年：拉美债务危机（沃尔克加息→墨西哥率先违约→拉美\"失去的十年\"）；③1987年：黑色星期一（美国股市单日暴跌22.6%，量化交易与程序化交易放大跌幅）；④1992-93年：欧洲汇率机制危机（索罗斯狙击英镑，英国被迫退出ERM）；⑤1994-95年：墨西哥比索危机（\"龙舌兰酒效应\"）；⑥1997-98年：亚洲金融危机（泰铢贬值引爆，涉及泰国、印尼、韩国、马来西亚）；⑦1998年：俄罗斯债务危机+LTCM（长期资本管理公司）破产；⑧2001年：阿根廷债务违约（有史以来最大规模主权违约）；⑨2007-09年：美国次贷危机→全球金融海啸（雷曼兄弟破产）；⑩2010-15年：欧洲主权债务危机（希腊等南欧国家）。翟东升规律：每一次危机都与**美元利率周期（美元潮汐）高度相关**——美国降息放水→泡沫形成→加息收水→外围危机爆发，是周期性的权力转移机制。", "explanation": "1973石油危机→1982拉美→1987黑色星期一→1992欧洲ERM→1994墨西哥→1997亚洲→1998俄罗斯→2001阿根廷→2008次贷→2010欧债。翟东升：每次危机与美元潮汐高度相关。", "memorization": "10次危机时间轴：73油→82拉美→87黑五→92英镑→94墨西哥→97亚洲→98俄/LTCM→01阿根廷→08次贷→10欧债。翟东升：美元潮汐是周期主线。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-essay-03-1", "category": "论述题", "question": "论述特朗普减税政策的背后政治诱因和经济考量，及对中国经济发展可能的影响。", "answer": "【政治诱因→经济考量→对中国影响】政治诱因（三点）：①**选民基础回报**：企业减税（企业税率35%→21%）回报华尔街和大企业（共和党核心金主），个人所得税减免讨好中产选民；②**意识形态立场**：\"大政府→小政府\"是里根主义的传承，减税是共和党的标志性政策承诺；③**再工业化叙事**：通过提高企业盈利、吸引海外资本回流，支持\"让美国再次伟大\"的制造业回归叙事。经济考量（两套）：①**短期刺激**：减税立刻扩大企业和个人可支配收入→消费和投资增加→GDP增速提升（事实上2018年美国GDP增速达2.9%）；②**长期争议**：\"供给侧\"逻辑（里根主义2.0）认为减税促创新和投资；批评者（翟东升赞同）认为只是加剧贫富分化和财政赤字。对中国影响（三条）：①**美国企业所得税大幅降低**，缩小了与中国（25%）的差距，可能降低外资在华意愿，加速\"制造业回流美国\"；②**美元升值压力**：减税叠加美联储加息→资本回流美国→美元走强→人民币贬值压力→热钱部分外流→中国金融市场承压；③**全球税收竞争加剧**：\"竞次效应\"——各国被迫跟随降低企业税率以留住资本。翟东升：特朗普减税是**新自由主义的最后一搏**，短期刺激了美国经济，但长期来看财政赤字恶化（2018年美国财政赤字占GDP超4%），实质上是用债务透支未来。这些债务最终要么通过通胀稀释（损害储蓄者），要么通过违约（损害债权国），说明**美国的财政可持续性本身也是美元霸权的战略赌注**。", "explanation": "", "memorization": "政治：金主回报+意识形态+再工业化叙事。经济：短期刺激+长期争议（供给侧vs贫富分化）。对中：外资意愿降+美元升→人民币压+税收竞争。翟东升：新自由主义最后一搏，债务透支未来。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-essay-03-2", "category": "论述题", "question": "从政治经济学角度论述中国为什么仅用了20多年时间完成了全球最大规模的工业化？", "answer": "【五大政治经济学因素】①**强大的国家能力（国家自主性）**：中国共产党领导的国家具有强大的动员能力和政策执行力——能够推行长期发展战略（五年计划）而不受短期选举政治干扰；能够低价征地、建设基础设施、优先配置金融资源于工业化目标。②**战略性利用全球化机遇**（三外路线的精准执行）：鼓励出口→获取外汇和外部需求；吸引FDI→引进技术和管理；控制外汇→稳定汇率和防范金融风险。这是翟东升所称**\"国家能力驾驭市场力量\"**的典型示范。③**规模经济与市场优势**：14亿人口的统一大市场提供了巨大的国内消费潜力和规模经济效应→外资进入的巨大诱因→技术溢出和本土企业成长的肥沃土壤。④**人口红利的历史窗口**（翟东升人口春秋比理论）：1980-2012年中国劳动年龄人口快速增长（人口红利）→劳动力充裕且廉价→储蓄率高→投资率高→工业积累速度快；这一窗口已经过去（2012年劳动年龄人口到顶），是工业化完成的历史时机判断。⑤**后发优势与技术引进**：在已有成熟工业技术的情况下，引进-消化-吸收-再创新比独立研发成本低得多（李斯特\"幼稚产业\"逻辑）；日德韩都经历了这一路径，但中国规模更大、速度更快。翟东升核心判断：中国工业化成功的本质是**国家能力+人口红利+全球化机遇三者的历史性相遇**；三者缺一，奇迹不会发生。未来面临人口红利消失的挑战，需要通过技术升级和产业政策继续推进高质量发展。", "explanation": "", "memorization": "五因素：国家能力+三外路线+规模经济+人口红利+后发优势。翟东升：国家能力×人口红利×全球化机遇，三者历史性相遇。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-essay-03-3", "category": "论述题", "question": "外资企业在中国发展过程中发挥的作用和问题有哪些？论述你对外资问题的本质及未来外资政策的方向的看法。", "answer": "【五大作用→三大问题→本质判断→未来方向】五大作用：①资本形成与就业创造（填补国内资本缺口，吸收农业剩余劳动力）；②技术与管理知识溢出（示范效应、竞争效应、人员流动效应、产业关联效应四条路径）；③推动产业升级与外贸扩张（出口导向型制造业发展）；④倒逼制度变迁（完善知识产权保护、行政管理改革）；⑤催生新型社会阶层（白领中产阶级形成）。三大问题：①**\"低端锁定\"风险**：部分外资有意将核心技术保留在母国，只将劳动密集型组装环节放在中国（\"以技术换市场\"的反面），使中国长期停留在价值链低端；②**竞争排挤本土企业**：外资享受超国民待遇（税收优惠等），在部分领域挤压本土企业的成长空间；③**潜在的数据安全和产业安全风险**：外资在关键领域的深度参与可能带来数据主权和产业安全隐患（在2018年中美博弈后愈发凸显）。外资问题的本质：翟东升认为外资问题本质上是**国家战略能力的考题**——外资是中性工具，关键在于国家是否有能力驾驭外资服务于本国发展目标，而非被外资反向控制。中国的成功正在于此。未来外资政策方向：①从\"招商引资\"转向\"选商择资\"（优先高技术含量、高研发投入的外资）；②\"以市场换股权\"替代\"以市场换技术\"（翟东升提出）：在中国市场准入换取对国际一流企业的股权参与，实现\"外资内资化\"；③安全审查常态化：在关键基础设施、数据、敏感技术领域建立完善的国家安全审查制度；④鼓励外资深度参与中国创新体系（设立研发中心、与高校合作），推动技术溢出从\"被动\"到\"主动\"。", "explanation": "", "memorization": "五作：资本+技术溢出+产业升级+制度改革+社会阶层。三问题：低端锁定+排挤本土+安全风险。翟东升：外资是中性工具，国家能力是关键；市场换股权替代市场换技术。", "source": "翟东升-货币金融-模拟03"},

    {"id": "ipe-term-04-67", "category": "名词解释", "question": "公开市场操作（Open Market Operations）", "answer": "央行通过在公开市场（二级市场）买卖国债（或其他高质量证券）来调节银行体系流动性、影响短期利率的货币政策工具。买入国债→基础货币投放（宽松）；卖出国债→基础货币回笼（紧缩）。三大优势：主动性强、灵活精确、可逆性好。是美联储最主要的货币政策操作工具；中国因国债市场深度不足，使用空间相对有限（更多依赖存准率和创新工具）。翟东升：公开市场操作在美国的本质是**\"美联储为美国国债创造买家\"**——大规模购债（QE）使美联储资产负债表扩张，美国政府得以低成本融资；这等于全球（持有美债的国家）为美国的财政赤字承担隐性成本。", "explanation": "央行买卖国债调节流动性和利率。买入=宽松，卖出=紧缩。三大优势：主动+灵活+可逆。翟东升：QE本质是为美国国债创造买家，全球为美财赤承担隐性成本。", "memorization": "公开市场操作=央行买卖国债。买国债→放水；卖国债→收水。翟东升：QE是美国财政赤字的全球化融资机器。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-term-04-68", "category": "名词解释", "question": "法定存款准备金率", "answer": "央行规定商业银行必须将存款的一定比例存入央行（不可用于放贷），这一比例即法定存款准备金率。提高存准率→银行可贷资金减少→货币供给收缩（紧缩）；降低存准率→银行可贷资金增加→货币供给扩张（宽松）。中国历史上存准率远高于美欧（曾达21.5%，当前约6-9%），体现了货币调控的结构性差异。翟东升：中国习惯用存准率而非利率调控的深层原因是**\"利率市场化尚未完成+汇率维稳需要\"**——在利率传导机制不畅的条件下，存准率是更直接的行政性数量调控工具；同时，高存准率实质上是央行向商业银行收取的\"隐性税\"，银行将客户存款强制存于央行（获得低于市场的存准利率），这部分利差损失最终转嫁给储蓄者。", "explanation": "商业银行必须存入央行的存款比例，调控银行可贷资金量。提高=紧缩，降低=宽松。翟东升：中国高存准率是行政调控手段+向储蓄者收取的隐性税。", "memorization": "存准率高→银行可贷资金少→货币收缩。翟东升：高存准率是行政调控+隐性税（储蓄者损失利息）。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-term-04-69", "category": "名词解释", "question": "友岸外包（Friend-shoring）", "answer": "美国拜登政府提出的供应链重组策略：将生产和采购集中于政治上\"可信任的盟友\"（友好国家），避免对\"潜在对手\"（主要指中国）的过度依赖。与\"近岸外包\"（Nearshoring，向地理近邻国家转移）形成\"双轮策略\"。友岸外包的政治逻辑优先于经济逻辑——即便生产成本更高，也要维护供应链安全。翟东升：友岸外包本质上是**将贸易政治化**的另一面——美国以\"经济安全\"为名划定\"朋友圈\"，将全球供应链人为分割。但翟东升指出这一策略面临**内在矛盾**：①\"友岸\"（越南、印度、墨西哥）仍大量依赖中国中间品；②生产成本大幅上升，损害美国消费者利益；③\"友岸\"国家未必甘愿选边站。", "explanation": "向政治可信任盟友国家转移生产采购，以经济效率换供应链安全。翟东升：贸易政治化，但内含矛盾——友岸国仍依赖中国，成本高昂。", "memorization": "友岸=向政治友好国家外包（别找中国）。翟东升：政治优先于经济，但中国供应链依赖难以切断。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-term-04-70", "category": "名词解释", "question": "微笑曲线", "answer": "台湾宏碁集团创始人施振荣1992年提出的产业价值链模型：将产品价值链分为左端（研发、专利、品牌）、中间（制造、组装）、右端（营销、售后服务），三者形成U型曲线——两端附加值高，中间制造环节附加值低。加工贸易时代的中国长期处于\"微笑曲线\"的底部（低附加值组装），享有的只是微薄的\"代工费\"。翟东升：微笑曲线揭示了中国出口导向时代的**结构性困境**——表面上出口规模巨大，实际上大部分附加值被掌握两端的跨国公司攫取；\"中国制造\"只是一个\"组装\"标签，真正的利润在苹果公司（品牌+设计）而非富士康（代工）。突破微笑曲线底部是中国产业升级的核心命题。", "explanation": "U型价值曲线：两端（研发+品牌）附加值高，中间（制造）附加值低。中国长期在底部。翟东升：揭示中国代工时代的结构困境，产业升级=向两端延伸。", "memorization": "微笑曲线：研发-制造-营销，中间（制造）最低。翟东升：苹果赚大钱，富士康赚辛苦钱。产业升级=冲两端。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-term-04-71", "category": "名词解释", "question": "货币互换（Currency Swap）", "answer": "两国（或央行）之间协议，在一定时期内相互提供本币融资便利，期末按原汇率换回，以满足对方货币的流动性需求。央行货币互换（Bilateral Swap Agreements）是国际金融安全网的重要组成部分：危机时盟国央行通过互换提供应急美元流动性（如2008年美联储与14个央行互换）。中国自2008年后与数十个国家签署人民币货币互换协议，为人民币国际化提供流动性支撑。翟东升：货币互换是**国际货币体系\"特许权\"的体现**——谁签得到货币互换、谁的互换规模更大，谁就在危机时有更多流动性保障。美联储的互换网络只对战略盟友开放，中国的互换网络则向发展中国家倾斜，是人民币国际化和构建替代性金融网络的重要工具。", "explanation": "两国央行相互提供本币融资便利，危机时提供流动性支持。翟东升：货币互换是国际货币特许权的体现，中国以此推进人民币国际化。", "memorization": "货币互换=两国相互借本币，危机时提供流动性支持。翟东升：美联储互换网络=战略盟友俱乐部，中国用互换构建替代网络。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-term-04-72", "category": "名词解释", "question": "特别提款权货币篮子（SDR Basket）", "answer": "IMF特别提款权（SDR）的价值由一篮子主要货币加权平均决定，当前五种货币及权重（2022年起）：美元41.73%、欧元29.81%、人民币12.28%、日元7.59%、英镑8.09%。人民币于2016年10月正式加入SDR篮子（权重10.92%，2022年调整至12.28%），是中国货币国际化的重要里程碑。翟东升：SDR货币篮子是国际货币权力格局的**制度性照妖镜**——哪种货币能进入篮子、权重多少，直接反映各国经济和政治地位；人民币加入是对中国作为贸易大国地位的认可，但SDR本身规模有限（杯水车薪），象征意义大于实际效用。真正的货币权力来自私人市场的使用选择，而非IMF的行政决定。", "explanation": "SDR价值由五种货币加权：美元41.73%+欧元29.81%+人民币12.28%+英镑8.09%+日元7.59%。2016年人民币加入。翟东升：货币权力格局的照妖镜，象征意义大于实际效用。", "memorization": "SDR篮子：美元（最大）+欧元+人民币（2016年加入）+英镑+日元。翟东升：是照妖镜，真正权力来自私人市场选择。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-short-04-1", "category": "简答题", "question": "简述央行吸纳和对冲流动性的主要手段。", "answer": "【五大工具】①**法定存款准备金（存准率）**：提高存准率→强制锁定商业银行资金于央行→持久性强，但\"一刀切\"冲击大；②**央行票据（央票）**：央行向商业银行发行短期债券→主动回笼流动性→有利息成本，适合中期冲销；③**公开市场操作（正回购）**：央行暂时卖出证券→短期回笼流动性→最灵活、最可逆；④**财政存款调节**：政府税款缴入国库（存于央行）→自动收紧流动性；税款拨付支出→自动投放。其季节性波动是重要的流动性扰动因素；⑤**国债买卖**（最市场化手段，中国正在扩大使用）。翟东升补充视角：这些工具在中国的实际运用主要受制于**\"被动冲销外汇占款\"的大背景**——各种工具都是针对外汇占款带来的过剩流动性的补救，根本之策是推进汇率市场化，让央行从被动冲销模式中解脱。", "explanation": "五大工具：存准率（持久）+央票（中期）+公开市场操作（灵活）+财政存款（季节性）+国债买卖（市场化）。翟东升：工具都是被动冲销的补救，根本是汇率市场化。", "memorization": "五工具：存准+央票+正回购+财政存款+国债买卖。翟东升：都是补救，根本是汇率市场化。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-short-04-2", "category": "简答题", "question": "存款准备金带来的利息节省由谁买单？为什么？", "answer": "存款准备金利息节省（即存准利率低于市场利率的差额）主要由**储蓄者和商业银行客户**买单。机制：商业银行将一定比例存款强制存入央行，获得的存准利率（央行支付）远低于市场利率→银行的资金成本被人为压低→但银行并不因此少收储户利息→此成本不传递给储户但银行受益（净利差扩大）；从另一角度看，若银行将这部分资金放贷，将赚取更高收益——被迫存于央行的成本即机会成本，最终转嫁为更高的贷款利率或更低的存款利率。翟东升：存款准备金利息节省的真正受益者是**央行（降低冲销成本）和国有银行（享有制度性利差保护）**，买单的是储户（负实际利率）和依赖贷款的实体企业（贷款利率高）。这是出口导向型增长模式内嵌的财富转移机制的一部分。", "explanation": "存准利率<市场利率→银行被迫接受低收益存准→成本转嫁给储蓄者（低存款利率）和借款企业（高贷款利率）。翟东升：受益是央行和国有银行，买单是储户和实体企业。", "memorization": "存准利率低于市场→银行机会成本→转嫁给储户（存款利率低）和企业（贷款利率高）。翟东升：储户和实体企业买单，央行和国有银行受益。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-short-04-3", "category": "简答题", "question": "财政存款的利息节省由谁买单？为什么？", "answer": "财政存款（政府税收存入央行账户）的利息节省（财政存款利率几乎为零）主要由**纳税人和全体国民**买单。机制：政府征收的税款本应用于公共支出（教育、医疗、基建）→但税款存于央行（接近零利率）→等于政府向央行提供了免费或廉价资金→央行用这笔钱对冲外汇占款，节省了发行高利率央票的成本→受益方是央行（降低对冲成本）；而纳税人：①本应享受的公共服务因财政资金滞存央行而供给减少；②税款的\"二次使用\"（补贴央行对冲操作）不是纳税人的本意。翟东升：这是**双重剥夺机制**——纳税人缴税一次，然后税款又被用来帮央行维持出口导向型增长模式的流动性管理，相当于**纳税人为\"出口集团+美元体系\"的利益安排间接付费**。", "explanation": "财政存款=接近零利率存央行→央行节省发央票的成本→纳税人付出：①减少公共服务②税款\"二次使用\"帮央行对冲。翟东升：双重剥夺，纳税人为出口集团和美元体系间接付费。", "memorization": "财政存款≈0利率存央行→央行节省冲销成本→纳税人买单（少了公共服务+税款被转用）。翟东升：双重剥夺。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-short-04-4", "category": "简答题", "question": "简述我国货币创造机制在1996年前后两个阶段的区别。", "answer": "【两阶段对比】1996年以前（信贷计划主导阶段）：基础货币投放主要通过**央行对国有银行的再贷款和再贴现**，即央行按国家计划向国有银行提供资金→国有银行按计划发放贷款→货币供给由行政指令驱动，不反映市场供需；\"贷款创造存款\"机制不成熟，货币主要靠央行直接投放。1996年之后（市场化货币创造阶段）：①货币创造从\"贷款计划\"转向**商业银行的市场化信贷决策**；②基础货币主要来源从再贷款转向**外汇占款**（1994年汇改+1996年后外贸顺差扩大）；③货币乘数机制开始真正发挥作用（存款准备金率调整成为重要政策工具）；④利率开始部分市场化（同业市场CHIBOR于1996年推出）。翟东升：1996年是中国货币体制的重要分水岭——从\"计划信贷\"走向\"市场货币\"，但\"市场化\"并非完全，仍存在大量行政干预（利率管制、信贷窗口指导），是\"有中国特色的货币创造机制\"。", "explanation": "1996年前：央行再贷款主导，计划信贷驱动货币供给。1996年后：外汇占款为主，商业银行市场化信贷，货币乘数机制发挥作用。翟东升：分水岭，从计划信贷→市场货币，但仍有行政干预。", "memorization": "1996年前：央行→国有银行再贷款（计划）。1996年后：外汇占款+商业银行市场化信贷+货币乘数。翟东升：分水岭，走向市场但不彻底。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-short-04-5", "category": "简答题", "question": "简述货币政策背后的政治考量。", "answer": "【四大政治考量维度】①**通胀与就业的政治权衡**：低通胀有利于债权人和金融资产持有者（通常是富裕阶层），低失业率有利于工薪阶层；货币政策的\"双目标\"（美联储）或\"稳健货币\"（中国）实质上是不同利益集团博弈的结果；②**汇率政治**：低汇率有利于出口集团（制造业、外向型企业），高汇率有利于消费者和对外投资；货币政策对汇率的影响是国内不同利益群体博弈的重要战场；③**中央政府与央行的关系**：\"央行独立性\"是政治安排而非自然状态——美联储名义独立但受国会监督；中国人民银行在党的领导下运作，服务于党的经济发展目标；④**大国间货币博弈**：美联储的利率决策影响全球资本流动，对新兴市场的溢出效应使其成为事实上的\"全球央行\"，引发外围国家的政治抗议（\"以邻为壑\"批评）。翟东升：货币政策的政治本质是**\"谁制定货币政策，谁的利益被优先照顾\"**——这是货币政治经济学的核心命题；中国货币政策长期服务于出口集团和增长目标，2012年后开始转向服务于\"共同富裕\"和居民消费者。", "explanation": "四维度：通胀vs就业（阶级分配）+汇率政治（出口vs消费者）+央行独立性（政治安排）+大国货币博弈（美联储=全球央行）。翟东升：货币政策=利益分配，谁制定谁受益。", "memorization": "四政治：通胀就业之争+汇率利益分配+央行独立性是政治安排+大国货币博弈。翟东升：货币政策是利益分配的工具。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-essay-04-1", "category": "论述题", "question": "人民币汇率是否被操纵？其是否是中美贸易巨幅顺差的根本原因？请从政治经济学角度解释其背后原因及代价。", "answer": "【操纵判断→顺差原因分析→代价】一、操纵判断（\"是，但不完全是\"）：①狭义技术定义看：中国曾长期通过强制结售汇、外汇市场干预（购买美元）维持人民币低于均衡水平，符合\"汇率操纵\"的行为特征；②但\"操纵\"有强烈价值判断意味——美国自己也干预汇率（美联储QE导致美元走弱），且美国财政部的\"汇率操纵\"认定带有明显政治意图；③翟东升判断：人民币汇率被\"管理\"是事实，但将其定性为\"操纵\"是政治话语，不是中性的经济分析。二、顺差原因分析（\"汇率不是根本原因\"）：①**结构性原因**：美国的贸易逆差根源是美国自身的储蓄不足+过度消费，不是中国的汇率政策（贸易恒等式：贸易差额=储蓄差额）；②**美元霸权内生逆差**：美国必须维持贸易逆差才能向世界输出美元（特里芬难题逻辑），这是美元霸权的结构性需求；③**产业比较优势**：即便人民币升值50%，中国在劳动密集型制造业的比较优势仍然存在；④**验证**：2005-2014年人民币升值约35%，美国对华贸易逆差并未缩小（反而扩大）。三、背后的政治经济学：汇率低估是**国内政治联盟**（出口企业+地方政府+国有银行）与**国际货币权力**（维持汇率稳定换取中美贸易关系稳定）共同塑造的结果。代价：储蓄者负实际利率+劳动者实际工资被压低+向美元体系缴纳\"货币地租\"（巨额外储）。翟东升：中美贸易顺差是美国储蓄不足、美元霸权结构性逆差需求与中国出口导向模式三者**共谋**的结果，\"汇率操纵\"叙事是美国用来转移国内矛盾的政治话语。", "explanation": "", "memorization": "操纵：管理是事实，政治判断是话术。顺差根源：美国储蓄不足+美元需要逆差+比较优势（汇率不是主因）。代价：储蓄者+劳动者+货币地租。翟东升：三方共谋，美国转移矛盾的政治话语。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-essay-04-2", "category": "论述题", "question": "论述世界市场体系中中央与外围各类国家的分类标准及特征，中国在体系中所处的地位和趋势。", "answer": "【分类标准→中心国特征→外围国特征→半外围→中国定位→趋势】分类标准（四维度）：①产业结构（高端制造+服务业=中心；初级产品+低端制造=外围）；②技术地位（技术创新者=中心；技术引进者=外围）；③货币地位（发行国际货币=中心；持有他国外储=外围）；④全球价值链位置（微笑曲线两端=中心；中间组装=外围）。中心国特征：掌握核心技术和专利→服务业主导→货币作为全球储备→制定游戏规则→可向外输出危机成本。外围国特征：初级产品出口为主→贸易条件长期恶化→货币不可国际化（\"原罪\"）→被迫接受他国制定的规则→危机时被全额承担调整成本。半外围地位（中国属于此类）：同时具有某些中心国特征（制造业产值全球第一、部分技术领先）和外围国特征（核心芯片技术受制于人、人民币国际化不完全）。中国定位：翟东升判断中国已从外围跃升至\"半中心\"，具有\"多层次特征\"——在劳动密集型产业中处于中心地位（向越南等国输出产业），在芯片等高端技术领域仍处外围；正处于从半中心向核心跃升的关键阶段。趋势与路径：①产业升级：从组装→制造→创新，冲击微笑曲线两端；②货币升级：人民币国际化，减少\"原罪\"；③规则参与：在WTO、IMF、AIIB、RCEP等国际平台争取更大话语权；④产业链编辑能力（CICE）：主动重塑全球产业分工格局，成为新的规则制定者。翟东升：中国处于历史性跃升的关键节点，成功的关键是**守住制造业基本盘+人民币国际化+提升规则制定能力**，三者缺一不可。", "explanation": "", "memorization": "四维分类：产业+技术+货币+价值链位置。中国=半中心（正在跃升）。三条路：产业升级+货币国际化+规则参与。翟东升：守制造业基本盘是核心。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-essay-04-3", "category": "论述题", "question": "简述现行国际货币体系的主要内容及特点，论述你对布雷顿森林体系-牙买加体系转化的原因，及对人民币国际化的启示。", "answer": "【现行体系特点→转化原因→人民币启示】现行牙买加体系（1976年至今）主要内容及特点：①法律上承认浮动汇率合法性，各国自主选择汇率制度（但实践中多数新兴市场采用管理浮动）；②黄金非货币化（官方不再以黄金定价），但黄金仍是重要储备资产；③美元实际上仍是主导储备货币（占全球外储约60%）；④SDR被定义为补充性国际储备资产，但实际使用有限；⑤IMF转型为国际收支监督和危机救助机构。布雷顿森林→牙买加转化的深层原因：①**特里芬困境的内在矛盾不可调和**：美元-黄金双挂钩既要提供全球流动性（美国保持逆差输出美元）又要维持信心（黄金储备必须足够），两者不可兼得；②**越战财政压力与大社会计划**：1960年代后美国财政赤字持续扩大→美元大量外流→海外美元持有量远超美国黄金储备→信心危机；③**美国战略选择**：尼克松1971年关闭黄金窗口是主动战略选择——脱离黄金束缚后，美国获得了不受约束的铸币权（翟东升：这是\"升级\"而非\"失败\"）；④**欧洲经济崛起**：联邦德国、法国积累大量美元，开始要求兑换黄金，加速了体系压力。对人民币国际化的启示（五条）：①**不必复制美元模式**（不需要成为其他国家的\"逆差输出国\"）；②**从贸易计价结算入手**（人民币跨境使用的自然起点）；③**建设人民币资产池**（让境外持有者有资产可配置：国债、熊猫债等）；④**审慎开放资本账户**（不走拉美金融自由化的弯路）；⑤**以制造业信用为锚**（不依靠军事霸权或金融霸权，而是以中国作为\"全球制造业工厂\"的真实信用为人民币背书）。翟东升：人民币国际化不是要复制美元的\"金融帝国\"模式，而是构建一种**以制造业产能和贸易网络为信用基础的\"民本主义\"国际货币新路径**。", "explanation": "", "memorization": "牙买加体系：浮动汇率+黄金非货币化+美元实际主导+SDR边缘化。转化原因：特里芬+越战财政+美国主动选择+欧洲崛起。人民币五启示：不复制美元+贸易入手+建资产池+慎开资本+制造业信用为锚。翟东升：民本主义新路径。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-term-06-73", "category": "名词解释", "question": "浮动汇率制度", "answer": "一国货币汇率由外汇市场供求关系自由决定，政府和中央银行不设定固定平价、不作系统性干预的汇率安排。纯粹浮动汇率（自由浮动）极少见，多数国家实行\"管理浮动\"（政府适度干预）。浮动汇率使货币政策获得独立性。背后的逻辑是蒙代尔三元悖论：资本自由流动、汇率稳定、货币政策独立三者只能取其二。为什么不可兼得？因为在资本自由进出时，本国利率一旦偏离锚货币，套利资金就会大举流入或流出；要守住固定汇率，央行就只能让利率盯住锚货币、被动放弃独立调息——这就是第三者必然落空的机制。浮动汇率正是主动放弃汇率稳定、换取货币政策独立的那一极。主要优点：自动调节国际收支、货币政策独立、减少官方外汇储备需求。主要缺点：汇率波动带来不确定性、助长投机、对通胀预期冲击大。1973年布雷顿森林体系崩溃后，主要货币转向浮动汇率。", "explanation": "", "memorization": "汇率由市场供求决定，政府不设固定平价。三元悖论：浮动换货币政策独立。优：自动调节+独立。缺：波动+投机。1973年后主流。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-term-06-74", "category": "名词解释", "question": "固定汇率制度", "answer": "一国货币当局将本币汇率固定在某一水平（或窄幅区间），并承诺通过干预外汇市场（买卖外汇）来维持该平价的汇率安排。分为三类：①硬性盯住（货币局、美元化）——汇率永久固定，货币供应完全由外汇储备决定；②可调整钉住（布雷顿森林体系的经典形式）——平时固定，需要时调整平价；③爬行钉住——汇率以预先公布的小幅度周期性贬值/升值。优点：降低汇率不确定性、有利于贸易投资、有助于输入通胀稳定性。缺点：放弃货币政策独立性、易遭投机性冲击（如1992年英镑危机）、需要大量外汇储备。这里的逻辑正是三元悖论的另一面：在资本自由流动下要把汇率钉死，本国利率就必须跟住锚货币，否则利差会引来套利资本冲垮平价；央行因此丧失了独立调息的空间，等于用货币政策独立换取了汇率稳定。1992年英镑危机就是被迫加息守汇率、最终守不住的典型。翟东升视角：中国长期实行管理浮动（接近固定）是出于政策稳定性和出口竞争力的权衡。", "explanation": "", "memorization": "固定平价，央行靠买卖外汇维持。硬性/可调整/爬行三类。优：降不确定性+稳定通胀。缺：放弃货币政策+易受冲击+需大量外储。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-term-06-75", "category": "名词解释", "question": "资产泡沫", "answer": "资产价格（股票、房产、大宗商品等）持续显著偏离其基本面价值（内在价值）的状态，通常由信贷扩张、市场预期自我实现和流动性过剩共同推动。泡沫形成三阶段：①流动性宽松→资产价格上涨→财富效应→更多信贷投入；②价格脱离基本面但情绪持续驱动（\"非理性繁荣\"）；③触发因素（利率上升、信心逆转）→泡沫破裂→资产价格急跌→债务通缩螺旋。翟东升框架：美联储的宽松货币政策（低利率+QE）是全球资产泡沫的主要驱动因素；\"美元潮汐\"收放导致全球资产价格周期性波动，资本输出时制造泡沫、回流时刺破泡沫。典型案例：1990年日本、2000年美国科技股、2007年美国房市、2015年A股。", "explanation": "", "memorization": "价格显著偏离基本面。三阶段：流动性→脱离基本面→破裂。翟东升：美元潮汐→全球资产泡沫周期。典型：日本90年+美国科技股00+美国房市07。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-term-06-76", "category": "名词解释", "question": "进口替代战略（ISI）", "answer": "Import Substitution Industrialization，发展中国家以政府政策（关税保护、补贴、外汇管制）扶持本国工业替代进口商品的工业化战略，流行于1950-1970年代拉丁美洲（阿根廷、巴西、墨西哥）和部分亚非国家。核心逻辑：①保护幼稚产业；②减少对外依赖、节约外汇；③推动工业化和就业。主要问题：①保护产业效率低下，难以形成出口竞争力；②外汇短缺（进口设备+能源仍需大量外汇，国内商品又打不进国际市场）；③财政赤字（补贴+国有企业亏损）→通货膨胀→债务危机（拉美1982年危机的结构性根源之一）。与东亚出口导向（EOI）战略形成鲜明对比：东亚选择融入全球分工，拉美选择内向保护，结果截然不同。翟东升：ISI失败的核心是**脱离全球市场就脱离了技术进步和规模效益的压力**。", "explanation": "", "memorization": "ISI=进口替代工业化。手段：关税+补贴+外汇管制。问题：低效+外汇短缺+财政赤字→债务危机。对比：东亚出口导向vs拉美进口替代。翟东升：脱离全球市场=脱离技术进步压力。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-term-06-77", "category": "名词解释", "question": "康德拉季耶夫周期", "answer": "又称\"长波周期\"（Long Wave），由苏联经济学家尼古拉·康德拉季耶夫（1892-1938）于1920年代提出。指资本主义经济存在约45-60年的长期波动周期，每个周期分为上升期（繁荣+衰退）和下降期（萧条+复苏）四个阶段。驱动机制：基础性技术革命（蒸汽机→铁路→电气化→石油化工→信息技术）引发新一轮长期投资热潮→产能过剩→长期萎缩→新技术革命开启下一轮。翟东升的应用：①将当前AI/绿色能源革命理解为第六次康波起点；②中国经济的长期韧性与其在新康波技术中的布局（新能源汽车、光伏、AI芯片）密切相关；③美元潮汐与康波周期有交叉——两个周期叠加时（如1970年代）往往出现最大的历史性动荡。", "explanation": "", "memorization": "45-60年长波周期，康德拉季耶夫提出。驱动：基础技术革命。四阶段：繁荣→衰退→萧条→复苏。翟东升：AI/绿能=第六波起点；与美元潮汐叠加→历史性动荡。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-short-06-1", "category": "简答题", "question": "中国人民银行在紧缩货币政策时为什么更多利用存准而不是利率工具？", "answer": "【四重原因：制度性+结构性+政治性+操作性】①**利率市场化不完全**（制度原因）：在利率尚未完全市场化阶段，存贷款基准利率调整效果有限——企业融资渠道多元（债券、影子银行、内部资金），利率工具传导链条不顺畅，而存准率直接控制银行可用资金总量，效果更确定；②**冲销外汇占款的需要**（结构原因）：大量外汇流入→央行被动投放人民币（外汇占款）→基础货币被动扩张→必须通过提高存准率冻结过剩流动性，这是中国特有的\"对冲型\"货币操作；③**政治敏感性较低**（政治原因）：调整存准率不直接影响储蓄者和贷款者的名义利率，社会舆论关注度低；而利率调整尤其是加息会立刻影响居民房贷成本，政治敏感；④**操作灵活性**：存准率可以分步小幅调整（每次0.5个百分点），对市场冲击可控。翟东升补充：随着人民币利率市场化推进（LPR改革2019年），央行正逐步转向以利率为主的调控框架，存准依赖性在下降。", "explanation": "", "memorization": "四原因：①利率市场化不完全→传导差；②冲销外汇占款（中国特有）；③政治敏感低（不影响房贷）；④操作灵活。翟东升：LPR改革后正转向利率主导。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-short-06-2", "category": "简答题", "question": "简要介绍和评价美国联邦政府的债务上限问题。", "answer": "【制度介绍→历史演变→政治博弈→评价】制度介绍：美国国会设定联邦政府债务总额上限（Debt Ceiling），财政部举债超过此上限须经国会授权提高。历史演变：债务上限自1917年设立以来已被提高约100次，实际上已成\"橡皮图章\"——每次接近上限，两党谈判、最终提高（或暂停适用）。政治博弈逻辑：①少数党（通常是在野党）将债务上限作为谈判筹码，要求对方作出财政削减或政策让步；②执政党通常在\"技术性违约前夕\"妥协，避免美国政府真正违约（这将引发全球美元资产信心危机）；③2011年危机：共和党利用债务上限逼迫奥巴马削减开支，最终导致标普下调美国主权信用评级（AAA→AA+）。评价：①短期：债务上限谈判制造金融市场波动，增加不确定性；②中长期：翟东升判断，美国联邦债务长期不可持续（2024年利息支出已超国防开支），债务上限博弈是\"掩盖财政危机的政治仪式\"，无法解决根本问题；③对中国意义：美国债务危机加剧动摇了美债作为\"无风险资产\"的地位，为人民币国际化提供窗口期。", "explanation": "", "memorization": "制度：国会设上限，超过须授权。历史：已提高约100次，形同虚设。政治：少数党当谈判筹码→最终妥协。评价：翟东升：掩盖财政危机的政治仪式，美债长期不可持续，为人民币创造窗口。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-short-06-3", "category": "简答题", "question": "简述金本位制度的国际政治本质。", "answer": "【三维度：霸权稳定+阶级政治+帝国扩张】①**霸权稳定论视角**：金本位（尤其是古典金本位1870-1914）实质上是以英国为核心的国际货币秩序——英镑是全球结算货币，英格兰银行是最终贷款人，英国通过金本位将自身货币政策传导给全球（各国必须随英国利率调整以维持金平价）。金本位不是\"中立的技术安排\"，而是**英国货币霸权的制度化**；②**阶级政治视角**：金本位实际上是债权人（银行、债券持有者）的制度偏好——通货紧缩保护债权实际价值，而通胀有利于债务人（农民、工人）。19世纪末美国波普列斯特党（民粹党）\"自由白银\"运动，本质是债务人阶级反对金本位的政治斗争；③**帝国扩张视角**：金本位与殖民地体系紧密联系——殖民地被迫使用宗主国货币（或固定汇率），原材料出口→宗主国加工→殖民地被动承受汇率风险和贸易条件恶化。翟东升：金本位的\"自动调节\"机制是神话，实质是英国通过货币规则输出调整成本的霸权机制。", "explanation": "", "memorization": "三维：①英国货币霸权的制度化（英镑=全球结算）；②债权人的制度偏好（通缩保护债权）；③帝国扩张工具（殖民地被动承受）。翟东升：\"自动调节\"是英国输出调整成本的神话。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-short-06-4", "category": "简答题", "question": "人民币国际化采取了哪些策略和步骤？", "answer": "【五步走策略】①**贸易结算先行**（2009年起）：跨境贸易人民币结算试点→推广→形成规模；通过实体贸易建立人民币境外流通的初始存量；②**双边货币互换网络**（2008年后快速扩张）：央行与数十个国家和地区签署货币互换协议（总额超过3万亿元），提供应急流动性，并建立政治信任；③**离岸人民币中心建设**：香港CNH市场（2010年）→伦敦、新加坡、法兰克福离岸中心陆续建立；④**人民币计价资产建设**：推动境外机构投资中国债券（债券通2017年）、股票（沪深港通）；人民币加入SDR货币篮（2016年，权重10.92%）；⑤**一带一路融资人民币化**：以人民币计价的对外贷款和工程承包合同；⑥**数字人民币（e-CNY）跨境探索**：mBridge多边央行数字货币项目。翟东升判断：当前人民币国际化面临的核心约束是**资本账户开放程度不足**（缺乏深度的、可自由进出的人民币资产市场），这是下一阶段的关键突破口。", "explanation": "", "memorization": "五步：①贸易结算（2009）→②货币互换网络→③离岸中心（香港CNH）→④资产建设（债券通+SDR入篮2016）→⑤一带一路融资→⑥数字人民币。翟东升：核心约束=资本账户开放不足。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-short-06-5", "category": "简答题", "question": "简述当下人民币国际化的机遇期特征。", "answer": "【五大机遇期特征】①**美元信用侵蚀**：美国联邦债务持续扩张、美国将美元武器化（对俄制裁冻结美元储备）→全球去美元化意愿上升，为人民币提供替代空间；②**地缘政治重塑**：俄乌战争后，大量\"非西方\"国家（金砖+全球南方）寻求减少对美元体系依赖，人民币作为替代储备和结算货币的需求上升；③**中国经济体量支撑**：中国制造业产值约占全球30%，大宗商品对华贸易规模庞大（石油、铁矿石、大豆），天然形成人民币计价动力；④**数字货币技术窗口**：数字人民币（e-CNY）可绕过SWIFT体系，降低跨境结算成本，为人民币国际化提供技术路径上的后发优势；⑤**多极化体系成型**：IMF改革、BRICS货币讨论、RCEP生效→多极货币体系正在形成，人民币有望占据重要位置。翟东升：机遇期的关键挑战是**中国能否在美元体系收缩时快速填补空白**，需要同步推进资本账户改革和金融市场深化。", "explanation": "", "memorization": "五大机遇：①美元信用侵蚀（债务+武器化）；②地缘政治重塑（去美元化）；③中国经济体量（制造业30%）；④数字货币技术窗口（绕SWIFT）；⑤多极化成型。翟东升：关键是快速填补空白+资本账户改革。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-essay-06-1", "category": "论述题", "question": "人民币汇率短期和长期前景下会不会大幅贬值，请给出观点并论述原因。", "answer": "【观点：短期有压力，长期不会大幅持续贬值】一、短期贬值压力（现实存在，但可控）：①美联储加息周期→美元指数走强→新兴市场货币普遍承压，人民币也不例外；②中国经济下行压力（房地产风险+出口放缓）→资本外流担忧→市场预期贬值；③贸易战关税冲击→中国出口减少→经常账户顺差收窄→人民币需求下降。二、长期不大幅贬值的五大支撑：①**经常账户顺差**：中国长期保持贸易顺差（全球制造业基本盘稳固），持续产生人民币需求；②**外汇储备充足**：约3万亿美元外储，干预能力强；③**资本管制防火墙**：中国资本账户未完全开放，大规模资本外逃受到管控；④**购买力平价支撑**：如果人民币大幅贬值，中国出口竞争力将进一步增强，产生自动纠偏机制；⑤**央行政策意志**：人民银行始终将防范大幅贬值作为政策目标，干预手段丰富（调整逆周期因子、外汇存款准备金率等）。三、翟东升判断：人民币汇率的长期趋势应是**温和升值**（基于中国生产率提升快于贸易伙伴，即巴拉萨-萨缪尔森效应），大幅持续贬值既不符合经济基本面，也与中国人民币国际化的战略利益相悖（贬值会损害人民币储值功能，降低他国持有意愿）。", "explanation": "", "memorization": "短期有压力（美元强+资本外流）。长期五支撑：①经常账户顺差；②3万亿外储；③资本管制；④购买力平价自动纠偏；⑤央行政策意志。翟东升：长期应温和升值（巴萨效应），大幅贬值与国际化战略相悖。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-essay-06-2", "category": "论述题", "question": "请简述外汇储备的政治意义，论述中美之间的金融平衡。", "answer": "【外储政治意义→中美金融平衡机制→平衡的脆弱性→出路】一、外汇储备的政治意义（四点）：①**主权信用担保**：巨额外储是国家偿债能力的信号，降低被国际评级机构降级和遭受投机性冲击的风险；②**货币主权防御**：抵御外部冲击的物质基础，1997年香港动用外储击退投机资本；③**地缘政治筹码**：持有美国国债→对美国具有一定金融影响力（\"互相确保金融毁灭\"，但非对等）；④**\"三外路线\"载体**：外汇储备是中国对外投资、对外援助、对外政治关系的资金来源。二、中美金融平衡机制（翟东升\"金融恐怖平衡\"）：①中国持有约8000亿美元美债→中国卖出美债会推高美国利率（损害美国）；②但中国持有的美债贬值（如美元贬值或利率上升）也直接损害中国储备价值；③中国需要美元收入支付进口（石油、芯片等），美国需要中国持续融资赤字；④这是一种**不对等的相互脆弱性**：美国可通过美元贬值（通胀）稀释中国外储购买力，而中国难以大规模抛售美债（会损害自身）；⑤翟东升命名为\"安全资产陷阱\"——中国被\"锁定\"在美元资产中，难以脱身。三、脆弱性与出路：美国的\"金融制裁\"武器（冻结俄罗斯央行储备2022年）已警示中国：过度持有单一国家资产存在政治风险。出路：①多元化外储（增持黄金、欧元资产）；②减少外储积累（通过人民币国际化，让人民币在境外循环而非兑换成美元）；③以对外直接投资（实物资产）替代金融资产持有。", "explanation": "", "memorization": "外储四意义：信用担保+主权防御+地缘筹码+三外载体。中美金融平衡：翟东升=\"金融恐怖平衡\"（不对等脆弱性）+安全资产陷阱。出路：多元化+减少积累+ODI替代金融资产。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-essay-06-3", "category": "论述题", "question": "分析日元国际化失败的原因，其经验对人民币国际化策略路径的启示。", "answer": "【日元国际化历程→失败原因→人民币启示】一、日元国际化历程：1980年代日本经济鼎盛期，日元开始国际化尝试——开放日本金融市场、推动日元计价贸易、在亚洲建立日元结算网络。1985年广场协议后日元大幅升值，日本企业大量对外投资，日元国际使用一度上升。但1990年代资产泡沫破裂后，日本经济陷入\"失去的十年\"，日元国际化基本停滞，目前日元在全球外储中仅占约5%。二、失败的四大原因（翟东升分析）：①**金融体系开放换来的是脆弱性**：美国压迫日本开放金融市场→大量国际资本进出→资产泡沫形成→1990年破裂，日本丧失了经济自主性；②**以升值求国际化的悖论**：日元大幅升值虽提高了日元资产的购买力，却损害了日本制造业出口竞争力→产业空心化→国内经济基本面恶化→日元国际化失去实体支撑；③**缺乏独立的货币政策意志**：日本长期跟随美国货币政策，从未形成独立的货币锚；④**政治依附性**：日本对美安全依赖决定了其不可能在货币上与美国竞争，日元国际化在战略上受到天花板限制。三、对人民币的启示（五条）：①**不能接受美国压迫的货币升值**（日元升值→空心化，人民币必须坚持主动渐进）；②**金融开放要有序**（不能重蹈日本金融自由化→资本冲击的覆辙）；③**制造业基本盘是货币国际化的物质基础**（守住而非放弃）；④**政治自主是货币国际化的前提**（没有战略独立性就没有货币独立性）；⑤**分散风险优于单一路径**（通过多边框架推进）。翟东升核心判断：日元国际化失败的本质是**日本丧失了政治经济主权**，人民币国际化必须建立在政治独立和制造业实力之上，不能走\"以开放换国际化、以升值换地位\"的日本路。", "explanation": "", "memorization": "日元失败四原因：①开放换来脆弱性（广场协议）；②升值→产业空心化；③缺乏独立货币意志；④政治依附美国。人民币五启示：①拒绝被迫升值；②有序开放；③守住制造业基本盘；④政治自主为前提；⑤多边分散路径。翟东升：失败本质=丧失政治经济主权。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-term-07-78", "category": "名词解释", "question": "特里芬难题", "answer": "由耶鲁大学经济学家罗伯特·特里芬（Robert Triffin）于1960年提出的国际货币体系结构性矛盾。在布雷顿森林体系下，美元作为唯一国际储备货币，面临内在两难：①**提供流动性需求**：全球经济增长需要不断增加的美元供给，这要求美国持续维持国际收支逆差（贸易赤字+资本输出）；②**维持信心需求**：美元可兑换黄金（35美元/盎司），持续逆差会耗尽美国黄金储备，动摇美元信用。两者不可兼得——提供流动性则信心下降；维持信心则流动性不足，全球经济萎缩。特里芬难题的现实演变：尼克松1971年关闭黄金窗口实际上是\"解决\"了特里芬难题的约束——美元不再兑换黄金，美国可以无限制提供流动性。翟东升：特里芬难题是美元霸权的内在矛盾，美元霸权的延续依靠的是\"美国债务的全球接受度\"而非任何实物锚。", "explanation": "", "memorization": "特里芬难题：美元必须逆差提供流动性，但逆差耗尽黄金则信心崩溃。两者不可兼得。1971年关闭黄金窗口=变相解决（但靠霸权而非实物锚）。翟东升：美元霸权靠全球接受度，非实物。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-term-07-79", "category": "名词解释", "question": "美元指数", "answer": "衡量美元相对于一篮子主要货币综合汇率的指标，由洲际交易所（ICE）发布，1973年以100为基准。货币篮子及权重：欧元（57.6%）、日元（13.6%）、英镑（11.9%）、加拿大元（9.1%）、瑞典克朗（4.2%）、瑞士法郎（3.6%）。特点与政治含义：①篮子成员全为发达国家货币，不包含人民币、卢布等，因此美元指数的\"强弱\"无法全面反映美元对新兴市场的购买力；②美元指数与全球资产价格高度负相关——美元指数上升→新兴市场资本外流→资产价格下跌（翟东升\"美元潮汐\"的测量工具）；③美联储加息→美元升值→美元指数上升→全球流动性收紧→对外围国家形成周期性冲击。翟东升：美元指数是观察\"美元潮汐\"节律的核心工具，其历史高点往往对应全球金融危机的爆发节点（如1985年、2000年、2022年）。", "explanation": "", "memorization": "美元对一篮子主要货币（六种，欧元权重最大57.6%）的综合汇率，1973年基准100。美元指数↑=全球流动性紧缩+新兴市场承压。翟东升：美元潮汐的测量工具，高点对应全球危机节点。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-term-07-80", "category": "名词解释", "question": "产业链编辑能力（CICE）", "answer": "由翟东升提出的概念，全称Capacity for Industrial Chain Editing。指一国在全球产业分工中，主动重新配置、整合、延伸或切断产业链环节的能力——即\"编辑\"全球产业链的能力，而非仅仅\"嵌入\"其中。核心含义：①**主动性**：不是被动接受跨国公司的产业分工安排，而是主动决定哪些产业链环节留在本国、哪些向外转移、与谁合作；②**系统性**：能够跨越单一产品或行业，从整个供应链生态系统进行布局；③**政治性**：CICE既是经济能力，也是地缘政治工具——可通过\"产业链切断\"对他国施加压力。中国CICE的体现：①将劳动密集型产业向越南、孟加拉、墨西哥转移（主动输出低端产业）；②将半导体、AI、新能源留在国内并扶持；③通过一带一路将中国标准和产业链延伸到非洲、中亚。翟东升：掌握CICE是中国从\"世界工厂\"升级为\"世界产业链编辑者\"的关键，是中国在全球价值链竞争中的核心战略能力。", "explanation": "", "memorization": "翟东升概念：产业链编辑能力（CICE）=主动重配/整合/切断全球产业链的能力。三特征：主动+系统+政治。中国体现：转移低端→留住高端→延伸一带一路。翟东升：从世界工厂→产业链编辑者的关键升级。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-term-07-81", "category": "名词解释", "question": "人民币国际化", "answer": "人民币在国际贸易结算、金融计价、储备积累三大职能上逐步替代（或补充）美元、欧元等主要货币，实现跨境自由流通和使用的过程。三大货币功能的国际化：①**交易媒介**：以人民币计价和结算跨境贸易（2009年试点，现已推广）；②**价值尺度**：国际商品（石油、铁矿石）以人民币计价（石油人民币期货2018年上市）；③**价值储藏**：外国央行和机构投资者将人民币资产（国债、股票）作为外汇储备。当前进展与挑战：人民币在全球外储份额约2.6%（位列第5）；主要挑战：资本账户未完全开放、人民币资产市场深度不足、地缘政治分割。翟东升：人民币国际化的最终形态不是取代美元（过于激进），而是实现\"人民币区\"的形成——在中国主导的贸易和投资网络中，人民币成为主要结算货币。", "explanation": "", "memorization": "三功能国际化：交易媒介（贸易结算）+价值尺度（商品计价）+价值储藏（外储）。进展：全球外储份额约2.6%。翟东升：目标不是取代美元，而是形成\"人民币区\"。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-term-07-82", "category": "名词解释", "question": "牙买加体系", "answer": "1976年牙买加协议（Kingston Accords）确立的现行国际货币体系，正式终结了布雷顿森林体系的黄金-美元双挂钩。主要内容：①法律上承认浮动汇率合法性，各国自由选择汇率制度；②黄金非货币化，取消官方黄金平价，IMF出售部分黄金储备；③SDR（特别提款权）被定义为主要国际储备资产（但实际地位边缘化）；④美元在实践中继续主导国际货币体系。深层政治含义（翟东升）：牙买加体系表面上是\"无体系\"（无中心锚），实质上是美国将不受约束的美元铸币权制度化——美元不再被黄金约束，美国可无限发债、无限印钞，全球其他国家被动承担美元购买力波动的风险。翟东升：牙买加体系是美国货币霸权的\"2.0升级版\"，比布雷顿森林体系对美国更有利——因为黄金约束被彻底消除。", "explanation": "", "memorization": "1976年，现行国际货币体系。四内容：浮动汇率合法+黄金非货币化+SDR为主储（名义）+美元实际主导。翟东升：美元霸权2.0——黄金束缚消除，美国无限铸币权制度化。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-term-07-83", "category": "名词解释", "question": "外汇占款", "answer": "央行（或商业银行）在购入外汇时，相应投放的等值本币。在中国，指中国人民银行以人民币购入外汇（美元、欧元等）时产生的基础货币投放，是央行资产负债表中的\"外汇资产\"对应的负债端（已投放人民币）。形成机制：出口商收到外汇→在银行结售汇→银行将外汇转售给央行→央行按汇率投放等值人民币→形成外汇占款（基础货币被动扩张）。宏观影响：①外汇占款是2000-2014年中国基础货币扩张的主要来源（外汇储备快速增长期）；②外汇占款增加→流动性泛滥→央行必须通过提高存准率、发行央票等方式\"冲销\"（对冲）；③2015年后外汇储备下降→外汇占款减少→央行通过MLF、SLF等新工具补充基础货币。政治含义：外汇占款机制使中国货币政策在某种程度上被动跟随美国货币周期，是\"货币主权受限\"的体现之一。", "explanation": "", "memorization": "央行购入外汇时投放的等值人民币=外汇占款。形成：出口商结售汇→央行购汇→投放人民币。宏观：2000-2014年基础货币主要来源；超发须冲销（存准+央票）；2015年后靠MLF补充。政治：货币政策被动跟随美国周期。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-term-07-84", "category": "名词解释", "question": "布雷顿森林体系", "answer": "1944年7月在美国新罕布什尔州布雷顿森林会议上建立的战后国际货币体系（1944-1971年）。核心安排：①**美元-黄金挂钩**：美元以35美元/盎司固定兑换黄金，美国承担最终兑换义务；②**可调整钉住汇率**：其他国家货币钉住美元（±1%波动区间），须经IMF批准才能调整平价；③**IMF和世界银行**：提供短期国际收支融资和长期发展贷款。历史意义：①确立了美元的核心储备货币地位（\"美元霸权的制度化起点\"）；②为战后国际贸易扩张和西方经济复苏提供稳定的货币环境；③1971年因特里芬难题（美国黄金储备不足）被尼克松宣布单边终止，过渡至牙买加体系。翟东升：布雷顿森林体系不是中性的多边合作安排，而是美国将战后压倒性经济优势制度化的霸权工具；英国凯恩斯方案（bancor）被否决，本质是美国输出了自身货币，而非创设真正的国际货币。", "explanation": "", "memorization": "1944-1971年，核心：美元-黄金挂钩（35$=1盎司）+其他货币钉住美元（IMF监督）。三支柱：IMF+世行+固定汇率。翟东升：美国将战后霸权制度化，凯恩斯bancor方案被否=美国利益优先。1971年特里芬难题终结。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-short-07-1", "category": "简答题", "question": "简述中国大量持有美国国债的原因。", "answer": "【五层原因：强制性+安全性+流动性+体制性+战略性】①**强制性的外汇储备积累机制**：长期强制结售汇制度+经常账户顺差→外汇储备快速积累（外汇占款）→必须配置美元资产；②**美元资产的安全性和流动性**：美国国债市场是全球规模最大、流动性最强的债券市场，在外储规模庞大的约束下，很少有其他资产能容纳如此量级的配置；③**历史路径依赖**：从1990年代开始，中国逐步形成以美债为主要外储资产的格局，体制惯性强；④**替代选择有限**：欧元资产（欧债危机风险）、日元资产（收益率极低）、黄金（总量有限，价格波动大）均无法完全替代美债规模；⑤**地缘政治的\"抵押品\"逻辑**：持有美债使中国对美国具有一定的金融影响力——若中国大规模抛售，将推高美国利率，形成\"金融恐怖平衡\"。翟东升：大量持有美债是\"安全资产陷阱\"——中国被美元体系结构性锁定，这既是现实约束，也是未来去美元化的驱动力所在。", "explanation": "", "memorization": "五原因：①强制结售汇→外汇占款积累；②美债安全+流动性最强；③历史路径依赖；④替代选择有限；⑤金融恐怖平衡筹码。翟东升：安全资产陷阱→结构性锁定。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-short-07-2", "category": "简答题", "question": "简述我国外汇储备的政治含义。", "answer": "【四重政治含义】①**主权信用背书**：巨额外储（约3万亿美元）向国际市场释放信号——中国有充足的偿债能力和抵御冲击的\"弹药库\"，降低外国资本将中国视为脆弱经济体的预期，减少资本外逃和货币投机动机；②**金融防御武器**：在汇率面临投机冲击时，央行可动用外储在市场上买入人民币、卖出美元，击退投机者（中国2015-2016年消耗约1万亿美元外储稳定汇率）；③**地缘政治资源**：外储支撑\"三外路线\"（外交投资、对外援助、对外开发），是一带一路、人民币国际化、经济外交的物质基础；④**对美影响力（有限但存在）**：持有美债=美国的债权国，理论上大规模抛售可对美国利率造成冲击，形成\"金融恐怖平衡\"（但实践中因损害自身而难以实施）。翟东升：外储的政治含义是双重的——既是战略资产（主权防御+地缘影响力），也是战略负担（安全资产陷阱，受制于美元霸权）。", "explanation": "", "memorization": "四政治含义：①主权信用背书（防投机）；②金融防御武器（干预汇率）；③地缘政治资源（三外路线/一带一路）；④对美有限影响力（金融恐怖平衡）。翟东升：既是战略资产也是战略负担（安全资产陷阱）。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-short-07-3", "category": "简答题", "question": "我国巨额外汇储备持有的代价和成本主要有哪些。", "answer": "【五大代价】①**机会成本**：持有低收益的美国国债（收益率约2-4%），而中国国内基础设施、教育、医疗投资的潜在回报率远高于此；②**通货膨胀压力**：外汇占款→基础货币被动扩张→流动性过剩→国内通胀压力和资产泡沫（2000-2012年房价大涨的重要因素之一）；③**货币政策主权损失**：外汇占款扩张使基础货币供应量被动跟随外汇流入规模，央行主动调控空间被压缩；④**美元贬值的汇兑损失**：当美元贬值时，以美元计价的外储折算成人民币后价值下降，中国已有潜在的购买力损失；⑤**集中度风险（政治风险）**：2022年俄罗斯事件后，以外储集中持有美元资产的政治风险已被充分证明——美国可单边冻结他国外汇储备，中国持有大量美债面临同等政治风险。翟东升：外储的真实成本是向美元霸权缴纳的\"货币地租\"——中国廉价商品换来的美元，以低利率贷给美国，而美国拿这笔钱消费中国商品，循环中的损失由中国承担。", "explanation": "", "memorization": "五代价：①机会成本（国债收益低于国内投资）；②通胀压力（外汇占款→货币超发）；③货币政策主权损失；④美元贬值汇兑损失；⑤政治风险（俄罗斯被冻结前车之鉴）。翟东升：本质=向美元霸权缴纳货币地租。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-short-07-4", "category": "简答题", "question": "通过货物贸易渠道，资本流入中国实施汇率套利的做法主要有哪些？", "answer": "【三类套利手法】背景：当人民币存在升值预期或利差（中国利率高于境外）时，资本希望通过贸易渠道流入中国套取汇率收益或利差，规避资本管制。①**贸易发票造假（虚假贸易）**：高报出口（实际出口价值100万美元，发票记成150万）→境内收到150万美元外汇→结汇获得人民币→套汇+升值收益；或低报进口（压低进口发票）→减少美元外流→变相留存外汇在境外等待升值；②**预收货款/延迟付款**：出口商提前收到境外货款（用作短期资金流入中国）；进口商推迟支付境外货款（减少美元外流）；在人民币升值预期下，拉长\"收汇\"、缩短\"付汇\"周期=变相资本流入；③**转口贸易/关联方交易**：通过香港等中间地区，由关联企业安排\"货物往返\"但资金净流入，实际商品并未真实交割，只是文件流转；常见于中国大陆与香港之间的异常贸易数据（如2013-2014年香港内地贸易数据严重失真）。监管应对：国家外汇管理局（SAFE）对异常贸易数据进行核查，要求贸易背景真实性审核；2014年后严查虚假贸易，相关数据明显改善。", "explanation": "", "memorization": "三类：①高报出口/低报进口（发票造假）；②预收货款/延迟付款（拉长收汇周期）；③转口贸易/关联方虚假交割（港-陆异常数据）。监管：SAFE核查真实贸易背景，2014年后严查。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-short-07-5", "category": "简答题", "question": "技术进步如何影响一国货币的汇率？", "answer": "【两条主渠道+翟东升视角】一、标准经济学分析（两条渠道）：①**巴拉萨-萨缪尔森效应**（最主要机制）：技术进步首先在可贸易品部门（制造业）体现→劳动生产率提升→可贸易品价格相对下降或工资上涨→工资溢出至不可贸易品（服务业）→整体价格水平上升→实际汇率升值（购买力平价意义上的升值）。这解释了为何高速发展经济体的货币倾向于实际升值；②**贸易条件改善**：技术进步→出口产品质量提升、附加值增加→出口价格可提升、出口需求增加→贸易顺差扩大→外汇需求增加→名义汇率升值压力。二、翟东升补充：③**产业链编辑能力（CICE）视角**：技术进步使一国向产业链高端攀升→获得更多\"技术垄断租金\"→国际谈判中议价能力提升→货币走强的结构性支撑；④**新兴技术的地缘政治效应**：AI、新能源等核心技术的领先国，往往在技术封锁中获得更多谈判筹码，间接强化货币信用。三、反向效应（技术落后）：技术停滞→出口产品向低附加值品集中→贸易条件恶化→货币贬值压力（拉美去工业化与货币弱势的历史印证）。", "explanation": "", "memorization": "两主渠道：①巴萨效应（技术进步→可贸易品生产率↑→实际汇率升值）；②贸易条件改善→顺差扩大→名义汇率升值。翟东升：CICE视角（攀升高端→技术租金→货币走强）。反向：技术停滞→拉美货币弱势。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-essay-07-1", "category": "论述题", "question": "人民币汇率政策低估值和高估值各会带来什么样的利弊？党的十九大后，为解决我国新时代的主要矛盾，应实行什么样的人民币汇率政策？", "answer": "【低估利弊→高估利弊→十九大后政策取向】一、低估值（人民币偏低）的利弊：利：①促进出口竞争力，有利于劳动密集型制造业就业和贸易顺差；②吸引外资（以低汇率计价的要素成本降低）；③有利于债务国（政府和企业以人民币计价的债务实际负担减轻）。弊：①储蓄者和消费者受损（进口品价格高、出境消费更贵、实际购买力下降）；②对美国等贸易伙伴产生贸易摩擦（\"汇率操纵\"指责）；③外汇占款被动扩张→通胀压力+货币政策主权受损；④向美元体系缴纳\"货币地租\"（低价出口商品换低收益美债）；⑤不利于产业升级（保护低效出口产业，抑制向高端转型的压力）。二、高估值的利弊：利：①增强国内购买力（进口商品更便宜，消费结构升级）；②降低进口能源和原材料成本（有利于制造业中下游和消费者）；③推动产业升级（高汇率淘汰低端出口，倒逼企业向高附加值转型）；④有利于人民币国际化（储值功能增强）。弊：①出口竞争力下降，低端制造业就业受损；②可能引发资本流入过热→资产泡沫；③如汇率急速升值（如1985年广场协议后的日元），可能导致产业空心化。三、十九大后的政策取向（翟东升视角）：十九大明确新时代主要矛盾为\"人民日益增长的美好生活需要和不平衡不充分的发展之间的矛盾\"——这意味着政策重心从\"保出口、保就业\"转向\"提升人民生活质量和消费能力\"。因此，汇率政策应**适度偏向高估值方向**：①允许人民币渐进升值（反映中国生产率提升的巴萨效应）；②以升值降低能源原材料进口成本，支持消费升级；③推动出口结构向高附加值品转型（淘汰低端出口依赖）；④坚决防止大幅贬值（避免向外输出通胀，维护人民币国际信用）。翟东升：汇率政策的本质是\"民本主义\"选择——以汇率作为分配工具，十九大后答案偏向消费者和人民生活质量。", "explanation": "", "memorization": "低估利：出口竞争力+外资+债务减轻。低估弊：储蓄者受损+贸易摩擦+货币地租+产业升级受阻。高估利：购买力+进口廉价+产业升级+国际化。高估弊：出口受损+资产泡沫风险+产业空心化风险。十九大后：适度高估（民本主义，提升消费者福利）。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-essay-07-2", "category": "论述题", "question": "从政治经济学角度论述人民币固定汇率制度和浮动汇率制度的优缺点，及若汇率从固定汇率向浮动汇率转变过程中会带来什么样的风险与挑战。", "answer": "【固定优缺→浮动优缺→转变风险与挑战】一、固定汇率制度（政治经济学视角）：优点：①**稳定预期，降低交易成本**：进出口商和跨国投资者无需对冲汇率风险，贸易和投资激励增加；②**输入性货币纪律**：盯住强势货币（如美元）可输入其货币公信力，帮助通胀不稳定的国家建立反通胀公信力（如香港联系汇率）；③**政治稳定**：汇率稳定往往与政治稳定相关，有利于政府维护民众信心。缺点：①**放弃货币政策独立性**（蒙代尔三元悖论）：在资本自由流动条件下，固定汇率→利率必须跟随锚定货币→国内货币政策丧失自主空间；②**易受投机冲击**：汇率目标公开，投机者有明确攻击目标（1992年英镑/1997年泰铢的经典案例）；③**国际收支调整缓慢**：无法通过汇率变动自动调节贸易失衡，调整成本转移到工资和物价（内部调整成本高昂且痛苦）。二、浮动汇率制度：优点：①**货币政策独立性**：汇率作为外部冲击的\"减震器\"，使国内货币政策可以独立应对本国经济周期；②**自动调节国际收支**：贸易逆差→货币贬值→出口竞争力恢复，无需政策主动干预；③**无法被投机性冲击集中攻击**（无明确攻击目标）。缺点：①**汇率波动增加不确定性**，贸易和投资的对冲成本上升；②**投机行为放大波动**（短期资本流动可产生超调）；③**货币政策面临通胀压力传导**（贬值→进口价格上涨→输入性通胀）。三、从固定向浮动转变的风险与挑战（以中国为参照）：①**资本外流压力骤增**：转变意味着资本账户放开，投资者会测试政策当局的承诺，可能引发大规模资本外流和汇率超调；②**汇率超调与恐慌**：市场对新汇率均衡水平不确定，投机性预期可能导致汇率大幅偏离基本面；③**金融体系脆弱性暴露**：国内企业长期未对冲美元债务，汇率大幅波动将导致资产负债表危机（1997年东南亚模式）；④**货币政策框架需同步重建**：转向浮动汇率后，需建立新的货币政策名义锚（利率走廊、通胀目标制等），否则会出现政策真空；⑤**政治压力与政策节奏管理**：在贬值预期强烈时推进浮动化，可能触发自我实现的危机，需选择合适时机（一般在货币有升值压力时推进）。翟东升建议：中国应实行**渐进式汇率市场化**——扩大日间波幅、弱化中间价干预、配合资本账户有序开放，而非\"一步到位\"的自由浮动。", "explanation": "", "memorization": "固定：优（稳预期+输入货币纪律+政治稳定），缺（放弃货币政策独立性+投机冲击+调整成本内化）。浮动：优（货币政策独立+自动调节+无明确攻击目标），缺（波动+投机超调+输入通胀）。转变五风险：资本外流+汇率超调+资产负债表危机+政策框架真空+政治压力。翟东升：渐进市场化，避免一步到位。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-essay-07-3", "category": "论述题", "question": "央行独立性是否是良好货币政策的必要前提，请给出你的观点并论述之。", "answer": "【观点：不是必要前提，而是充分条件之一（有利但非唯一路径）】一、主流观点（支持央行独立性）的逻辑：①**时间不一致性问题**（Kydland-Prescott）：政客有短期刺激经济（降低失业率）的激励→货币扩张→通胀预期上升→实际通胀率提高，但长期经济不改善，故需独立的央行承诺长期价格稳定；②**信用积累**：独立的央行（如德意志联邦银行、美联储）通过长期守住价格稳定目标，积累货币政策公信力，降低通胀预期锚定成本；③**政治周期与货币周期分离**：避免政策制定者将货币政策工具化为选举工具。二、反驳与限定（翟东升视角）：①**历史案例反驳**：中国央行缺乏西方意义的独立性，但中国长期保持了相对稳定的通胀水平和较高的经济增长（说明没有独立性也可以实现良好货币政策）；②**制度环境决定论**：央行独立性的效果取决于整体政治经济制度环境——在多党民主+分权体制中，独立性有助于隔离短期政治压力；在党政统一体制中，政治目标与宏观稳定目标可能本身一致，无需制度隔离；③**独立性≠无政治**：美联储看似独立，但实际上高度依赖国会授权、总统任命，并非真正独立于政治；④**民主问责的正当性**：若央行完全独立，则货币政策脱离民主问责，存在合法性危机；翟东升的\"民本主义\"立场认为，货币政策不应只服务于金融稳定，也应服务于就业和人民福祉，过度独立化是金融精英的制度偏好而非公共利益最大化。三、综合结论：央行独立性是在特定制度环境下有效改善货币政策的工具，但不是唯一路径，也非必要前提。决定货币政策质量的根本因素是：①政策目标的合理性（兼顾价格稳定、充分就业和金融稳定）；②决策者的专业能力和诚信；③有效的问责机制（无论是政治问责还是制度问责）。翟东升总结：\"独立的央行可能是良好货币政策的有效工具，但从不是充分条件，更不是必要条件——它是西方自由民主政治体制的制度安排，移植到其他政治体制需要审慎评估其真实效果。\"", "explanation": "", "memorization": "主流支持：时间不一致性→独立央行承诺价格稳定。翟东升反驳：①中国无独立性但货币政策稳健；②制度环境决定论；③美联储并非真独立；④民主问责的合法性。结论：非必要前提，是特定制度下有效工具。根本因素：政策目标合理+专业诚信+问责机制。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-scholar-01", "category": "学术人物", "question": "考克斯（Robert Cox）", "answer": "代表作：《生产、权力与世界秩序》（1987）。核心命题：“理论总是为某人、某种目的服务的”——批判理论揭示既有国际秩序服务于霸权利益，而非中立工具；需与维持现状的“问题解决理论”严格区分。理论地位：新葛兰西主义IPE奠基人，将葛兰西霸权概念引入国际秩序分析，确立批判政治经济学方法论基础。", "explanation": "", "memorization": "新葛兰西主义；“理论总是为某人服务”；批判理论vs问题解决理论；代表作《生产、权力与世界秩序》。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-02", "category": "学术人物", "question": "斯特兰奇（Susan Strange）", "answer": "代表作：《国家与市场》（1988）、《赌场资本主义》（1986）。核心命题：结构性权力（生产、安全、金融、知识四大结构）比关系性权力对国际政治经济具有更根本的决定意义，谁掌控结构谁就掌控规则。理论地位：英国学派IPE创始人，结构性权力分析框架奠基者，最早系统批判国际金融结构侵蚀国家主权。", "explanation": "", "memorization": "英国学派；结构性权力四维（生产、安全、金融、知识）>关系性权力；代表作《国家与市场》《赌场资本主义》。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-03", "category": "学术人物", "question": "基欧汉（Robert Keohane）", "answer": "代表作：《权力与相互依赖》（与奈合著，1977）、《霸权之后》（1984）。核心命题：霸权衰落后国际机制仍可维系合作，因为制度能降低交易成本、提供信息、缓解欺骗问题，合作不依赖单一霸权存在。理论地位：新自由制度主义创始人，复合相互依赖与国际机制理论奠基人，与现实主义形成当代IPE核心论争。", "explanation": "", "memorization": "新自由制度主义；复合相互依赖；霸权衰落后机制仍可维系合作；代表作《霸权之后》《权力与相互依赖》。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-04", "category": "学术人物", "question": "奥斯特罗姆（Elinor Ostrom）", "answer": "代表作：《公共事务的治理之道》（1990）。核心命题：“公地悲剧”不可避免的结论是错误的——社区通过自主设计规则、相互监督，可以有效治理公共资源，既无需国家强制，也无需私有化。理论地位：2009年诺贝尔经济学奖得主，公共池塘资源（CPR）自主治理理论奠基人，打破国家-市场两分法定见。", "explanation": "", "memorization": "2009诺贝尔经济学奖；公共池塘资源自主治理；打破“公地悲剧”宿命论；代表作《公共事务的治理之道》。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-05", "category": "学术人物", "question": "卡赞斯坦（Peter Katzenstein）", "answer": "代表作：《小国在世界市场中》（1985）、《文化规范与国家安全》（1996）。核心命题：国家对外经济政策由国内政治联盟结构与国家-社会关系决定；文化与规范是国际政治不可或缺的解释变量，而非单纯反映物质利益。理论地位：比较政治经济学奠基人，后期确立建构主义文化-制度分析路径，深刻影响安全与经济研究。", "explanation": "", "memorization": "比较政治经济学；国内政治结构决定对外政策；文化与规范的因果作用；代表作《小国在世界市场中》。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-06", "category": "学术人物", "question": "库珀（Richard Cooper）", "answer": "代表作：《相互依存的经济学》（1968）。核心命题：经济相互依赖使各国政策产生强烈外溢效应，单边政策的效力因此衰减，国际宏观经济政策协调不是可选项，而是相互依赖时代的结构性必然。理论地位：经济相互依赖理论先驱，国际宏观经济政策协调研究奠基人，早于基欧汉系统论证相互依赖的政治后果。", "explanation": "", "memorization": "相互依赖先驱；政策外溢→单边效力衰减→协调必然；代表作《相互依存的经济学》（1968）。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-07", "category": "学术人物", "question": "科斯（Ronald Coase）", "answer": "代表作：《企业的性质》（1937）、《社会成本问题》（1960）。核心命题：交易成本决定经济组织的边界；产权明晰且交易成本为零时，外部性可通过自愿谈判实现帕累托最优，无需政府干预（科斯定理）。理论地位：1991年诺贝尔经济学奖得主，新制度经济学奠基人，科斯定理为产权分析提供方法论基石。", "explanation": "", "memorization": "1991诺贝尔经济学奖；交易成本→企业边界；科斯定理（产权明晰+谈判→外部性内部化）；代表作《企业的性质》《社会成本问题》。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-08", "category": "学术人物", "question": "诺思（Douglass North）", "answer": "代表作：《制度、制度变迁与经济绩效》（1990）、《西方世界的兴起》（1973）。核心命题：制度是“游戏规则”，非正式约束（文化、习惯、意识形态）与正式规则共同决定国家长期经济绩效，历史路径依赖使落后国家难以走出低效均衡。理论地位：1993年诺贝尔经济学奖得主，新制度经济学历史分析奠基人，路径依赖概念的核心阐发者。", "explanation": "", "memorization": "1993诺贝尔经济学奖；制度=游戏规则；路径依赖；非正式约束决定长期绩效；代表作《制度、制度变迁与经济绩效》。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-09", "category": "学术人物", "question": "金德尔伯格（Charles Kindleberger）", "answer": "代表作：《1929-1939年世界经济萧条》（1986）。核心命题：霸权稳定论——国际经济稳定需要一个既有意愿又有能力充当“最后贷款人”、维护开放市场的单一霸权国，大萧条的根源即在于英国无力、美国不愿承担领导责任。理论地位：霸权稳定理论奠基人，国际金融史权威，其论断成为争论美国霸权是否必要的核心依据。", "explanation": "", "memorization": "霸权稳定论奠基人；霸权=最后贷款人+维护开放市场；大萧条教训；代表作《1929-1939年世界经济萧条》。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-10", "category": "学术人物", "question": "克拉斯纳（Stephen Krasner）", "answer": "代表作：《捍卫国家利益》（1978）、《国际机制》（1983）。核心命题：国际机制是“期望汇聚的原则、规范、规则和决策程序”；国家是核心行为体，机制的建立与存续取决于权力分配，而非自发的功能需求。理论地位：国际机制理论定义性贡献者，现实主义IPE代表人物，威斯特伐利亚主权规范的重要分析权威。", "explanation": "", "memorization": "现实主义IPE；国际机制定义（原则+规范+规则+程序）；权力决定机制；代表作《国际机制》《捍卫国家利益》。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-11", "category": "学术人物", "question": "沃勒斯坦（Immanuel Wallerstein）", "answer": "代表作：《现代世界体系》（三卷，1974-1989）。核心命题：资本主义世界经济按核心-半边缘-边缘结构运作，边缘国家通过不平等交换向核心持续输送剩余，结构性剥削使欠发展难以根本逆转。理论地位：世界体系理论奠基人，依附论发展的顶峰，历史社会学与政治经济学跨界整合的标志性人物。", "explanation": "", "memorization": "世界体系理论；核心-半边缘-边缘三层结构；不平等交换→结构性剥削；代表作《现代世界体系》三卷本。", "source": "IPE-学术人物"},
    {"id": "ipe-scholar-12", "category": "学术人物", "question": "卡多佐（Fernando Henrique Cardoso）", "answer": "代表作：《依附与发展》（与法莱托合著，1969）。核心命题：“关联发展”——依附是历史结构性状况，但内部阶级联盟与国家干预能在依附中实现有限发展，否定了机械的“欠发展宿命论”，强调内部政治能动性的关键作用。理论地位：依附论修正派核心人物，拉美结构主义与发展理论重要代表，后任巴西总统。", "explanation": "", "memorization": "依附论修正派；“关联发展”（依附中仍可发展）；否定欠发展宿命论；代表作《依附与发展》（1969）；后任巴西总统。", "source": "IPE-学术人物"},
    {"id": "ipe-fill-05-0", "category": "填空题", "question": "【最优货币区（Optimal Currency Area, OCA）】指在某一地理区域内，采用___或___比各自浮动汇率更有效率的经济区域。", "answer": "单一货币、固定汇率", "explanation": "OCA理论揭示了货币主权让渡的条件，欧元区是典型实践但财政不统一。", "memorization": "口诀：单货+固汇 = OCA。翟东升：货币区不仅经济、更是政治博弈。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-fill-05-1", "category": "填空题", "question": "【经常项目与资本项目】国际收支中：管\"货物+服务+收入\"的是___；管\"投资+资产\"的是___；二者互为镜像。中国长期\"双顺差\"本质上是将___换成___。", "answer": "经常项目、资本项目、实际资源、外币资产", "explanation": "双顺差本质=将实际资源换成外币资产，承担他国量化宽松代价。", "memorization": "经常=货物+服务+收入；资本=投资+资产。互为镜像。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-fill-05-2", "category": "填空题", "question": "【国际收支（Balance of Payments, BOP）】会计平衡公式：___ + ___ + ___ = 0。", "answer": "经常项目、资本项目、误差与遗漏", "explanation": "国际收支不仅是经济账本，更是国际政治权力关系的映射。", "memorization": "BOP = 经常 + 资本 + 误差遗漏 = 0", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-fill-05-3", "category": "填空题", "question": "【一价定律（Law of One Price）】指在自由贸易、无运输成本和贸易壁垒的理想条件下，同一种商品在不同市场用同一货币计价的价格应当___；其背后机制是___（价差超过运输成本即低买高卖将其抹平）。", "answer": "相等、套利", "explanation": "一价定律是购买力平价（PPP）理论的微观基石；在可贸易品大致成立，在服务业等非贸易品领域经常失效。", "memorization": "一价定律=同一商品同价；靠套利抹平价差。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-fill-05-4", "category": "填空题", "question": "【可贸易品（Tradable Goods）】指能够___、参与国际贸易（出口或进口）的商品，与只能本地生产消费的___（如理发、餐饮、房地产等服务）相对。", "answer": "跨国境运输、非贸易品", "explanation": "可贸易品部门的强大是一国货币国际化的产业基础；中国崛起使工业制成品、运力、电力、算力、火力五大可贸易品价格大幅下降。", "memorization": "可贸易品=能跨国买卖；非贸易品=只能本地消费（理发餐饮房产）。", "source": "翟东升-货币金融-模拟05"},
    {"id": "ipe-fill-08-13", "category": "填空题", "question": "【SWIFT系统】环球银行金融电信协会，是全球最主要的跨境金融___传送系统，为200多个国家和地区的金融机构提供标准化的___信息传输服务（本身不划转资金，只传报文）。", "answer": "报文、支付结算", "explanation": "SWIFT已被美国\"武器化\"成为金融制裁的核心工具（被踢出即被切断全球金融血脉）；中国建设CIPS构建替代性结算通道。", "memorization": "SWIFT = 全球金融\"邮局\"（只传报文）；中国建CIPS绕开。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-fill-08-14", "category": "填空题", "question": "【拉美债务危机】以___年___宣布无力偿还外债为标志，使拉美陷入\"___\"，是美元潮汐收割的经典案例。", "answer": "1982、墨西哥、失去的十年", "explanation": "IMF的\"救助\"实为华盛顿共识的强制推行，本质是为下一轮收割拆除防火墙。<br>📺 <a href='https://www.bilibili.com/video/BV15b4y1Q7Ez' target='_blank' style='color:#6a8899;text-decoration:underline'>B站·陈平眉山论剑《拉美借债史》（18.8万播放）</a>", "memorization": "1982墨西哥违约→失去的十年。翟东升：美元潮汐收割教科书。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-fill-08-15", "category": "填空题", "question": "【去工业化】指一国___在国民经济中的比重（产值占GDP比重和就业占比）持续___的过程和趋势；翟东升强调人民币的真正\"锚\"不是黄金，而是___。", "answer": "制造业、下降、中国的工业产能（制造业基本盘）", "explanation": "去工业化是中央-外围体系运转的副产品，守住制造业=守住货币之锚。", "memorization": "制造业占比持续下降 = 去工业化。守制造业 = 守货币之锚。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-fill-08-16", "category": "填空题", "question": "【预算软约束】由匈牙利经济学家科尔奈提出，指企业（尤其是国有企业）即使经营___，也能通过政府补贴、贷款减免等方式继续___、不受市场纪律制约的现象；根源是企业预期亏损总会被政府___。", "answer": "亏损、存活、兜底", "explanation": "翟东升延伸：美国凭借美元霸权享有全球最大的\"软约束\"，可长期维持财政赤字和贸易逆差而不受严厉市场惩罚。", "memorization": "亏损不死、政府兜底 = 预算软约束。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-fill-08-17", "category": "填空题", "question": "【依附理论】20世纪___年代兴起的国际政治经济理论，认为发展中国家（外围）的不发达不是内部原因，而是被中心国___剥削和控制的结果；代表人物弗兰克认为\"越融入越穷\"，卡多佐主张\"___\"。", "answer": "50-60、结构性、可以有限发展（关联发展）", "explanation": "外围国家积累美元储备 = 向中心国缴纳\"货币地租\"。", "memorization": "穷国穷是被剥削（结构性）。弗兰克：越融入越穷；卡多佐：有限发展。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-fill-08-18", "category": "填空题", "question": "【经济安全】指一国在经济领域___内外部威胁和冲击、维持经济体系稳定运行和可持续发展的能力与状态；翟东升强调其核心不是封闭自保，而是在___中掌握主动权。", "answer": "抵御、开放", "explanation": "当前最大威胁来自美元体系\"武器化\"；中国推进人民币国际化、建CIPS、减持美债、增持黄金，本质都是经济安全的战略布局。", "memorization": "经济安全 = 抵御冲击 + 开放中掌握主动权。", "source": "翟东升-货币金融-模拟08"},
    {"id": "ipe-fill-09-19", "category": "填空题", "question": "【特里芬困境】___年___提出的命题：作为全球储备货币的美元，既要通过持续___向世界提供流动性，又要维持对___的可兑换性，两者存在根本矛盾。", "answer": "1960、罗伯特·特里芬、贸易逆差、黄金", "explanation": "美国通过1971年关闭黄金窗口、转向石油美元+金融霸权实际\"摆脱\"了困境。", "memorization": "提供流动性（逆差）vs 维持信心（不可兑换）。1960特里芬提出。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-fill-09-20", "category": "填空题", "question": "【铸币税】货币发行者通过发行货币所获得的收益，等于货币___减去___；对于国际储备货币发行国，铸币税表现为世界各国用___换取该国纸币或以该币计价的资产。", "answer": "面值、发行成本、真实资源", "explanation": "铸币税是美元霸权最直接的利益体现——美国印绿纸，世界给真货。", "memorization": "印纸换真货 = 铸币税。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-fill-09-21", "category": "填空题", "question": "【原罪（Original Sin）】指发展中国家在国际金融市场上只能以___（主要是美元）而非___发行债务的现象；汇率波动直接转化为___负担。", "answer": "强势货币、本币、债务", "explanation": "本币收入+美元债务=汇率一波动就死。", "memorization": "只能用美元借债 = 原罪。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-fill-09-22", "category": "填空题", "question": "【巴拉萨-萨缪尔森效应】一国生产率增速快的___部门工资上涨带动___部门工资上涨，导致整体价格水平上升、本币实际汇率___。", "answer": "可贸易品、非贸易品、升值", "explanation": "该效应解释了为什么发展中国家货币按PPP衡量往往被低估。", "memorization": "可贸易品生产率快→非贸易品价格涨→实际汇率升值。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-fill-09-23", "category": "填空题", "question": "【荷兰病（Dutch Disease）】指一国因___或___导致制造业竞争力下降、产业空心化的现象；最初因荷兰发现___后制造业衰落而得名。", "answer": "自然资源出口、本币高估、天然气", "explanation": "美元霸权+资本开放=外围国得荷兰病。", "memorization": "资源/本币高估→制造业衰落 = 荷兰病。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-fill-09-24", "category": "填空题", "question": "【金融自由化】指一国放松对金融市场的管制，包括四个方面：___、___、___、___。", "answer": "利率市场化、资本账户开放、金融业务混业、国有银行私有化", "explanation": "对发展中国家是\"饮鸩止渴\"，中国坚持\"渐进+可控\"的金融开放是正解。", "memorization": "利率·资本·混业·私有化 = 金融自由化四件套。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-fill-09-25", "category": "填空题", "question": "【华盛顿共识】由___年经济学家___总结，以___为内核；其\"四化\"药方：___、___、___、___。", "answer": "1989、威廉姆森、新自由主义、自由化、私有化、市场化、去管制化", "explanation": "不是中性建议，是美国推行新自由主义全球化的意识形态工具。", "memorization": "1989威廉姆森+\"四化\"药方。中国成功=有选择吸收。", "source": "翟东升-货币金融-模拟09"},
    {"id": "ipe-fill-10-41", "category": "填空题", "question": "【外商直接投资（FDI）】核心特征是\"___\"和\"___\"，区别于证券投资等组合投资。翟东升主张从\"以市场换技术\"升级为\"以市场换___\"，实现\"外资内资化\"。", "answer": "控制权、持久利益、股权", "explanation": "FDI是可被驾驭的战略工具，应通过参股控股实现\"外资内资化\"。", "memorization": "长期投资+控制权 = FDI；市场换股权 = 新策略。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-fill-10-42", "category": "填空题", "question": "【利率平价】在资本自由流动条件下，两国___差异应等于___升贴水率，以消除套利机会；中国通过对___的审慎管控保持了货币政策的独立性。", "answer": "利率、远期汇率、资本账户", "explanation": "中国通过资本账户的审慎管控保持了货币政策的独立性。", "memorization": "高利率国货币远期贴水；利率高→即期升值，远期贬值。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-fill-10-43", "category": "填空题", "question": "【国债收益率曲线】正常情形下呈___形态（经济健康），倒挂时呈___形态（衰退预警）；美债收益率曲线是全球金融市场的\"___\"。", "answer": "上升斜坡、下降斜坡、温度计", "explanation": "美联储通过影响收益率曲线对全球美元流动性和资产定价产生溢出效应。", "memorization": "正常上升坡=健康；倒挂下降坡=衰退。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-fill-10-44", "category": "填空题", "question": "【次贷危机】指2007-2008年间起源于美国___（向信用较差借款人发放的住房抵押贷款）市场、因___连锁崩盘而引发全球性金融海啸的金融危机。", "answer": "次级住房抵押贷款、金融衍生品", "explanation": "标志性事件是2008.9.15雷曼兄弟破产；传导链：次贷→MBS/CDO证券化扩散→房价崩→衍生品归零→全球信用紧缩。", "memorization": "次贷危机=起源于次级房贷+衍生品连锁崩盘。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-fill-10-45", "category": "填空题", "question": "【滞涨（Stagflation）】经济___（高失业率）与高___并存的经济现象；___年代石油危机是经典案例，标志着___政策失灵，为___（里根/撒切尔）登场提供土壤。", "answer": "停滞、通货膨胀、1970、凯恩斯主义、新自由主义", "explanation": "沃尔克通过极端加息治通胀，触发了拉美债务危机——治中心国的病，外围国买单。", "memorization": "停滞+通胀=滞涨。70年代石油危机。凯恩斯失灵→新自由主义登场。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-fill-10-46", "category": "填空题", "question": "【欧洲债务危机】始于___年的___，后蔓延至爱尔兰、葡萄牙、西班牙、意大利，根源是欧元区\"统一货币、___\"的制度性缺陷。", "answer": "2009、希腊、分散财政（无统一财政部）", "explanation": "证明了最优货币区条件在现实中几乎无法满足，是政治意志强推货币统一的代价。", "memorization": "希腊起火→南欧蔓延；有统一央行没统一财政部。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-fill-10-47", "category": "填空题", "question": "【华盛顿共识】指1989年威廉姆森总结的、以___为内核的一套经济政策药方（贸易自由化、私有化、放松管制、市场化等），被IMF和世界银行推广为发展中国家改革的\"___\"。", "answer": "新自由主义、标准方案", "explanation": "中国成功在于\"有选择地吸收而非照搬\"——开放市场但保留资本管制。<br>📺 拉美·<a href='https://www.bilibili.com/video/BV15b4y1Q7Ez' target='_blank' style='color:#6a8899;text-decoration:underline'>陈平眉山论剑《拉美借债史》（18.8万）</a> ｜ 俄罗斯·<a href='https://www.bilibili.com/video/BV1b5411x7Kn' target='_blank' style='color:#6a8899;text-decoration:underline'>有机社会《叶利钦如何打断俄罗斯脊梁骨》（110.3万）</a>", "memorization": "IMF+世行推广。拉美失去十年+俄罗斯休克疗法 = 失败案例。", "source": "翟东升-货币金融-模拟10"},
    {"id": "ipe-fill-01-48", "category": "填空题", "question": "【2008全球金融危机】传导链：低利率+监管松弛→次贷泡沫→___/___证券化扩散→___崩溃→衍生品价值归零→全球___紧缩。", "answer": "MBS、CDO、房价、信用", "explanation": "雷曼兄弟破产（2008.9.15）是标志性事件，是大萧条以来最严重的全球经济衰退。", "memorization": "次贷→MBS/CDO→房价崩→衍生品归零→信用紧缩。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-fill-01-49", "category": "填空题", "question": "【金汇兑本位制】一战后黄金储量不足，各国转而以___（如英镑或美元）为储备、再间接与黄金挂钩；___体系是其最高级形态（美元-黄金双挂钩）。", "answer": "关键货币、布雷顿森林", "explanation": "金汇兑本位看似技术性安排，实则是中心国以规则之名攫取铸币税特权的制度设计。", "memorization": "不直接持金→持英镑/美元→间接兑金。布雷顿森林是最高形态。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-fill-01-50", "category": "填空题", "question": "【中心外围关系】中心国（发达国家）掌握___、___、___，外围国（发展中国家）提供___、___和___；初级产品贸易条件长期___，外围向中心持续输送剩余价值。", "answer": "技术、资本、货币定价权、劳动力、原材料、市场、恶化", "explanation": "中国正从外围向\"半中心\"跃升，关键是守住制造业基本盘和推进人民币国际化。", "memorization": "中心=技术+资本+货币定价权；外围=劳动+原材料+市场。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-fill-01-51", "category": "填空题", "question": "【贸易溢出效应】分为___（如中国经济增长带动大宗商品出口国受益）和___（如美国量化宽松导致热钱冲击新兴市场）；中国\"五重价格革命\"是最重要的___溢出效应，但也是___的根源之一。", "answer": "正溢出、负溢出、正、逆全球化", "explanation": "如美国QE导致热钱冲击新兴市场是负溢出；中国制造降低全球价格是正溢出。", "memorization": "正溢出（中国制造）vs 负溢出（美国QE）。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-fill-01-52", "category": "填空题", "question": "【新自由主义】核心主张\"三化\"：___、___、___；政治代表：___、___；理论来源：___（自发秩序）、___（货币主义）。", "answer": "私有化、自由化、去管制化、里根、撒切尔、哈耶克、弗里德曼", "explanation": "不是中性经济学理论，是资本阶级的意识形态工具。2016年逆全球化是其40年恶果的政治反弹。", "memorization": "三化：私+自+去管制。里根撒切尔=政治代表，哈耶克弗里德曼=理论代表。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-fill-01-53", "category": "填空题", "question": "【全球化与逆全球化】全球化指商品、服务、资本、劳动力、信息___的深化趋势，以国际分工和___为特征；逆全球化则指各国转向贸易保护主义、民粹主义、供应链___的反向潮流。", "answer": "跨国流动、相互依存、本地化", "explanation": "逆全球化的根源不是\"民粹\"，而是新自由主义全球化收益分配极度不均；以2008危机后、2016特朗普当选为标志，代表事件有英国脱欧、中美贸易战。", "memorization": "全球化=跨国流动+相互依存；逆全球化=保护主义+供应链本地化。", "source": "翟东升-货币金融-模拟01"},
    {"id": "ipe-fill-02-54", "category": "填空题", "question": "【外汇占款】指央行___外汇时被动投放的等值___，是外汇储备形成过程中被动投放的___；___—___年间是中国基础货币投放的最主要渠道。", "answer": "购入、人民币、基础货币、2003、2014", "explanation": "外汇占款机制是\"三外路线\"中\"控制外汇\"的核心制度传导链。", "memorization": "央行购汇→投放人民币 = 外汇占款。2003-2014年峰值超27万亿。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-fill-02-55", "category": "填空题", "question": "【铸币税】现代信用货币体系下分为：①___：央行印钞购买政府债券，名义\"借款\"实际获得资源；②___：储备货币国（主要是美国）用印制的___换取他国的___。", "answer": "国内铸币税、国际铸币税、纸币、真实商品和服务", "explanation": "中国外储是中国以真实劳动和资源向美国缴纳的\"货币地租\"。", "memorization": "国内（央行印钞买国债）+国际（印纸换资源）。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-fill-02-56", "category": "填空题", "question": "【加工贸易】核心特征是\"___\"（原料___、产品___），主要形式包括___和___；鼎盛时期（2000年代）占中国出口约___%。", "answer": "两头在外、进口、出口、来料加工、进料加工、55", "explanation": "加工贸易将中国嵌入全球价值链的组装环节，附加值极低（微笑曲线底部）。", "memorization": "两头在外=来料加工+进料加工。占比2000s约55%。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-fill-02-57", "category": "填空题", "question": "【资源诅咒】丰富的自然资源反而导致经济发展停滞的现象，又称\"___\"；机制：资源出口繁荣→本币___→制造业出口竞争力___→非资源产业___→经济结构畸形。", "answer": "荷兰病（Dutch Disease）、升值、下降、萎缩", "explanation": "典型案例：中东石油国、尼日利亚、委内瑞拉。", "memorization": "资源越丰→制造越弱（荷兰病机制）。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-fill-02-58", "category": "填空题", "question": "【强制结售汇制度】___年汇率并轨后中国实行：境内企业外汇收入须卖给指定外汇银行（___），所需外汇须向指定银行购买（___），___作为外汇市场的\"最终买家\"。", "answer": "1994、结汇、售汇、央行", "explanation": "把全社会的美元集中到国家手里，汇率风险社会化由国家承担。", "memorization": "1994汇改+结汇/售汇+央行最终买家。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-fill-02-59", "category": "填空题", "question": "【黄金输送点】古典金本位下，当两国汇率偏离铸币平价超过___（运输+保险成本）时触发黄金流动：分为黄金___点（汇率高于上限→运金出口）和黄金___点（汇率低于下限→运金进口）。", "answer": "运送成本、输出、输入", "explanation": "调节的成本永远由外围国承担，是金本位制度权力不对称的体现。", "memorization": "汇率偏离过大→运金比换汇合算→黄金自动流动。", "source": "翟东升-货币金融-模拟02"},
    {"id": "ipe-fill-03-60", "category": "填空题", "question": "【央票（央行票据）】是中国人民银行向___发行的___债券（期限通常___至___），主要用于对冲___带来的过剩流动性；___—___年是其鼎盛时期。", "answer": "商业银行、短期、3个月、1年、外汇占款、2003、2013", "explanation": "央票是\"不得已的政策工具\"——补救强制结售汇产生的外汇占款过多。", "memorization": "央行向商业银行借钱（发短债）→锁定过剩流动性→对冲外汇占款。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-fill-03-61", "category": "填空题", "question": "【雁行模式】由日本经济学家___（___年代）提出，描述产业从___→___→___的梯度转移；该模式被中国崛起根本性颠覆，被翟东升提出的\"___\"（CICE）取代。", "answer": "赤松要、1930、日本、亚洲四小龙、中国/东盟、产业链编辑能力", "explanation": "中国跳过队列、成为新头雁，CICE取代雁行。", "memorization": "头雁日本→四小龙→中国/东盟。中国已成新头雁。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-fill-03-62", "category": "填空题", "question": "【\"三外路线\"】翟东升对中国改革开放后对外经济战略核心的概括：___、___、___（强制结售汇+资本管制）。", "answer": "鼓励外贸（促进出口）、吸引外资（引进FDI）、控制外汇", "explanation": "历史阶段最优路径，正向\"双循环\"模式演进。", "memorization": "三外：外贸+外资+外汇（结售汇）。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-fill-03-63", "category": "填空题", "question": "【量化宽松（QE）】央行在政策利率接近___时采用的非常规货币政策，通过在二级市场大规模购买___，直接向金融体系注入___；___后美联储/欧央行/日本央行相继实施。", "answer": "零下界（零利率约束）、中长期国债、流动性、2008年危机", "explanation": "QE制造全球泡沫，是翟东升\"美元潮汐收割\"机制的第一步。", "memorization": "政策利率→0时，央行直接买长期国债。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-fill-03-64", "category": "填空题", "question": "【货币乘数】= ___ / ___ = 1 / (___ + ___ + ___)。", "answer": "M2（货币供应量）、基础货币、法定存款准备金率、超额存准率、现金漏损率", "explanation": "货币乘数揭示货币的内生性——经济不景气时乘数下降→QE失效（推绳子）。", "memorization": "货币乘数=M2/基础货币≈1/准备金率。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-fill-03-65", "category": "填空题", "question": "【基础货币】又称\"___\"（High-Powered Money），包括___和___两部分；2003-2013年中国基础货币以___为主（被动），2014年后改以___等工具主动投放。", "answer": "高能货币、流通中的现金、商业银行在央行的存款准备金、外汇占款、MLF/再贷款", "explanation": "投放渠道从被动到主动，是货币政策独立性提升的重要标志。", "memorization": "基础货币=现金+准备金=高能货币。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-fill-03-66", "category": "填空题", "question": "【全球供应链】指产品从原材料采购、零部件生产、最终组装到销售___于多个国家的全球化___网络，以分工细化、___最大化为特征。", "answer": "分布、生产、比较优势", "explanation": "形成背景：贸易自由化（WTO）+信息技术（互联网+ERP）+运输成本下降（集装箱化）；2020年后疫情和中美博弈使其脆弱性暴露无遗。", "memorization": "全球供应链=跨多国分布的生产网络，比较优势最大化。", "source": "翟东升-货币金融-模拟03"},
    {"id": "ipe-fill-04-67", "category": "填空题", "question": "【公开市场操作（Open Market Operations）】央行通过在公开市场买卖国债调节流动性：买入国债→基础货币___（___）；卖出国债→基础货币___（___）。三大优势：___、___、___。", "answer": "投放、宽松、回笼、紧缩、主动性强、灵活精确、可逆性好", "explanation": "QE本质是美联储为美国国债创造买家，全球为美国财政赤字承担隐性成本。", "memorization": "买国债→放水；卖国债→收水。优势：主动+灵活+可逆。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-fill-04-68", "category": "填空题", "question": "【法定存款准备金率】央行规定商业银行必须将存款的一定比例存入央行（不可用于放贷），这一比例即法定存款准备金率：提高存准率→银行可贷资金___→货币供给___；中国历史上存准率曾达___%，当前约___%。", "answer": "减少、收缩、21.5、6-9", "explanation": "高存准率是央行向商业银行收取的\"隐性税\"，利差损失最终转嫁给储蓄者。", "memorization": "存准高→可贷少→收缩。中国曾21.5%。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-fill-04-69", "category": "填空题", "question": "【友岸外包（Friend-shoring）】美国___政府提出的供应链重组策略：将生产和采购集中于政治上\"___\"，避免对中国的过度依赖；与向地理近邻转移的\"___\"形成双轮策略。", "answer": "拜登、可信任的盟友（友好国家）、近岸外包（Nearshoring）", "explanation": "贸易政治化的另一面：政治优先于经济，但内含矛盾。", "memorization": "友岸=向政治友好国外包+近岸=向地理近邻外包。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-fill-04-70", "category": "填空题", "question": "【微笑曲线】由___集团创始人___于___年提出的产业价值链模型。U型三段：左端___+品牌，中间___（附加值最低），右端___+售后服务。", "answer": "台湾宏碁、施振荣、1992、研发、制造组装、营销", "explanation": "中国长期处于微笑曲线的底部（低附加值组装），享受微薄代工费。", "memorization": "U型曲线：研发-制造-营销，中间最低（中国代工时代）。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-fill-04-71", "category": "填空题", "question": "【货币互换（Currency Swap）】两国（或央行）之间协议、在一定时期内相互提供本币融资便利、期末按___换回的安排；中国自___年后与数十个国家签署人民币货币互换协议，为___提供流动性支撑。", "answer": "原汇率、2008、人民币国际化", "explanation": "美联储的互换网络只对战略盟友开放，中国的互换网络向发展中国家倾斜。", "memorization": "互换=两国相互借本币。中国2008后建网络支持人民币国际化。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-fill-04-72", "category": "填空题", "question": "【特别提款权货币篮子（SDR Basket）】指IMF特别提款权（SDR）的价值由一篮子___货币___平均决定的机制；当前由美元、欧元、___、日元、英镑五种货币构成（美元权重最大）。", "answer": "主要、加权、人民币", "explanation": "人民币于2016年正式加入SDR篮子（现权重12.28%），是中国货币国际化的重要里程碑；SDR是国际货币权力格局的制度性照妖镜。", "memorization": "SDR=一篮子主要货币加权定值；五币：美·欧·人民币·日·英。", "source": "翟东升-货币金融-模拟04"},
    {"id": "ipe-fill-06-73", "category": "填空题", "question": "【浮动汇率制度】指一国货币汇率由外汇市场___自由决定、政府和央行不设固定平价、不作系统性干预的汇率安排；按蒙代尔三元悖论，它主动放弃___，换取货币政策独立性。", "answer": "供求关系、汇率稳定", "explanation": "纯粹浮动极少见，多数国家实行\"管理浮动\"；三元悖论：资本自由流动、汇率稳定、货币政策独立三者只能取其二。", "memorization": "浮动汇率=市场供求定价；放弃汇率稳定换货币政策独立。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-fill-06-74", "category": "填空题", "question": "【固定汇率制度】三类：①___（货币局、美元化）；②___（布雷顿森林体系经典形式）；③___（汇率以预先公布的小幅度周期性贬值/升值）。", "answer": "硬性盯住、可调整钉住、爬行钉住", "explanation": "1992年英镑危机是固定汇率易遭投机性冲击的典型案例。", "memorization": "三类：硬性/可调整/爬行。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-fill-06-75", "category": "填空题", "question": "【资产泡沫】形成三阶段：①___宽松→资产价格上涨→财富效应；②价格脱离___但情绪持续驱动（\"___\"）；③___→泡沫破裂→债务通缩螺旋。", "answer": "流动性、基本面、非理性繁荣、触发因素（利率上升/信心逆转）", "explanation": "翟东升：美元潮汐收放导致全球资产价格周期性波动。", "memorization": "三阶段：宽松→脱离基本面（非理性繁荣）→触发因素→破裂。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-fill-06-76", "category": "填空题", "question": "【进口替代战略（ISI）】英文全称___；流行于___年代拉美（阿根廷、巴西、墨西哥）和部分亚非国家；手段：___、___、___；与东亚___战略形成鲜明对比。", "answer": "Import Substitution Industrialization、1950-1970、关税保护、补贴、外汇管制、出口导向（EOI）", "explanation": "ISI失败的核心是脱离全球市场就脱离了技术进步和规模效益的压力。", "memorization": "ISI=关税+补贴+外汇管制。拉美ISI vs 东亚EOI。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-fill-06-77", "category": "填空题", "question": "【康德拉季耶夫周期】又称\"___\"，约___年；由苏联经济学家康德拉季耶夫于___年代提出；四阶段：___→___→___→___。", "answer": "长波周期、45-60、1920、繁荣、衰退、萧条、复苏", "explanation": "翟东升：AI/绿色能源革命=第六次康波起点；与美元潮汐叠加→历史性动荡。", "memorization": "45-60年长波，康德拉季耶夫1920年代提出。四阶段：繁→衰→萧→复。", "source": "翟东升-货币金融-模拟06"},
    {"id": "ipe-fill-07-78", "category": "填空题", "question": "【特里芬难题】指作为唯一国际储备货币的美元面临的结构性两难：既要靠美国持续___向世界提供___，又要维持美元对黄金的可兑换性（信心），两者方向相反、不可兼得。", "answer": "国际收支逆差、流动性", "explanation": "尼克松1971年关闭黄金窗口实际\"解决\"了该约束——美元不再兑换黄金，靠的是\"美国债务的全球接受度\"而非实物锚。", "memorization": "提供流动性需逆差，维持信心需不逆差→特里芬两难。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-fill-07-79", "category": "填空题", "question": "【美元指数】由___（ICE）发布，___年以___为基准；货币篮子六种货币中权重最大的是___（___%）；美元指数高点往往对应全球金融危机爆发节点（如___、___、___年）。", "answer": "洲际交易所、1973、100、欧元、57.6、1985、2000、2022", "explanation": "美元指数是\"美元潮汐\"的测量工具——美元指数↑=全球流动性紧缩+新兴市场承压。", "memorization": "美元指数1973基准100；欧元权重最大57.6%。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-fill-07-80", "category": "填空题", "question": "【产业链编辑能力（CICE）】由翟东升提出，英文全称___；三大特征：___、___、___；体现：将劳动密集型产业向越南/孟加拉转移，将___、___、___留在国内。", "answer": "Capacity for Industrial Chain Editing、主动性、系统性、政治性、半导体、AI、新能源", "explanation": "中国从\"世界工厂\"升级为\"世界产业链编辑者\"的关键能力。", "memorization": "CICE三特征：主动+系统+政治。转出低端，留住高端。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-fill-07-81", "category": "填空题", "question": "【人民币国际化】三大货币功能：___（贸易结算）、___（商品计价）、___（外储资产）；当前人民币在全球外储份额约___%，位列第___；翟东升主张目标是形成\"___\"。", "answer": "交易媒介、价值尺度、价值储藏、2.6、5、人民币区", "explanation": "目标不是取代美元（过于激进），而是在中国主导的贸易投资网络中成为主要结算货币。", "memorization": "三功能：交易媒介+价值尺度+价值储藏。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-fill-07-82", "category": "填空题", "question": "【牙买加体系】___年牙买加协议（Kingston Accords）确立的国际货币体系四大内容：①___合法；②黄金___；③___被定义为主要国际储备资产（但实际边缘化）；④___在实践中继续主导。翟东升：美元霸权的\"___升级版\"。", "answer": "1976、浮动汇率、非货币化、SDR（特别提款权）、美元、2.0", "explanation": "黄金束缚消除，美国无限铸币权制度化，比布雷顿森林体系对美国更有利。", "memorization": "牙买加体系：浮动+黄金非货币+SDR名义为主+美元实际主导。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-fill-07-83", "category": "填空题", "question": "【外汇占款（央行新工具视角）】外汇占款指央行___外汇时相应投放的等值___，属被动投放的基础货币；2015年后外储下降→外汇占款减少→央行改用MLF、SLF等新工具___补充基础货币。", "answer": "购入、本币（人民币）、主动", "explanation": "外汇占款机制曾使中国货币政策被动跟随美国货币周期（货币主权受限）；转向MLF/SLF主动投放是政策独立性提升的标志。", "memorization": "外汇占款=购汇被动投放本币；2015后改MLF/SLF主动投放。", "source": "翟东升-货币金融-模拟07"},
    {"id": "ipe-fill-07-84", "category": "填空题", "question": "【布雷顿森林体系】___年___月在美国___州布雷顿森林会议建立（___—___年）；核心：美元以___美元/盎司固定兑换___，其他货币钉住美元（±___%波动区间）；三支柱：___、___、固定汇率。", "answer": "1944、7、新罕布什尔、1944、1971、35、黄金、1、IMF、世界银行", "explanation": "美国将战后压倒性经济优势制度化的霸权工具；英国凯恩斯方案(bancor)被否决。", "memorization": "1944布雷顿森林+35美元/盎司+IMF/世行/固定汇率三支柱。", "source": "翟东升-货币金融-模拟07"}
];
